{
  "name": "Yeilu Store Inventory MVP",
  "description": "A modern multi-location inventory management system for Yeilu Store with authentication and CRUD capabilities.",
  "requestFramePermissions": []
}

export type SedeId = 'sede_norte' | 'sede_sur' | 'sede_centro';

export interface Sede {
  id: SedeId;
  name: string;
}

export interface User {
  id: string;
  username: string;
  password?: string;
  sedeId: SedeId;
  name: string;
}

export interface Product {
  id: string;
  reference: string;
  type: string;
  quantity: number;
  cost: number;
  saleValue: number;
  sedeId: SedeId;
  updatedAt: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import { Sede, User } from './types';

export const SEDES: Sede[] = [
  { id: 'sede_norte', name: 'Yeilu Norte' },
  { id: 'sede_sur', name: 'Yeilu Sur' },
  { id: 'sede_centro', name: 'Yeilu Centro' }
];

// Mock users for demonstration (In real app, this would be a hash in DB)
export const MOCK_USERS: User[] = [
  { id: '1', username: 'admin_norte', password: '123', sedeId: 'sede_norte', name: 'Admin Norte' },
  { id: '2', username: 'admin_sur', password: '123', sedeId: 'sede_sur', name: 'Admin Sur' },
  { id: '3', username: 'admin_centro', password: '123', sedeId: 'sede_centro', name: 'Admin Centro' }
];

export const STORAGE_KEYS = {
  PRODUCTS: 'yeilu_inventory_products',
  AUTH: 'yeilu_auth_state'
};

import { Product, SedeId } from '../types';
import { STORAGE_KEYS } from '../constants';

export const getProducts = (): Product[] => {
  const data = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
  return data ? JSON.parse(data) : [];
};

export const getProductsBySede = (sedeId: SedeId): Product[] => {
  return getProducts().filter(p => p.sedeId === sedeId);
};

export const saveProduct = (product: Product): void => {
  const products = getProducts();
  const index = products.findIndex(p => p.id === product.id);

  if (index >= 0) {
    products[index] = { ...product, updatedAt: new Date().toISOString() };
  } else {
    products.push({ ...product, updatedAt: new Date().toISOString() });
  }

  localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
};

export const deleteProduct = (id: string): void => {
  const products = getProducts();
  const filtered = products.filter(p => p.id !== id);
  localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(filtered));
};

export const clearAllData = (): void => {
  localStorage.removeItem(STORAGE_KEYS.PRODUCTS);
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = 'px-4 py-2 rounded-lg font-medium transition-all focus:ring-2 focus:ring-offset-2 disabled:opacity-50 flex items-center justify-center gap-2';
  const variants = {
    primary: 'bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500',
    secondary: 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 focus:ring-slate-400',
    danger: 'bg-red-500 text-white hover:bg-red-600 focus:ring-red-400',
    ghost: 'text-slate-500 hover:text-indigo-600 hover:bg-indigo-50'
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${fullWidth ? 'w-full' : ''} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
  label?: string;
}

export const Input: React.FC<InputProps> = ({ label, className = '', ...props }) => {
  return (
    <div className="flex flex-col gap-1.5 w-full">
      {label && <label className="text-sm font-medium text-slate-700">{label}</label>}
      <input 
        className={`px-3 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all ${className}`}
        {...props}
      />
    </div>
  );
};

interface SelectProps extends React.SelectHTMLAttributes<HTMLSelectElement> {
  label?: string;
  options: { value: string; label: string }[];
}

export const Select: React.FC<SelectProps> = ({ label, options, className = '', ...props }) => {
  return (
    <div className="flex flex-col gap-1.5 w-full">
      {label && <label className="text-sm font-medium text-slate-700">{label}</label>}
      <select 
        className={`px-3 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all appearance-none cursor-pointer ${className}`}
        {...props}
      >
        {options.map(opt => (
          <option key={opt.value} value={opt.value}>{opt.label}</option>
        ))}
      </select>
    </div>
  );
};

export const Modal: React.FC<{ isOpen: boolean; onClose: () => void; title: string; children: React.ReactNode }> = ({ isOpen, onClose, title, children }) => {
  if (!isOpen) return null;
  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="px-6 py-4 border-b border-slate-100 flex justify-between items-center">
          <h3 className="text-lg font-bold text-slate-900">{title}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
          </button>
        </div>
        <div className="p-6">
          {children}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Product, SedeId } from '../types';
import { Input, Button } from './UI';

interface ProductFormProps {
  onSubmit: (data: Omit<Product, 'id' | 'updatedAt' | 'sedeId'>) => void;
  initialData?: Product | null;
  onCancel: () => void;
}

export const ProductForm: React.FC<ProductFormProps> = ({ onSubmit, initialData, onCancel }) => {
  const [formData, setFormData] = useState({
    reference: '',
    type: '',
    quantity: 0,
    cost: 0,
    saleValue: 0,
  });

  useEffect(() => {
    if (initialData) {
      setFormData({
        reference: initialData.reference,
        type: initialData.type,
        quantity: initialData.quantity,
        cost: initialData.cost,
        saleValue: initialData.saleValue,
      });
    }
  }, [initialData]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: type === 'number' ? parseFloat(value) || 0 : value
    }));
  };

  return (
    <form onSubmit={handleSubmit} className="flex flex-col gap-4">
      <Input 
        label="Referencia / SKU" 
        name="reference" 
        value={formData.reference} 
        onChange={handleChange} 
        required 
        placeholder="Eje: PROD-123"
      />
      <Input 
        label="Tipo / Categoría" 
        name="type" 
        value={formData.type} 
        onChange={handleChange} 
        required 
        placeholder="Eje: Electrónicos"
      />
      <div className="grid grid-cols-3 gap-3">
        <Input 
          label="Cantidad" 
          name="quantity" 
          type="number" 
          value={formData.quantity} 
          onChange={handleChange} 
          required 
          min="0"
        />
        <Input 
          label="Costo ($)" 
          name="cost" 
          type="number" 
          value={formData.cost} 
          onChange={handleChange} 
          required 
          min="0"
        />
        <Input 
          label="Venta ($)" 
          name="saleValue" 
          type="number" 
          value={formData.saleValue} 
          onChange={handleChange} 
          required 
          min="0"
        />
      </div>
      <div className="flex gap-3 mt-4">
        <Button type="button" variant="secondary" fullWidth onClick={onCancel}>Cancelar</Button>
        <Button type="submit" variant="primary" fullWidth>{initialData ? 'Actualizar' : 'Crear Producto'}</Button>
      </div>
    </form>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, Product } from '../types';
import { SEDES } from '../constants';
import { getProductsBySede, saveProduct, deleteProduct } from '../services/storageService';
import { Button, Input, Modal } from './UI';
import { ProductForm } from './ProductForm';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [products, setProducts] = useState<Product[]>([]);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);

  const currentSede = SEDES.find(s => s.id === user.sedeId);

  const loadProducts = () => {
    setProducts(getProductsBySede(user.sedeId));
  };

  useEffect(() => {
    loadProducts();
  }, [user.sedeId]);

  const filteredProducts = useMemo(() => {
    return products.filter(p => 
      p.reference.toLowerCase().includes(search.toLowerCase()) || 
      p.type.toLowerCase().includes(search.toLowerCase())
    );
  }, [products, search]);

  const stats = useMemo(() => {
    const totalItems = products.reduce((acc, p) => acc + p.quantity, 0);
    const lowStock = products.filter(p => p.quantity < 5).length;
    const inventoryValue = products.reduce((acc, p) => acc + (p.cost * p.quantity), 0);
    return { totalItems, lowStock, inventoryValue };
  }, [products]);

  const handleAddOrEdit = (data: Omit<Product, 'id' | 'updatedAt' | 'sedeId'>) => {
    const newProduct: Product = {
      ...data,
      id: editingProduct?.id || crypto.randomUUID(),
      sedeId: user.sedeId,
      updatedAt: new Date().toISOString()
    };
    saveProduct(newProduct);
    loadProducts();
    setIsModalOpen(false);
    setEditingProduct(null);
  };

  const handleDelete = (id: string) => {
    if (confirm('¿Estás seguro de eliminar este producto?')) {
      deleteProduct(id);
      loadProducts();
    }
  };

  const openEdit = (product: Product) => {
    setEditingProduct(product);
    setIsModalOpen(true);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
             <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"></path></svg>
          </div>
          <div>
            <h1 className="text-xl font-bold text-slate-900 leading-tight">Yeilu Store</h1>
            <p className="text-sm text-slate-500 font-medium">{currentSede?.name}</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="text-right hidden sm:block">
            <p className="text-sm font-semibold text-slate-900">{user.name}</p>
            <p className="text-xs text-slate-500">Gestor de Inventario</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-sm">
            Cerrar Sesión
          </Button>
        </div>
      </header>

      <main className="flex-1 p-6 max-w-7xl mx-auto w-full space-y-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <p className="text-slate-500 text-sm font-medium">Total de Artículos</p>
            <p className="text-3xl font-bold text-slate-900 mt-1">{stats.totalItems}</p>
          </div>
          <div className={`p-6 rounded-2xl shadow-sm border ${stats.lowStock > 0 ? 'bg-red-50 border-red-100' : 'bg-white border-slate-200'}`}>
            <p className={`${stats.lowStock > 0 ? 'text-red-600' : 'text-slate-500'} text-sm font-medium`}>Stock Bajo (&lt;5)</p>
            <p className={`text-3xl font-bold mt-1 ${stats.lowStock > 0 ? 'text-red-700' : 'text-slate-900'}`}>{stats.lowStock}</p>
          </div>
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <p className="text-slate-500 text-sm font-medium">Valor Inventario (Costo)</p>
            <p className="text-3xl font-bold text-slate-900 mt-1">${stats.inventoryValue.toLocaleString()}</p>
          </div>
        </div>

        {/* Inventory Controls */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 space-y-6">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <h2 className="text-lg font-bold text-slate-900">Listado de Stock</h2>
            <div className="flex flex-col sm:flex-row w-full md:w-auto gap-3">
              <div className="relative w-full sm:w-64">
                <input
                  type="text"
                  placeholder="Buscar por SKU o Tipo..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
                />
                <svg className="absolute left-3 top-2.5 w-4 h-4 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"></path></svg>
              </div>
              <Button onClick={() => { setEditingProduct(null); setIsModalOpen(true); }} className="whitespace-nowrap">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
                Nuevo Producto
              </Button>
            </div>
          </div>

          {/* Product Table */}
          <div className="overflow-x-auto -mx-6">
            <div className="inline-block min-w-full align-middle px-6">
              <table className="min-w-full divide-y divide-slate-200">
                <thead>
                  <tr className="text-left text-xs font-semibold text-slate-500 uppercase tracking-wider">
                    <th className="px-4 py-3">Referencia</th>
                    <th className="px-4 py-3">Categoría</th>
                    <th className="px-4 py-3 text-center">Cantidad</th>
                    <th className="px-4 py-3">Costo</th>
                    <th className="px-4 py-3">PVP</th>
                    <th className="px-4 py-3 text-right">Acciones</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 bg-white">
                  {filteredProducts.length === 0 ? (
                    <tr>
                      <td colSpan={6} className="px-4 py-12 text-center text-slate-400 italic">No se encontraron productos en esta sede.</td>
                    </tr>
                  ) : filteredProducts.map((p) => (
                    <tr key={p.id} className="hover:bg-slate-50 transition-colors">
                      <td className="px-4 py-4 whitespace-nowrap font-medium text-slate-900">{p.reference}</td>
                      <td className="px-4 py-4 whitespace-nowrap">
                        <span className="px-2 py-1 text-xs font-semibold rounded-full bg-slate-100 text-slate-600 uppercase">{p.type}</span>
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-center">
                        <span className={`px-3 py-1 rounded-lg font-bold text-sm ${p.quantity < 5 ? 'bg-red-100 text-red-700' : 'bg-green-100 text-green-700'}`}>
                          {p.quantity}
                        </span>
                      </td>
                      <td className="px-4 py-4 whitespace-nowrap text-slate-600 font-medium">${p.cost.toLocaleString()}</td>
                      <td className="px-4 py-4 whitespace-nowrap text-indigo-600 font-bold">${p.saleValue.toLocaleString()}</td>
                      <td className="px-4 py-4 whitespace-nowrap text-right space-x-2">
                        <Button variant="ghost" className="px-2" onClick={() => openEdit(p)}>
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg>
                        </Button>
                        <Button variant="ghost" className="px-2 text-red-400 hover:text-red-600 hover:bg-red-50" onClick={() => handleDelete(p.id)}>
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path></svg>
                        </Button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </main>

      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={editingProduct ? 'Editar Producto' : 'Añadir Nuevo Producto'}
      >
        <ProductForm 
          onSubmit={handleAddOrEdit} 
          initialData={editingProduct} 
          onCancel={() => setIsModalOpen(false)} 
        />
      </Modal>

      <footer className="bg-white border-t border-slate-200 py-6 px-6 text-center text-sm text-slate-400">
        &copy; {new Date().getFullYear()} Yeilu Store Inventory System. v1.0 MVP.
      </footer>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AuthState, SedeId, User } from './types';
import { MOCK_USERS, SEDES, STORAGE_KEYS } from './constants';
import { Input, Select, Button } from './components/UI';
import { Dashboard } from './components/Dashboard';

const App: React.FC = () => {
  const [authState, setAuthState] = useState<AuthState>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.AUTH);
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const [loginForm, setLoginForm] = useState({
    username: '',
    password: '',
    sedeId: 'sede_norte' as SedeId
  });

  const [error, setError] = useState('');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AUTH, JSON.stringify(authState));
  }, [authState]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    const user = MOCK_USERS.find(
      u => u.username === loginForm.username && 
           u.password === loginForm.password && 
           u.sedeId === loginForm.sedeId
    );

    if (user) {
      setAuthState({ user, isAuthenticated: true });
    } else {
      setError('Credenciales inválidas o el usuario no pertenece a la sede seleccionada.');
    }
  };

  const handleLogout = () => {
    setAuthState({ user: null, isAuthenticated: false });
  };

  if (authState.isAuthenticated && authState.user) {
    return <Dashboard user={authState.user} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-xl shadow-slate-200 border border-slate-100 overflow-hidden">
        <div className="bg-indigo-600 p-8 text-white text-center">
          <div className="bg-white/20 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4">
             <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"></path></svg>
          </div>
          <h2 className="text-2xl font-bold">Yeilu Store</h2>
          <p className="text-indigo-100 mt-1 opacity-80">Gestión de Inventario Multi-Sede</p>
        </div>

        <form onSubmit={handleLogin} className="p-8 space-y-5">
          {error && (
            <div className="bg-red-50 border border-red-100 text-red-600 text-sm p-3 rounded-lg flex items-center gap-2">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd"></path></svg>
              {error}
            </div>
          )}

          <div className="space-y-4">
            <Input 
              label="Usuario" 
              placeholder="Ingrese su usuario" 
              value={loginForm.username}
              onChange={e => setLoginForm(prev => ({ ...prev, username: e.target.value }))}
              required
            />
            <Input 
              label="Contraseña" 
              type="password" 
              placeholder="••••••••" 
              value={loginForm.password}
              onChange={e => setLoginForm(prev => ({ ...prev, password: e.target.value }))}
              required
            />
            <Select 
              label="Sede de Trabajo"
              options={SEDES.map(s => ({ value: s.id, label: s.name }))}
              value={loginForm.sedeId}
              onChange={e => setLoginForm(prev => ({ ...prev, sedeId: e.target.value as SedeId }))}
            />
          </div>

          <Button type="submit" fullWidth className="mt-4 py-3 text-lg font-bold">
            Entrar al Sistema
          </Button>

          <div className="pt-4 border-t border-slate-100">
            <p className="text-center text-xs text-slate-400 leading-relaxed uppercase tracking-widest font-bold">
              Credenciales Demo
            </p>
            <div className="mt-2 text-[10px] text-slate-500 flex justify-center gap-3">
              <span>Norte: admin_norte / 123</span>
              <span>Sur: admin_sur / 123</span>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

