export const STORAGE_KEYS = {
  MOVEMENTS: 'yeilu_kardex_movements',
  AUTH: 'yeilu_auth_state'
};

import { Movement, ProductStock, SedeId, MovementType } from '../types';
import { STORAGE_KEYS } from '../constants';

export const getMovements = (): Movement[] => {
  const data = localStorage.getItem(STORAGE_KEYS.MOVEMENTS);
  return data ? JSON.parse(data) : [];
};

export const registerMovement = (movement: Movement): void => {
  const movements = getMovements();
  movements.push({ ...movement, timestamp: new Date().toISOString() });
  localStorage.setItem(STORAGE_KEYS.MOVEMENTS, JSON.stringify(movements));
};

// Calcula el stock actual consolidado o por sede
export const calculateStock = (sedeId?: SedeId): ProductStock[] => {
  const movements = getMovements();
  const filteredMovements = sedeId ? movements.filter(m => m.sedeId === sedeId) : movements;

  const stockMap: Record<string, ProductStock> = {};

  filteredMovements.forEach(m => {
    const key = `${m.reference}_${m.sedeId}`;
    if (!stockMap[key]) {
      stockMap[key] = {
        reference: m.reference,
        type: m.type,
        quantity: 0,
        cost: m.cost,
        salePrice: m.salePrice,
        margin: m.salePrice - m.cost,
        sedeId: m.sedeId
      };
    }

    if (m.movementType === 'ENTRADA' || m.movementType === 'AJUSTE') {
      stockMap[key].quantity += m.quantity;
    } else if (m.movementType === 'SALIDA') {
      stockMap[key].quantity -= m.quantity;
    }

    // Actualizar precios al último registro
    stockMap[key].cost = m.cost;
    stockMap[key].salePrice = m.salePrice;
    stockMap[key].margin = m.salePrice - m.cost;
  });

  return Object.values(stockMap);
};

export const executeTransfer = (
  userId: string, 
  username: string,
  reference: string, 
  type: string,
  quantity: number, 
  originSede: SedeId, 
  destSede: SedeId,
  cost: number,
  salePrice: number
): void => {
  // 1. Salida de Origen
  registerMovement({
    id: crypto.randomUUID(),
    timestamp: new Date().toISOString(),
    userId,
    username,
    sedeId: originSede,
    reference,
    type,
    movementType: 'SALIDA',
    quantity,
    cost,
    salePrice,
    margin: salePrice - cost,
    notes: `Traslado hacia ${destSede}`
  });

  // 2. Entrada en Destino
  registerMovement({
    id: crypto.randomUUID(),
    timestamp: new Date().toISOString(),
    userId,
    username,
    sedeId: destSede,
    reference,
    type,
    movementType: 'ENTRADA',
    quantity,
    cost,
    salePrice,
    margin: salePrice - cost,
    notes: `Traslado recibido desde ${originSede}`
  });
};

/**
 * GOOGLE APPS SCRIPT - BACKEND PARA YEILU STORE
 * Desplegar como Aplicación Web con acceso para "Cualquiera".
 */

const SPREADSHEET_ID = 'TU_ID_DE_GOOGLE_SHEET_AQUÍ';
const SHEET_NAME = 'Movimientos';

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
    let sheet = ss.getSheetByName(SHEET_NAME);

    if (!sheet) {
      sheet = ss.insertSheet(SHEET_NAME);
      sheet.appendRow([
        'ID_Registro', 'Timestamp', 'Usuario', 'Rol', 'Sede', 
        'Referencia', 'Tipo_Producto', 'Cantidad', 'Costo_Unitario', 
        'Precio_Venta', 'Margen_Utilidad', 'Movimiento', 'Sede_Destino'
      ]);
    }

    const row = [
      data.id,
      data.timestamp || new Date().toISOString(),
      data.username,
      data.role,
      data.sedeId,
      data.reference,
      data.type,
      data.quantity,
      data.cost,
      data.salePrice,
      data.salePrice - data.cost,
      data.movementType,
      data.destinationSedeId || ''
    ];

    sheet.appendRow(row);

    return ContentService.createTextOutput(JSON.stringify({ status: 'success' }))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ status: 'error', message: err.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}

function doGet() {
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);
  const sheet = ss.getSheetByName(SHEET_NAME);
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();

  const result = data.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  });

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

import React, { useState, useEffect, useMemo } from 'react';
