    e.preventDefault();
    registerMovement({
      id: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      userId: user.id,
      username: user.name,
      sedeId: user.role === 'GERENTE' && filterSede !== 'ALL' ? filterSede : user.sedeId,
      reference: movForm.reference,
      type: movForm.type,
      movementType: movForm.movType,
      quantity: movForm.quantity,
      cost: movForm.cost,
      salePrice: movForm.salePrice,
      margin: movForm.salePrice - movForm.cost
