              value={filterSede}
              onChange={(e) => setFilterSede(e.target.value as any)}
            />
          )}
          <Button variant="secondary" onClick={onLogout} className="text-xs py-1.5">Salir</Button>
        </div>
      </header>

      <main className="p-6 max-w-[1600px] mx-auto w-full space-y-8">
        {/* KPI Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <p className="text-slate-400 text-xs font-bold uppercase tracking-wider">Inversión Total</p>
            <h3 className="text-3xl font-black text-slate-800 mt-2">${stats.totalInversion.toLocaleString()}</h3>
            <div className="mt-3 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
               <div className="bg-indigo-500 h-full" style={{width: '65%'}}></div>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <p className="text-slate-400 text-xs font-bold uppercase tracking-wider">Rentabilidad Proyectada</p>
            <h3 className="text-3xl font-black text-emerald-600 mt-2">${stats.totalRentabilidad.toLocaleString()}</h3>
            <p className="text-xs text-emerald-500 font-medium mt-1">Margen promedio: {stock.length ? Math.round((stats.totalRentabilidad / (stats.totalInversion + 1)) * 100) : 0}%</p>
          </div>
