import React, { useState, useEffect, useMemo } from 'react';
import { User, ProductStock, Movement, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES } from '../constants';
import { calculateStock, registerMovement, executeTransfer, getMovements } from '../services/storageService';
import { Button, Input, Select, Modal } from './UI';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [stock, setStock] = useState<ProductStock[]>([]);
  const [movements, setMovements] = useState<Movement[]>([]);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isTransferModalOpen, setIsTransferModalOpen] = useState(false);

  // Form States
  const [movForm, setMovForm] = useState({
    reference: '',
    type: PRODUCT_CATEGORIES[0],
    quantity: 0,
    cost: 0,
    salePrice: 0,
    movType: 'ENTRADA' as MovementType
  });

  const [transferForm, setTransferForm] = useState({
    reference: '',
    quantity: 0,
    originSede: user.sedeId,
    destSede: SEDES[0].id
  });

  const loadData = () => {
    const currentSedeFilter = filterSede === 'ALL' ? undefined : filterSede;
    setStock(calculateStock(currentSedeFilter));
    setMovements(getMovements().reverse().slice(0, 10)); // Top 10 latest
  };

  useEffect(() => { loadData(); }, [filterSede]);

  const stats = useMemo(() => {
    const totalInversion = stock.reduce((acc, p) => acc + (p.cost * p.quantity), 0);
    const totalRentabilidad = stock.reduce((acc, p) => acc + (p.margin * p.quantity), 0);
    const lowStockCount = stock.filter(p => p.quantity < 5).length;

    // Categorías para el mini-gráfico
    const categoryDist: Record<string, number> = {};
    stock.forEach(p => categoryDist[p.type] = (categoryDist[p.type] || 0) + p.quantity);

    return { totalInversion, totalRentabilidad, lowStockCount, categoryDist };
  }, [stock]);

  const handleMovSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    registerMovement({
      id: crypto.randomUUID(),
      timestamp: new Date().toISOString(),
      userId: user.id,
      username: user.name,
      sedeId: user.role === 'GERENTE' && filterSede !== 'ALL' ? (filterSede as SedeId) : user.sedeId,
      reference: movForm.reference,
      type: movForm.type,
      movementType: movForm.movType,
      quantity: movForm.quantity,
      cost: movForm.cost,
      salePrice: movForm.salePrice,
      margin: movForm.salePrice - movForm.cost
    });
    setIsMovModalOpen(false);
    loadData();
  };

  const handleTransferSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const product = stock.find(p => p.reference === transferForm.reference && p.sedeId === transferForm.originSede);
    if (!product || product.quantity < transferForm.quantity) {
      alert('Stock insuficiente en origen');
      return;
    }
    executeTransfer(
      user.id,
      user.name,
      transferForm.reference,
      product.type,
      transferForm.quantity,
      transferForm.originSede,
      transferForm.destSede,
      product.cost,
      product.salePrice
    );
    setIsTransferModalOpen(false);
    loadData();
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      {/* Navbar Superior */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex flex-col md:flex-row md:items-center justify-between gap-4 sticky top-0 z-30">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg shadow-indigo-200">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2"></path></svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tight">YEILU STORE</h1>
            <div className="flex items-center gap-2">
              <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${user.role === 'GERENTE' ? 'bg-amber-100 text-amber-700' : 'bg-blue-100 text-blue-700'}`}>
                {user.role}
              </span>
              <span className="text-xs text-slate-400 font-medium">Sede: {SEDES.find(s => s.id === user.sedeId)?.name}</span>
            </div>
          </div>
        </div>

        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <Select 
              className="text-sm py-1.5 min-w-[180px]"
              options={[{ value: 'ALL', label: 'Consolidado Global' }, ...SEDES.map(s => ({ value: s.id, label: s.name }))]}
              value={filterSede}
              onChange={(e) => setFilterSede(e.target.value as any)}
            />
          )}
          <Button variant="secondary" onClick={onLogout} className="text-xs py-1.5">Salir</Button>
        </div>
      </header>

      <main className="p-6 max-w-[1600px] mx-auto w-full space-y-8">
        {/* KPI Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
            <p className="text-slate-400 text-xs font-bold uppercase tracking-wider">Inversión Total</p>
            <h3 className="text-3xl font-black text-slate-800 mt-2">${stats.totalInversion.toLocaleString()}</h3>
            <div className="mt-3 w-full bg-slate-100 h-1.5 rounded-full overflow-hidden">
               <div className="bg-indigo-500 h-full" style={{width: '65%'}}></div>
            </div>
          </div>
          <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-200">
