            {/* Added explicit type casting and ensured division safety to fix arithmetic operation error */}
            <p className="text-xs text-emerald-500 font-medium mt-1">Margen promedio: {stock.length ? Math.round(((stats.totalRentabilidad as number) / ((stats.totalInversion as number) + 1)) * 100) : 0}%</p>
