const SPREADSHEET_ID = 'TU_ID_DE_GOOGLE_SHEET_AQUÍ';

function doPost(e) {
  const data = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  if (data.action === 'REGISTER_PRODUCT') {
    const sheet = ss.getSheetByName('Maestro_Productos');
    sheet.appendRow([data.reference, data.name, data.type, data.cost, data.salePrice, data.minStock]);
    return response({ status: 'success' });
  }

  if (data.action === 'REGISTER_MOVEMENT') {
    const sheet = ss.getSheetByName('Log_Movimientos');
    sheet.appendRow([
      Utilities.getUuid(),
      new Date().toISOString(),
      data.username,
      data.sedeId,
      data.reference,
      data.quantity,
      data.movementType,
      data.destinationSedeId || ''
    ]);
    return response({ status: 'success' });
  }
}

function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  if (action === 'GET_ALL') {
    const maestro = getSheetData(ss, 'Maestro_Productos');
    const logs = getSheetData(ss, 'Log_Movimientos');
    return response({ maestro, logs });
  }
}

function getSheetData(ss, name) {
  const sheet = ss.getSheetByName(name);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  const headers = data.shift();
  return data.map(row => {
    let obj = {};
    headers.forEach((h, i) => obj[h] = row[i]);
    return obj;
  });
}

function response(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj)).setMimeType(ContentService.MimeType.JSON);
}

export type SedeId = 'taller' | 'country' | 'plaza_sol' | 'portal_prado' | 'centro';
export type UserRole = 'OPERADOR' | 'GERENTE';
export type MovementType = 'ENTRADA' | 'SALIDA' | 'TRASLADO' | 'AJUSTE';

export interface MaestroProducto {
  Referencia: string;
  Nombre: string;
  Tipo: string;
  Costo: number;
  Precio_Venta: number;
  Stock_Minimo: number;
}

export interface LogMovimiento {
  ID_Mov: string;
  Timestamp: string;
  Usuario: string;
  Sede: SedeId;
  Referencia: string;
  Cantidad: number;
  Tipo_Movimiento: MovementType;
  Sede_Destino?: SedeId;
}

export interface ProductStock extends MaestroProducto {
  Stock_Actual: number;
  SedeId: SedeId;
}

export interface User {
  id: string;
  username: string;
  password?: string;
  sedeId: SedeId;
  role: UserRole;
  name: string;
}

import React, { useEffect } from 'react';

interface QRScannerProps {
  onScan: (decodedText: string) => void;
  onClose: () => void;
}

export const QRScanner: React.FC<QRScannerProps> = ({ onScan, onClose }) => {
  useEffect(() => {
    const html5QrCode = new (window as any).Html5Qrcode("reader");
    const config = { fps: 10, qrbox: { width: 250, height: 250 } };

    html5QrCode.start(
      { facingMode: "environment" }, 
      config, 
      (decodedText: string) => {
        onScan(decodedText);
        html5QrCode.stop();
      },
      () => {}
    ).catch((err: any) => console.error("Error QR:", err));

    return () => {
      if (html5QrCode.isScanning) {
        html5QrCode.stop();
      }
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[60] bg-black flex flex-col items-center justify-center p-4">
      <div className="w-full max-w-sm bg-white rounded-3xl overflow-hidden relative">
        <button onClick={onClose} className="absolute top-4 right-4 z-[70] bg-slate-900/50 text-white p-2 rounded-full">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path></svg>
        </button>
        <div id="reader" className="w-full"></div>
        <div className="p-6 text-center">
          <h3 className="font-bold text-slate-800">Escanea la Referencia</h3>
          <p className="text-xs text-slate-500 mt-1">Apunta al código QR del producto</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
