                      </span>
                    </td>
                    {user.role === 'GERENTE' && <td className="p-4 font-bold text-slate-600">${s.Precio_Venta.toLocaleString()}</td>}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL REGISTRO MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="Registrar Operación">
         <div className="space-y-4">
            <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
            <div className="grid grid-cols-2 gap-4">
               <Select 
                  label="Acción" 
                  options={[
                    {value: 'SALIDA', label: 'Venta / Salida'},
                    {value: 'ENTRADA', label: 'Compra / Entrada'},
                    {value: 'TRASLADO', label: 'Traslado Inter-Sede'},
                    {value: 'AJUSTE', label: 'Ajuste Inventario'}
                  ]}
                  value={movForm.type}
                  onChange={e => setMovForm({...movForm, type: e.target.value as any})}
               />
               <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
            </div>
            {movForm.type === 'TRASLADO' && (
              <Select 
                label="Sede Destino" 
                options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value: s.id, label: s.name}))}
                value={movForm.destSede}
                onChange={e => setMovForm({...movForm, destSede: e.target.value as any})}
              />
            )}
            <Button fullWidth onClick={registerMovement}>Registrar en Log</Button>
         </div>
      </Modal>

      {/* MODAL REGISTRO MAESTRO (PARA NUEVOS QR) */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="Nuevo Producto Maestro">
         <div className="space-y-4">
            <p className="text-[10px] text-indigo-600 font-bold bg-indigo-50 p-2 rounded">Escaneaste una referencia nueva: {newMaestro.reference}</p>
            <Input label="Nombre Producto" value={newMaestro.name} onChange={e => setNewMaestro({...newMaestro, name: e.target.value})} />
            <Select 
              label="Categoría" 
              options={PRODUCT_CATEGORIES.map(c => ({value: c, label: c}))} 
              value={newMaestro.type}
              onChange={e => setNewMaestro({...newMaestro, type: e.target.value})}
            />
            <div className="grid grid-cols-2 gap-4">
               <Input label="Costo" type="number" value={newMaestro.cost} onChange={e => setNewMaestro({...newMaestro, cost: Number(e.target.value)})} />
               <Input label="Precio Venta" type="number" value={newMaestro.salePrice} onChange={e => setNewMaestro({...newMaestro, salePrice: Number(e.target.value)})} />
            </div>
            <Button fullWidth onClick={registerMaestro}>Guardar en Maestro</Button>
         </div>
      </Modal>
    </div>
  );
};

