import React, { useEffect, useState } from 'react';

interface QRScannerProps {
  onScan: (decodedText: string) => void;
  onClose: () => void;
}

export const QRScanner: React.FC<QRScannerProps> = ({ onScan, onClose }) => {
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const html5QrCode = new (window as any).Html5Qrcode("reader");
    const config = { fps: 10, qrbox: { width: 250, height: 250 } };

    html5QrCode.start(
      { facingMode: "environment" }, 
      config, 
      (decodedText: string) => {
        onScan(decodedText);
        html5QrCode.stop().catch(e => console.error("Error stopping scanner", e));
      },
      () => {}
    ).catch((err: any) => {
      console.error("Error QR:", err);
      if (err?.toString().includes("NotAllowedError") || err?.toString().includes("Permission denied")) {
        setError("El acceso a la cámara fue denegado. Por favor, permite el uso de la cámara en la configuración de tu navegador para poder escanear.");
      } else {
        setError("No se pudo iniciar la cámara. Asegúrate de que ningún otro programa la esté usando.");
      }
    });

    return () => {
      if (html5QrCode.isScanning) {
        html5QrCode.stop().catch(e => console.error("Error cleanup scanner", e));
      }
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[60] bg-black/90 flex flex-col items-center justify-center p-4 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-white rounded-3xl overflow-hidden relative shadow-2xl">
        <button 
          onClick={onClose} 
          className="absolute top-4 right-4 z-[70] bg-slate-900/50 hover:bg-slate-900 text-white p-2 rounded-full transition-colors"
          aria-label="Cerrar escáner"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"></path>
          </svg>
        </button>

        <div className="relative">
          <div id="reader" className="w-full aspect-square bg-slate-100"></div>

          {error && (
            <div className="absolute inset-0 bg-white flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-300">
              <div className="bg-red-100 text-red-600 p-4 rounded-full mb-4">
                <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path>
                </svg>
              </div>
              <h4 className="text-lg font-bold text-slate-800 mb-2">Error de Cámara</h4>
              <p className="text-sm text-slate-600 mb-6 leading-relaxed">{error}</p>
              <button 
                onClick={() => window.location.reload()} 
                className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100"
              >
                Reintentar / Recargar
              </button>
            </div>
          )}
        </div>

        {!error && (
          <div className="p-6 text-center bg-white border-t border-slate-50">
            <h3 className="font-bold text-slate-800">Escanea la Referencia</h3>
            <p className="text-xs text-slate-500 mt-1">Apunta al código QR del producto Yeilu Store</p>
          </div>
        )}
      </div>
    </div>
  );
};

