      const foundUser = usersTable.find((u: any) => 
        u.Correo.trim().toLowerCase() === loginForm.email.trim().toLowerCase() && 
        String(u.Contraseña) === loginForm.password
      );

      if (!foundUser) {
        throw new Error("Correo o contraseña incorrectos.");
      }

      const userData: User = {
        id: foundUser.Correo,
        username: foundUser.Nombre,
        sedeId: foundUser.Sede as SedeId,
        role: foundUser.Perfil as UserRole,
        name: foundUser.Nombre
      };

      setAuthState({ user: userData, isAuthenticated: true });
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'Error de conexión.');
    } finally {
      setIsLoading(false);
