import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form States
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });
  const [newMaestro, setNewMaestro] = useState({ reference: '', name: '', type: PRODUCT_CATEGORIES[0], cost: 0, salePrice: 0, minStock: 5 });

  const loadData = async () => {
    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setIsLoading(false);
      return;
    }

    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      if (!response.ok) throw new Error("Error cargando datos");
      const data = await response.json();

      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error conectando con Sheets:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // LÓGICA DE BALANCE DE STOCK & ANALYTICS
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    logs.forEach(log => {
      const key = `${log.Referencia}_${log.Sede}`;
      const productInfo = maestro.find(m => m.Referencia === log.Referencia);

      if (!productInfo) return;

      if (!stockMap[key]) {
        stockMap[key] = { 
          ...productInfo, 
          Costo: Number(productInfo.Costo) || 0,
          Precio_Venta: Number(productInfo.Precio_Venta) || 0,
          Stock_Actual: 0, 
          SedeId: log.Sede 
        };
      }

      const cantidad = Number(log.Cantidad) || 0;
      if (log.Tipo_Movimiento === 'ENTRADA' || log.Tipo_Movimiento === 'AJUSTE') {
        stockMap[key].Stock_Actual += cantidad;
      } else if (log.Tipo_Movimiento === 'SALIDA') {
        stockMap[key].Stock_Actual -= cantidad;
      } else if (log.Tipo_Movimiento === 'TRASLADO') {
        stockMap[key].Stock_Actual -= cantidad;
        const destKey = `${log.Referencia}_${log.Sede_Destino}`;
        if (!stockMap[destKey]) {
           stockMap[destKey] = { 
             ...productInfo, 
             Costo: Number(productInfo.Costo) || 0,
             Precio_Venta: Number(productInfo.Precio_Venta) || 0,
             Stock_Actual: 0, 
             SedeId: log.Sede_Destino! 
           };
        }
        stockMap[destKey].Stock_Actual += cantidad;
      }
    });

    return Object.values(stockMap);
  }, [logs, maestro]);

  const filteredStock = useMemo(() => {
    return allStockData.filter(s => filterSede === 'ALL' || s.SedeId === filterSede);
  }, [allStockData, filterSede]);

  // KPIs GLOBALES (Para Gerencia)
  const stats = useMemo(() => {
    const totalCost = filteredStock.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalPotentialSale = filteredStock.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);
    const totalItems = filteredStock.reduce((acc, s) => acc + s.Stock_Actual, 0);
    const avgMargin = totalPotentialSale > 0 ? ((totalPotentialSale - totalCost) / totalPotentialSale) * 100 : 0;

    // Top productos por margen
    const topMarginProducts = [...maestro]
      .map(m => ({ ...m, margin: Number(m.Precio_Venta) - Number(m.Costo) }))
      .sort((a, b) => b.margin - a.margin)
      .slice(0, 5);

    // Stock por Sede (Comparativo)
    const sedeComparison = SEDES.map(sede => {
      const sedeStock = allStockData.filter(s => s.SedeId === sede.id);
      return {
        name: sede.name,
        totalValue: sedeStock.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
        units: sedeStock.reduce((acc, s) => acc + s.Stock_Actual, 0)
      };
    });

    return { totalCost, totalPotentialSale, totalItems, avgMargin, topMarginProducts, sedeComparison };
  }, [filteredStock, maestro, allStockData]);

  const handleQRScan = (ref: string) => {
    setIsQRVisible(false);
    const product = maestro.find(m => m.Referencia === ref);
    if (product) {
      setMovForm({ ...movForm, reference: ref });
      setIsMovModalOpen(true);
    } else {
      setNewMaestro({ ...newMaestro, reference: ref, name: '', cost: 0, salePrice: 0 });
      setIsMaestroModalOpen(true);
    }
  };

  const registerMovement = async () => {
    setIsSubmitting(true);
    const movementData = {
      action: 'REGISTER_MOVEMENT',
      username: user.name,
      sedeId: user.sedeId,
      reference: movForm.reference,
      quantity: movForm.quantity,
      movementType: movForm.type,
      destinationSedeId: movForm.type === 'TRASLADO' ? movForm.destSede : ''
    };

    try {
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(movementData)
      });

      const newLog: LogMovimiento = {
        ID_Mov: crypto.randomUUID(),
        Timestamp: new Date().toISOString(),
        Usuario: user.name,
        Sede: user.sedeId,
        Referencia: movForm.reference,
        Cantidad: movForm.quantity,
        Tipo_Movimiento: movForm.type,
        Sede_Destino: movForm.type === 'TRASLADO' ? movForm.destSede : undefined
      };
      setLogs(prev => [...prev, newLog]);
      setIsMovModalOpen(false);
      setTimeout(loadData, 1500);
    } catch (error) {
      console.error(error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const registerMaestro = async () => {
    setIsSubmitting(true);
    const productData = {
      action: 'REGISTER_PRODUCT',
      reference: newMaestro.reference,
      name: newMaestro.name,
      type: newMaestro.type,
      cost: newMaestro.cost,
      salePrice: newMaestro.salePrice,
      minStock: newMaestro.minStock
    };

    try {
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(productData)
      });

      const product: MaestroProducto = {
        Referencia: newMaestro.reference,
        Nombre: newMaestro.name,
        Tipo: newMaestro.type,
        Costo: newMaestro.cost,
        Precio_Venta: newMaestro.salePrice,
        Stock_Minimo: newMaestro.minStock
      };
      setMaestro(prev => [...prev, product]);
      setIsMaestroModalOpen(false);
      setTimeout(loadData, 1500);
    } catch (error) {
      console.error(error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-12">
      {isQRVisible && <QRScanner onScan={handleQRScan} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white/80 backdrop-blur-md border-b p-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg shadow-indigo-200">
             {isLoading ? (
               <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
             ) : (
               <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
             )}
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 uppercase tracking-tighter leading-none">Yeilu Kardex</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">{user.sedeId} • {user.role}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsQRVisible(true)} className="bg-slate-900 text-white p-3 rounded-2xl shadow-xl hover:scale-105 transition-all active:scale-95">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z"></path></svg>
          </button>
          <Button variant="secondary" onClick={onLogout} className="rounded-2xl text-xs px-4">Salir</Button>
        </div>
      </header>

      <main className="p-4 space-y-6 max-w-7xl mx-auto">
        {/* FILTROS Y ESTADO SINC */}
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="w-full md:w-auto flex gap-2 overflow-x-auto pb-2 md:pb-0 no-scrollbar">
            {user.role === 'GERENTE' && (
              <Select 
                className="bg-white min-w-[200px]"
                options={[{value: 'ALL', label: 'Ver Todas las Sedes'}, ...SEDES.map(s => ({value: s.id, label: s.name}))]}
                value={filterSede}
                onChange={e => setFilterSede(e.target.value as any)}
              />
            )}
            <Button variant="secondary" onClick={loadData} className="bg-white text-xs whitespace-nowrap">
              <svg className={`w-3.5 h-3.5 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2"></path></svg>
              Sincronizar
            </Button>
          </div>
          {isLoading && (
            <div className="flex items-center gap-2 text-indigo-600 animate-pulse">
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-ping"></div>
              <span className="text-[10px] font-black uppercase tracking-widest">Conectando Sheets...</span>
            </div>
          )}
        </div>

        {/* KPIs PARA GERENCIA */}
        {user.role === 'GERENTE' && (
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
             <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-50 rounded-full -mr-8 -mt-8 transition-transform group-hover:scale-110"></div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inversión Stock</p>
               <h3 className="text-2xl font-black text-slate-800 mt-2">
                 ${Math.round(stats.totalCost).toLocaleString()}
               </h3>
               <div className="mt-2 text-[10px] text-slate-400 font-bold uppercase">{stats.totalItems} unidades en bodega</div>
             </div>

             <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-50 rounded-full -mr-8 -mt-8 transition-transform group-hover:scale-110"></div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Proyección Ventas</p>
               <h3 className="text-2xl font-black text-emerald-600 mt-2">
                 ${Math.round(stats.totalPotentialSale).toLocaleString()}
               </h3>
               <div className="mt-2 text-[10px] text-emerald-500 font-bold uppercase">Utilidad Estimada: ${Math.round(stats.totalPotentialSale - stats.totalCost).toLocaleString()}</div>
             </div>

             <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-100 relative overflow-hidden group">
               <div className="absolute top-0 right-0 w-24 h-24 bg-rose-50 rounded-full -mr-8 -mt-8 transition-transform group-hover:scale-110"></div>
               <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Margen Promedio</p>
               <h3 className="text-2xl font-black text-slate-800 mt-2">
                 {stats.avgMargin.toFixed(1)}%
               </h3>
               <div className="mt-2 text-[10px] text-rose-500 font-bold uppercase">{filteredStock.filter(s => s.Stock_Actual < s.Stock_Minimo).length} Prendas en Stock Crítico</div>
             </div>

             <div className="bg-indigo-600 p-5 rounded-[2rem] shadow-xl shadow-indigo-100 text-white relative overflow-hidden">
               <svg className="absolute bottom-0 right-0 w-32 h-32 text-white/10 -mb-8 -mr-8" fill="currentColor" viewBox="0 0 20 20"><path d="M2 11a1 1 0 011-1h2a1 1 0 011 1v5a1 1 0 01-1 1H3a1 1 0 01-1-1v-5zM8 7a1 1 0 011-1h2a1 1 0 011 1v9a1 1 0 01-1 1H9a1 1 0 01-1-1V7zM14 4a1 1 0 011-1h2a1 1 0 011 1v12a1 1 0 01-1 1h-2a1 1 0 01-1-1V4z"></path></svg>
               <p className="text-[10px] font-black text-indigo-100 uppercase tracking-widest">Sede Más Rentable</p>
               <h3 className="text-xl font-bold mt-2">
                 {stats.sedeComparison.sort((a,b) => b.totalValue - a.totalValue)[0]?.name || '---'}
               </h3>
               <p className="text-[10px] mt-2 text-indigo-200">Basado en volumen de inversión actual</p>
             </div>
          </div>
        )}

        {/* COMPARATIVO DE SEDES (SOLO GERENTE) */}
        {user.role === 'GERENTE' && filterSede === 'ALL' && (
           <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
             <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
               <span className="w-1.5 h-6 bg-indigo-600 rounded-full"></span>
               Comparativo de Inventario por Sede
             </h2>
             <div className="grid grid-cols-2 md:grid-cols-5 gap-6">
                {stats.sedeComparison.map(s => (
                  <div key={s.name} className="flex flex-col gap-2">
                    <div className="text-[10px] font-black text-slate-400 uppercase truncate">{s.name}</div>
                    <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                       <div 
                        className="h-full bg-indigo-500 rounded-full" 
                        style={{ width: `${(s.totalValue / stats.totalCost) * 100}%` }}
                       ></div>
                    </div>
                    <div className="flex justify-between items-center">
                       <span className="text-xs font-bold text-slate-700">${Math.round(s.totalValue/1000)}k</span>
                       <span className="text-[9px] font-black text-slate-400">{s.units} unds</span>
                    </div>
                  </div>
                ))}
             </div>
           </div>
        )}

        {/* TABLA PRINCIPAL */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
            <div>
              <h2 className="font-black text-slate-800 uppercase tracking-widest text-sm">Inventario de Prendas</h2>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tight mt-1">
                {filterSede === 'ALL' ? 'Mostrando consolidado total' : `Sede: ${SEDES.find(s=>s.id===filterSede)?.name}`}
              </p>
            </div>
            <button 
              onClick={() => setIsMovModalOpen(true)} 
              className="bg-indigo-50 text-indigo-600 px-4 py-2 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-100 transition-colors"
            >
              + Registro Manual
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left border-collapse">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase border-b border-slate-50">
                  <th className="p-6">Prenda / Referencia</th>
                  <th className="p-6">Categoría</th>
                  <th className="p-6 text-center">Stock Actual</th>
                  {user.role === 'GERENTE' && <th className="p-6">P. Venta</th>}
                  {user.role === 'GERENTE' && <th className="p-6">Margen</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredStock.map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className={`hover:bg-slate-50/80 transition-colors ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-50/20' : ''}`}>
                    <td className="p-6">
                      <div className="font-black text-slate-800 text-sm tracking-tight">{s.Referencia}</div>
                      <div className="text-[10px] text-slate-400 uppercase font-bold mt-0.5">{s.Nombre}</div>
                    </td>
                    <td className="p-6">
                      <span className="text-[9px] px-2.5 py-1 bg-slate-100 text-slate-500 rounded-lg font-black uppercase tracking-tighter italic">{s.Tipo}</span>
                    </td>
                    <td className="p-6 text-center">
                      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl font-black text-xs ${s.Stock_Actual < s.Stock_Minimo ? 'text-rose-600 bg-rose-50 border border-rose-100' : 'text-emerald-600 bg-emerald-50 border border-emerald-100'}`}>
                        {s.Stock_Actual}
                        {s.Stock_Actual < s.Stock_Minimo && <span className="w-1.5 h-1.5 bg-rose-500 rounded-full animate-ping"></span>}
                      </div>
                    </td>
                    {user.role === 'GERENTE' && (
                      <td className="p-6 font-black text-slate-600 text-xs">
                        ${Math.round(s.Precio_Venta).toLocaleString()}
                      </td>
                    )}
                    {user.role === 'GERENTE' && (
                      <td className="p-6">
                        <div className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md inline-block">
                          {(((s.Precio_Venta - s.Costo) / s.Precio_Venta) * 100).toFixed(0)}% Util.
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
                {!isLoading && filteredStock.length === 0 && (
                  <tr><td colSpan={5} className="p-20 text-center text-slate-300 text-xs font-black uppercase tracking-widest italic">No se encontraron registros activos</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL REGISTRO MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="Operación de Inventario">
         <div className="space-y-4">
            <Input label="Referencia / SKU" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Eje: YEL-100" />
            <div className="grid grid-cols-2 gap-4">
               <Select 
                  label="Tipo de Acción" 
                  options={[
                    {value: 'SALIDA', label: 'Venta Directa'},
                    {value: 'ENTRADA', label: 'Carga de Stock'},
                    {value: 'TRASLADO', label: 'Traslado Sedes'},
                    {value: 'AJUSTE', label: 'Ajuste Manual'}
                  ]}
                  value={movForm.type}
                  onChange={e => setMovForm({...movForm, type: e.target.value as any})}
               />
               <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} min="1" />
            </div>
            {movForm.type === 'TRASLADO' && (
              <Select 
                label="Sede de Destino" 
                options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value: s.id, label: s.name}))}
                value={movForm.destSede}
                onChange={e => setMovForm({...movForm, destSede: e.target.value as any})}
              />
            )}
            <Button fullWidth onClick={registerMovement} disabled={isSubmitting || !movForm.reference} className="py-4 rounded-2xl font-black uppercase tracking-widest text-[11px]">
              {isSubmitting ? 'Sincronizando...' : 'Confirmar Registro'}
            </Button>
         </div>
      </Modal>

      {/* MODAL REGISTRO MAESTRO */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="Nueva Referencia Maestro">
         <div className="space-y-4">
            <div className="bg-indigo-600 p-4 rounded-2xl text-white mb-2">
              <p className="text-[10px] font-black uppercase tracking-widest opacity-80 text-indigo-200">Nueva Prenda Detectada</p>
              <h4 className="text-xl font-black tracking-tighter uppercase">{newMaestro.reference}</h4>
            </div>
            <Input label="Nombre de la Prenda" value={newMaestro.name} onChange={e => setNewMaestro({...newMaestro, name: e.target.value})} placeholder="Eje: Vestido Gala Rojo M" />
            <Select 
              label="Línea / Categoría" 
              options={PRODUCT_CATEGORIES.map(c => ({value: c, label: c}))} 
              value={newMaestro.type}
              onChange={e => setNewMaestro({...newMaestro, type: e.target.value})}
            />
            <div className="grid grid-cols-2 gap-4">
               <Input label="Costo de Fabricación" type="number" value={newMaestro.cost} onChange={e => setNewMaestro({...newMaestro, cost: Number(e.target.value)})} />
               <Input label="Precio al Público" type="number" value={newMaestro.salePrice} onChange={e => setNewMaestro({...newMaestro, salePrice: Number(e.target.value)})} />
            </div>
            <Button fullWidth onClick={registerMaestro} disabled={isSubmitting || !newMaestro.name} variant="primary" className="py-4 rounded-2xl font-black uppercase tracking-widest text-[11px]">
               {isSubmitting ? 'Guardando en Maestro...' : 'Crear Producto Maestro'}
            </Button>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });
  const [newMaestro, setNewMaestro] = useState({ reference: '', name: '', type: PRODUCT_CATEGORIES[0], cost: 0, salePrice: 0, minStock: 5 });

  // Función robusta para limpiar números de Sheets (ej. "$35.000" -> 35000)
  const parseSheetNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    const cleaned = String(val || '0').replace(/[$.]/g, '').replace(',', '.');
    return parseFloat(cleaned) || 0;
  };

  const loadData = async () => {
    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // LÓGICA DE BALANCE INTEGRAL (MAESTRO + LOGS)
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Inicializar con todos los productos del maestro para cada sede activa
    const sedesToInit = filterSede === 'ALL' ? SEDES.map(s => s.id) : [filterSede];

    maestro.forEach(p => {
      sedesToInit.forEach(sedeId => {
        const key = `${p.Referencia}_${sedeId}`;
        stockMap[key] = {
          ...p,
          Costo: parseSheetNumber(p.Costo),
          Precio_Venta: parseSheetNumber(p.Precio_Venta),
          Stock_Minimo: parseSheetNumber(p.Stock_Minimo),
          Stock_Actual: 0,
          SedeId: sedeId as SedeId
        };
      });
    });

    // 2. Aplicar movimientos sobre el mapa base
    logs.forEach(log => {
      const key = `${log.Referencia}_${log.Sede}`;
      const cantidad = parseSheetNumber(log.Cantidad);

      // Solo procesar si el producto existe en el maestro
      if (stockMap[key]) {
        if (log.Tipo_Movimiento === 'ENTRADA' || log.Tipo_Movimiento === 'AJUSTE') {
          stockMap[key].Stock_Actual += cantidad;
        } else if (log.Tipo_Movimiento === 'SALIDA') {
          stockMap[key].Stock_Actual -= cantidad;
        } else if (log.Tipo_Movimiento === 'TRASLADO') {
          stockMap[key].Stock_Actual -= cantidad;
          const destKey = `${log.Referencia}_${log.Sede_Destino}`;
          if (stockMap[destKey]) {
            stockMap[destKey].Stock_Actual += cantidad;
          }
        }
      }
    });

    return Object.values(stockMap);
  }, [logs, maestro, filterSede]);

  // KPIs ESTRATÉGICOS
  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);
    const totalUnits = allStockData.reduce((acc, s) => acc + s.Stock_Actual, 0);
    const lowStockCount = allStockData.filter(s => s.Stock_Actual < s.Stock_Minimo).length;

    const sedeComparison = SEDES.map(sede => {
      const sedeStock = allStockData.filter(s => s.SedeId === sede.id);
      return {
        name: sede.name,
        value: sedeStock.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
        units: sedeStock.reduce((acc, s) => acc + s.Stock_Actual, 0)
      };
    });

    return { totalCost, totalSale, totalUnits, lowStockCount, sedeComparison };
  }, [allStockData]);

  const handleQRScan = (ref: string) => {
    setIsQRVisible(false);
    const product = maestro.find(m => m.Referencia === ref);
    if (product) {
      setMovForm({ ...movForm, reference: ref });
      setIsMovModalOpen(true);
    } else {
      setNewMaestro({ ...newMaestro, reference: ref });
      setIsMaestroModalOpen(true);
    }
  };

  const registerMovement = async () => {
    setIsSubmitting(true);
    try {
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'REGISTER_MOVEMENT',
          username: user.name,
          sedeId: user.sedeId,
          reference: movForm.reference,
          quantity: movForm.quantity,
          movementType: movForm.type,
          destinationSedeId: movForm.destSede
        })
      });
      setIsMovModalOpen(false);
      setTimeout(loadData, 1000);
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {isQRVisible && <QRScanner onScan={handleQRScan} onClose={() => setIsQRVisible(false)} />}

      {/* HEADER MODERNO */}
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tighter uppercase">Yeilu Store</h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">{user.sedeId} • {user.role}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsQRVisible(true)} className="bg-slate-900 text-white p-3 rounded-2xl hover:scale-105 active:scale-95 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
          <Button variant="secondary" onClick={onLogout} className="rounded-2xl">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">

        {/* FILTROS Y CONTROLES */}
        <div className="flex flex-wrap items-center justify-between gap-4">
          <div className="flex gap-2 items-center">
            {user.role === 'GERENTE' && (
              <Select 
                className="bg-white min-w-[220px] rounded-2xl border-slate-200 shadow-sm"
                options={[{value: 'ALL', label: 'Consolidado Todas las Sedes'}, ...SEDES.map(s => ({value: s.id, label: s.name}))]}
                value={filterSede}
                onChange={e => setFilterSede(e.target.value as any)}
              />
            )}
            <Button variant="ghost" onClick={loadData} className={`${isLoading ? 'animate-spin' : ''}`}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </Button>
          </div>
          {isLoading && <span className="text-[10px] font-black text-indigo-500 uppercase animate-pulse">Sincronizando Excel...</span>}
        </div>

        {/* INDICADORES CLAVE (KPIs) */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 group hover:border-indigo-200 transition-all">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inversión Total</p>
            <h2 className="text-3xl font-black text-slate-800 mt-2">${Math.round(stats.totalCost).toLocaleString()}</h2>
            <div className="mt-4 flex items-center gap-2">
              <span className="bg-slate-100 text-slate-500 text-[10px] font-black px-2 py-1 rounded-lg">{stats.totalUnits} PRENDAS EN STOCK</span>
            </div>
          </div>

          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 group hover:border-emerald-200 transition-all">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Venta Proyectada</p>
            <h2 className="text-3xl font-black text-emerald-600 mt-2">${Math.round(stats.totalSale).toLocaleString()}</h2>
            <p className="text-[10px] font-bold text-emerald-400 mt-2 uppercase">MARGEN EST: {stats.totalSale > 0 ? (((stats.totalSale - stats.totalCost)/stats.totalSale)*100).toFixed(1) : 0}%</p>
          </div>

          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Alertas de Stock</p>
            <h2 className={`text-3xl font-black mt-2 ${stats.lowStockCount > 0 ? 'text-rose-500' : 'text-slate-800'}`}>{stats.lowStockCount}</h2>
            <p className="text-[10px] font-bold text-slate-400 mt-2 uppercase">PRENDAS BAJO EL MÍNIMO</p>
          </div>

          <div className="bg-indigo-600 p-6 rounded-[2.5rem] shadow-xl shadow-indigo-100 text-white flex flex-col justify-between">
            <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">Sede Principal</p>
            <h2 className="text-xl font-black mt-2 leading-tight">
              {stats.sedeComparison.sort((a,b) => b.value - a.value)[0]?.name || '---'}
            </h2>
            <div className="mt-4 h-1.5 w-full bg-white/20 rounded-full overflow-hidden">
              <div className="h-full bg-white" style={{ width: '70%' }}></div>
            </div>
          </div>
        </div>

        {/* COMPARATIVO VISUAL DE SEDES */}
        {user.role === 'GERENTE' && filterSede === 'ALL' && (
          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8 flex items-center gap-2">
               <span className="w-1.5 h-6 bg-indigo-600 rounded-full"></span>
               Distribución de Valor por Sede
             </h3>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-8">
                {stats.sedeComparison.map(s => (
                  <div key={s.name} className="space-y-3">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] font-black text-slate-400 uppercase truncate pr-2">{s.name}</span>
                      <span className="text-xs font-black text-slate-700">${Math.round(s.value/1000)}k</span>
                    </div>
                    <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-indigo-500 transition-all duration-1000" 
                        style={{ width: stats.totalCost > 0 ? `${(s.value / stats.totalCost) * 100}%` : '0%' }}
                      ></div>
                    </div>
                    <p className="text-[9px] font-bold text-slate-400 uppercase tracking-tight">{s.units} unidades</p>
                  </div>
                ))}
             </div>
          </div>
        )}

        {/* LISTADO DE PRENDAS */}
        <div className="bg-white rounded-[3rem] shadow-sm border border-slate-100 overflow-hidden">
          <div className="px-8 py-6 border-b border-slate-50 flex justify-between items-center bg-slate-50/50">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Inventario Detallado</h3>
            <button 
              onClick={() => setIsMovModalOpen(true)}
              className="bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest px-6 py-2.5 rounded-2xl shadow-lg shadow-indigo-100 hover:scale-105 transition-all"
            >
              + Nuevo Movimiento
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-8 py-5">Prenda / Ref</th>
                  <th className="px-8 py-5">Línea</th>
                  <th className="px-8 py-5 text-center">Stock</th>
                  {user.role === 'GERENTE' && <th className="px-8 py-5">Valor Venta</th>}
                  {user.role === 'GERENTE' && <th className="px-8 py-5 text-right">Rentabilidad</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className={`hover:bg-slate-50/50 transition-colors ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-50/30' : ''}`}>
                    <td className="px-8 py-6">
                      <div className="font-black text-slate-800 text-sm tracking-tight">{s.Referencia}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase mt-0.5">{s.Nombre}</div>
                    </td>
                    <td className="px-8 py-6">
                      <span className="text-[9px] font-black uppercase tracking-tighter italic bg-slate-100 text-slate-500 px-2 py-1 rounded-lg">{s.Tipo}</span>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <div className={`inline-flex items-center gap-2 px-3 py-1.5 rounded-xl font-black text-xs ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual}
                        {s.Stock_Actual < s.Stock_Minimo && <span className="w-1.5 h-1.5 bg-rose-500 rounded-full animate-ping"></span>}
                      </div>
                    </td>
                    {user.role === 'GERENTE' && (
                      <td className="px-8 py-6 font-black text-slate-600 text-xs">
                        ${Math.round(s.Precio_Venta).toLocaleString()}
                      </td>
                    )}
                    {user.role === 'GERENTE' && (
                      <td className="px-8 py-6 text-right">
                        <div className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl inline-block">
                          {s.Precio_Venta > 0 ? (((s.Precio_Venta - s.Costo)/s.Precio_Venta)*100).toFixed(0) : 0}% Margen
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
                {allStockData.length === 0 && !isLoading && (
                  <tr>
                    <td colSpan={5} className="py-20 text-center">
                      <div className="text-slate-300 italic text-sm font-black uppercase tracking-widest">
                        Aún no tienes productos en el Maestro_Productos de tu Excel
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODALES */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="Registrar Movimiento">
        <div className="space-y-4">
          <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="EJ: YEL-101" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Acción" options={[{value:'SALIDA', label:'Venta'}, {value:'ENTRADA', label:'Entrada'}, {value:'TRASLADO', label:'Traslado'}, {value:'AJUSTE', label:'Ajuste'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="Sede Destino" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Button fullWidth onClick={registerMovement} disabled={isSubmitting}>{isSubmitting ? 'Sincronizando...' : 'Confirmar'}</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });
  const [newMaestro, setNewMaestro] = useState({ reference: '', name: '', type: PRODUCT_CATEGORIES[0], cost: 0, salePrice: 0, minStock: 5 });

  // Función ultra-robusta para números de Excel
  const parseSheetNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    // Elimina todo lo que no sea número, coma o punto
    const cleaned = String(val).replace(/[^0-9,.-]/g, '').replace(',', '.');
    return parseFloat(cleaned) || 0;
  };

  // Normalizador de strings para vinculación de tablas
  const normalize = (str: string) => String(str || '').trim().toLowerCase();

  const loadData = async () => {
    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // LÓGICA DE RECONCILIACIÓN DE DATOS (Relacionar Maestro con Logs)
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Poblamos el mapa con TODO el maestro para TODAS las sedes
    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      SEDES.forEach(sede => {
        const key = `${normRef}_${normalize(sede.id)}`;
        stockMap[key] = {
          ...p,
          Costo: parseSheetNumber(p.Costo),
          Precio_Venta: parseSheetNumber(p.Precio_Venta),
          Stock_Minimo: parseSheetNumber(p.Stock_Minimo),
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    // 2. Aplicamos movimientos de la tabla Log_Movimientos
    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      const normSede = normalize(log.Sede);
      const key = `${normRef}_${normSede}`;
      const cantidad = parseSheetNumber(log.Cantidad);

      // Si el producto existe en el maestro, actualizamos stock
      if (stockMap[key]) {
        if (log.Tipo_Movimiento === 'ENTRADA' || log.Tipo_Movimiento === 'AJUSTE') {
          stockMap[key].Stock_Actual += cantidad;
        } else if (log.Tipo_Movimiento === 'SALIDA') {
          stockMap[key].Stock_Actual -= cantidad;
        } else if (log.Tipo_Movimiento === 'TRASLADO') {
          stockMap[key].Stock_Actual -= cantidad;
          const destKey = `${normRef}_${normalize(log.Sede_Destino || '')}`;
          if (stockMap[destKey]) {
            stockMap[destKey].Stock_Actual += cantidad;
          }
        }
      }
    });

    // 3. Filtramos por la sede seleccionada en el UI
    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || normalize(s.SedeId) === normalize(filterSede)
    );
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);
    const totalUnits = allStockData.reduce((acc, s) => acc + s.Stock_Actual, 0);
    const lowStock = allStockData.filter(s => s.Stock_Actual < s.Stock_Minimo).length;

    const sedeStats = SEDES.map(sede => {
      const stockSede = allStockData.filter(s => normalize(s.SedeId) === normalize(sede.id));
      return {
        name: sede.name,
        value: stockSede.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
        units: stockSede.reduce((acc, s) => acc + s.Stock_Actual, 0)
      };
    });

    return { totalCost, totalSale, totalUnits, lowStock, sedeStats };
  }, [allStockData]);

  const handleQRScan = (ref: string) => {
    setIsQRVisible(false);
    const product = maestro.find(m => normalize(m.Referencia) === normalize(ref));
    if (product) {
      setMovForm({ ...movForm, reference: ref });
      setIsMovModalOpen(true);
    } else {
      setNewMaestro({ ...newMaestro, reference: ref });
      setIsMaestroModalOpen(true);
    }
  };

  const registerMovement = async () => {
    setIsSubmitting(true);
    try {
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'REGISTER_MOVEMENT',
          username: user.name,
          sedeId: user.sedeId,
          reference: movForm.reference,
          quantity: movForm.quantity,
          movementType: movForm.type,
          destinationSedeId: movForm.destSede
        })
      });
      setIsMovModalOpen(false);
      setTimeout(loadData, 1000);
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {isQRVisible && <QRScanner onScan={handleQRScan} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg shadow-indigo-100">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tighter uppercase leading-none">Yeilu Store</h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{user.sedeId} • {user.role}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsQRVisible(true)} className="bg-slate-900 text-white p-3 rounded-2xl hover:scale-105 active:scale-95 transition-all shadow-xl shadow-slate-200">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
          <Button variant="secondary" onClick={onLogout} className="rounded-2xl font-bold px-5">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">

        {/* BARRA DE ESTADO */}
        <div className="flex flex-wrap items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex gap-3 items-center">
            {user.role === 'GERENTE' && (
              <Select 
                className="bg-slate-50 border-none min-w-[240px] font-bold text-slate-700"
                options={[{value: 'ALL', label: '📊 Todas las Sedes (Consolidado)'}, ...SEDES.map(s => ({value: s.id, label: `📍 ${s.name}`}))]}
                value={filterSede}
                onChange={e => setFilterSede(e.target.value as any)}
              />
            )}
            <Button variant="ghost" onClick={loadData} className={`bg-slate-50 rounded-xl p-2 ${isLoading ? 'animate-spin' : ''}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2.5" strokeLinecap="round"/></svg>
            </Button>
          </div>
          {isLoading ? (
            <div className="flex items-center gap-2 text-indigo-600">
               <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
               <span className="text-[10px] font-black uppercase tracking-widest">Sincronizando con Google...</span>
            </div>
          ) : (
            <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-2">
              <div className="w-2 h-2 bg-emerald-500 rounded-full"></div> Datos Actualizados
            </span>
          )}
        </div>

        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 relative overflow-hidden group hover:shadow-xl hover:shadow-indigo-50 transition-all duration-300">
            <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-full -mr-16 -mt-16 group-hover:scale-110 transition-transform"></div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest relative">Inversión Stock</p>
            <h2 className="text-3xl font-black text-slate-800 mt-2 relative">${Math.round(stats.totalCost).toLocaleString()}</h2>
            <div className="mt-4 flex items-center gap-2 relative">
              <span className="bg-indigo-50 text-indigo-600 text-[10px] font-black px-3 py-1 rounded-full uppercase">{stats.totalUnits} Prendas en Stock</span>
            </div>
          </div>

          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100 relative overflow-hidden group hover:shadow-xl hover:shadow-emerald-50 transition-all duration-300">
            <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-50/50 rounded-full -mr-16 -mt-16 group-hover:scale-110 transition-transform"></div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest relative">Venta Estimada</p>
            <h2 className="text-3xl font-black text-emerald-600 mt-2 relative">${Math.round(stats.totalSale).toLocaleString()}</h2>
            <p className="text-[10px] font-bold text-emerald-400 mt-2 uppercase relative flex items-center gap-1">
              <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M12 7a1 1 0 110-2h5a1 1 0 011 1v5a1 1 0 11-2 0V8.414l-4.293 4.293a1 1 0 01-1.414 0L8 10.414l-4.293 4.293a1 1 0 01-1.414-1.414l5-5a1 1 0 011.414 0L11 10.586 14.586 7H12z" clipRule="evenodd"></path></svg>
              Rentabilidad: {stats.totalSale > 0 ? (((stats.totalSale - stats.totalCost)/stats.totalSale)*100).toFixed(1) : 0}%
            </p>
          </div>

          <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-slate-100">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock Crítico</p>
            <h2 className={`text-3xl font-black mt-2 ${stats.lowStock > 0 ? 'text-rose-500' : 'text-slate-800'}`}>{stats.lowStock}</h2>
            <div className="mt-4 flex items-center gap-2">
              <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase ${stats.lowStock > 0 ? 'bg-rose-50 text-rose-500' : 'bg-slate-50 text-slate-400'}`}>Referencias por Agotarse</span>
            </div>
          </div>

          <div className="bg-slate-900 p-6 rounded-[2.5rem] shadow-2xl text-white relative overflow-hidden group">
            <svg className="absolute bottom-0 right-0 w-40 h-40 text-white/5 -mb-10 -mr-10 group-hover:rotate-12 transition-transform" fill="currentColor" viewBox="0 0 24 24"><path d="M12 1L3 5v6c0 5.55 3.84 10.74 9 12 5.16-1.26 9-6.45 9-12V5l-9-4z"/></svg>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest relative">Sede más Activa</p>
            <h2 className="text-xl font-black mt-3 leading-tight relative uppercase">
              {stats.sedeStats.sort((a,b) => b.value - a.value)[0]?.name || '---'}
            </h2>
            <div className="mt-6 flex justify-between items-end relative">
               <div className="text-[9px] font-bold text-slate-500 uppercase">Eficiencia de Stock</div>
               <div className="text-xs font-black">100%</div>
            </div>
          </div>
        </div>

        {/* COMPARATIVO DE SEDES */}
        {user.role === 'GERENTE' && filterSede === 'ALL' && (
          <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-slate-100">
             <div className="flex justify-between items-center mb-10">
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-3">
                  <span className="w-2 h-8 bg-indigo-600 rounded-full"></span>
                  Balance de Inversión por Sede
                </h3>
             </div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-10">
                {stats.sedeStats.map(s => (
                  <div key={s.name} className="flex flex-col gap-4 group">
                    <div className="flex justify-between items-end">
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-tighter truncate max-w-[100px] group-hover:text-indigo-600 transition-colors">{s.name}</span>
                      <span className="text-xs font-black text-slate-700">${Math.round(s.value/1000)}k</span>
                    </div>
                    <div className="h-3 w-full bg-slate-50 rounded-full overflow-hidden border border-slate-100 p-0.5">
                      <div 
                        className="h-full bg-gradient-to-r from-indigo-500 to-indigo-400 rounded-full transition-all duration-1000 ease-out shadow-sm shadow-indigo-100" 
                        style={{ width: stats.totalCost > 0 ? `${(s.value / stats.totalCost) * 100}%` : '0%' }}
                      ></div>
                    </div>
                    <div className="flex justify-between text-[9px] font-black text-slate-400 uppercase">
                      <span>{s.units} Unds</span>
                      <span>{stats.totalUnits > 0 ? ((s.units/stats.totalUnits)*100).toFixed(0) : 0}%</span>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        )}

        {/* LISTADO DE INVENTARIO */}
        <div className="bg-white rounded-[3.5rem] shadow-sm border border-slate-100 overflow-hidden">
          <div className="px-8 py-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <div>
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Kardex de Inventario</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase mt-1 tracking-widest">Listado general de prendas y disponibilidad</p>
            </div>
            <button 
              onClick={() => setIsMovModalOpen(true)}
              className="bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest px-8 py-3.5 rounded-2xl shadow-xl shadow-indigo-100 hover:translate-y-[-2px] hover:shadow-indigo-200 transition-all active:scale-95"
            >
              + Nuevo Movimiento
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-10 py-6">Prenda / Referencia</th>
                  <th className="px-10 py-6">Línea de Moda</th>
                  <th className="px-10 py-6 text-center">Stock</th>
                  {user.role === 'GERENTE' && <th className="px-10 py-6">P. Venta</th>}
                  {user.role === 'GERENTE' && <th className="px-10 py-6 text-right">Utilidad</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className={`group hover:bg-slate-50/50 transition-colors ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-50/30' : ''}`}>
                    <td className="px-10 py-6">
                      <div className="font-black text-slate-800 text-sm tracking-tight group-hover:text-indigo-600 transition-colors">{s.Referencia}</div>
                      <div className="text-[10px] font-bold text-slate-400 uppercase mt-1 tracking-tight">{s.Nombre}</div>
                    </td>
                    <td className="px-10 py-6">
                      <span className="text-[9px] font-black uppercase tracking-tighter italic bg-slate-100 text-slate-500 px-3 py-1.5 rounded-xl border border-slate-200 group-hover:bg-indigo-50 group-hover:text-indigo-600 group-hover:border-indigo-100 transition-colors">{s.Tipo}</span>
                    </td>
                    <td className="px-10 py-6 text-center">
                      <div className={`inline-flex items-center gap-2 px-4 py-2 rounded-2xl font-black text-xs shadow-sm transition-transform group-hover:scale-110 ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-100 text-rose-600 border border-rose-200' : 'bg-emerald-100 text-emerald-600 border border-emerald-200'}`}>
                        {s.Stock_Actual}
                        {s.Stock_Actual < s.Stock_Minimo && <span className="w-1.5 h-1.5 bg-rose-500 rounded-full animate-ping"></span>}
                      </div>
                    </td>
                    {user.role === 'GERENTE' && (
                      <td className="px-10 py-6 font-black text-slate-600 text-xs">
                        ${Math.round(s.Precio_Venta).toLocaleString()}
                      </td>
                    )}
                    {user.role === 'GERENTE' && (
                      <td className="px-10 py-6 text-right">
                        <div className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-4 py-2 rounded-2xl border border-indigo-100 inline-block">
                          {s.Precio_Venta > 0 ? (((s.Precio_Venta - s.Costo)/s.Precio_Venta)*100).toFixed(0) : 0}% Margen
                        </div>
                      </td>
                    )}
                  </tr>
                ))}
                {allStockData.length === 0 && !isLoading && (
                  <tr>
                    <td colSpan={5} className="py-32 text-center">
                      <div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-6 text-slate-200">
                        <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4" strokeWidth="2"/></svg>
                      </div>
                      <div className="text-slate-400 text-xs font-black uppercase tracking-widest max-w-sm mx-auto leading-relaxed">
                        No hay datos vinculados. Revisa que las referencias en Maestro coincidan con los Logs en Excel.
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL REGISTRO MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📝 Operación de Stock">
        <div className="space-y-6">
          <Input label="Referencia de la Prenda" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="EJ: YEL-101" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Tipo de Movimiento" options={[{value:'SALIDA', label:'Venta'}, {value:'ENTRADA', label:'Entrada'}, {value:'TRASLADO', label:'Traslado'}, {value:'AJUSTE', label:'Ajuste'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="Sede de Destino" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Button fullWidth onClick={registerMovement} disabled={isSubmitting || !movForm.reference} className="py-5 text-xs font-black uppercase tracking-widest shadow-xl shadow-indigo-100">
             {isSubmitting ? 'Procesando...' : 'Confirmar Operación'}
          </Button>
        </div>
      </Modal>

      {/* MODAL NUEVO PRODUCTO */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="🆕 Nueva Referencia">
        <div className="space-y-5">
           <div className="bg-indigo-600 p-5 rounded-3xl text-white">
              <p className="text-[10px] font-black uppercase tracking-[0.2em] opacity-60">Creando en Maestro</p>
              <h4 className="text-2xl font-black tracking-tighter uppercase mt-1">{newMaestro.reference}</h4>
           </div>
           <Input label="Nombre / Descripción" value={newMaestro.name} onChange={e => setNewMaestro({...newMaestro, name: e.target.value})} placeholder="Vestido de Seda Rojo" />
           <Select label="Línea de Moda" options={PRODUCT_CATEGORIES.map(c => ({value:c, label:c}))} value={newMaestro.type} onChange={e => setNewMaestro({...newMaestro, type: e.target.value})} />
           <div className="grid grid-cols-2 gap-4">
              <Input label="Costo Fabricación" type="number" value={newMaestro.cost} onChange={e => setNewMaestro({...newMaestro, cost: Number(e.target.value)})} />
              <Input label="Precio de Venta" type="number" value={newMaestro.salePrice} onChange={e => setNewMaestro({...newMaestro, salePrice: Number(e.target.value)})} />
           </div>
           <Button fullWidth onClick={() => {}} disabled={isSubmitting} className="py-5 font-black uppercase tracking-widest">Crear Producto Maestro</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  const parseSheetNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    const cleaned = String(val).replace(/[^0-9,.-]/g, '').replace(',', '.');
    return parseFloat(cleaned) || 0;
  };

  const normalize = (str: string) => String(str || '').trim().toLowerCase();

  const loadData = async () => {
    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // LÓGICA DE UNIÓN DE TABLAS (MAESTRO + LOGS)
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      SEDES.forEach(sede => {
        const key = `${normRef}_${normalize(sede.id)}`;
        stockMap[key] = {
          ...p,
          Costo: parseSheetNumber(p.Costo),
          Precio_Venta: parseSheetNumber(p.Precio_Venta),
          Stock_Minimo: parseSheetNumber(p.Stock_Minimo),
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      const normSede = normalize(log.Sede);
      const key = `${normRef}_${normSede}`;
      const cantidad = parseSheetNumber(log.Cantidad);

      if (stockMap[key]) {
        if (log.Tipo_Movimiento === 'ENTRADA' || log.Tipo_Movimiento === 'AJUSTE') {
          stockMap[key].Stock_Actual += cantidad;
        } else if (log.Tipo_Movimiento === 'SALIDA') {
          stockMap[key].Stock_Actual -= cantidad;
        } else if (log.Tipo_Movimiento === 'TRASLADO') {
          stockMap[key].Stock_Actual -= cantidad;
          const destKey = `${normRef}_${normalize(log.Sede_Destino || '')}`;
          if (stockMap[destKey]) stockMap[destKey].Stock_Actual += cantidad;
        }
      }
    });

    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || normalize(s.SedeId) === normalize(filterSede)
    );
  }, [logs, maestro, filterSede]);

  // ESTADÍSTICAS PARA GRÁFICOS
  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);

    // Agrupación por Categoría (Gráfico 1)
    const categoryData = PRODUCT_CATEGORIES.map(cat => {
      const items = allStockData.filter(s => s.Tipo === cat);
      const value = items.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: cat, value };
    }).filter(c => c.value > 0).sort((a,b) => b.value - a.value);

    // Agrupación por Sede (Gráfico 2)
    const sedeData = SEDES.map(sede => {
      const items = allStockData.filter(s => normalize(s.SedeId) === normalize(sede.id));
      const value = items.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: sede.name, value };
    });

    return { totalCost, totalSale, categoryData, sedeData };
  }, [allStockData]);

  const handleQRScan = (ref: string) => {
    setIsQRVisible(false);
    setMovForm({ ...movForm, reference: ref });
    setIsMovModalOpen(true);
  };

  const registerMovement = async () => {
    setIsSubmitting(true);
    try {
      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'REGISTER_MOVEMENT',
          username: user.name,
          sedeId: user.sedeId,
          reference: movForm.reference,
          quantity: movForm.quantity,
          movementType: movForm.type,
          destinationSedeId: movForm.destSede
        })
      });
      setIsMovModalOpen(false);
      setTimeout(loadData, 1000);
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans">
      {isQRVisible && <QRScanner onScan={handleQRScan} onClose={() => setIsQRVisible(false)} />}

      {/* HEADER */}
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg shadow-indigo-200">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <div>
            <h1 className="text-xl font-black text-slate-800 tracking-tighter uppercase leading-none">Yeilu Analytics</h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{user.role} Dashboard</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => setIsQRVisible(true)} className="bg-slate-900 text-white p-3 rounded-2xl shadow-xl hover:scale-105 transition-all">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
          <Button variant="secondary" onClick={onLogout} className="rounded-2xl font-bold">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">

        {/* SELECTOR DE SEDE Y ESTADO */}
        <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-100 flex flex-wrap items-center justify-between gap-4">
           <div className="flex gap-3 items-center">
              {user.role === 'GERENTE' && (
                <Select 
                  className="bg-slate-50 border-none min-w-[280px] font-black text-slate-700"
                  options={[{value: 'ALL', label: '📊 VISTA GLOBAL CONSOLIDADA'}, ...SEDES.map(s => ({value: s.id, label: `📍 SEDE: ${s.name.toUpperCase()}`}))]}
                  value={filterSede}
                  onChange={e => setFilterSede(e.target.value as any)}
                />
              )}
              <Button variant="ghost" onClick={loadData} className={isLoading ? 'animate-spin' : ''}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2.5" strokeLinecap="round"/></svg>
              </Button>
           </div>
           {isLoading && <span className="text-[10px] font-black text-indigo-500 uppercase tracking-widest animate-pulse">Sincronizando con Excel...</span>}
        </div>

        {/* GRÁFICOS GERENCIALES (SECCIÓN NUEVA) */}
        {user.role === 'GERENTE' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

             {/* GRÁFICO 1: DISTRIBUCIÓN POR SEDE */}
             <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8 flex items-center gap-3">
                  <span className="w-2 h-6 bg-indigo-600 rounded-full"></span>
                  Inversión por Punto de Venta
                </h3>
                <div className="space-y-6">
                   {stats.sedeData.map(s => (
                     <div key={s.name} className="space-y-2">
                        <div className="flex justify-between items-end">
                           <span className="text-[10px] font-black text-slate-400 uppercase">{s.name}</span>
                           <span className="text-xs font-black text-slate-800">${Math.round(s.value).toLocaleString()}</span>
                        </div>
                        <div className="h-4 w-full bg-slate-50 rounded-full overflow-hidden border border-slate-100 relative">
                           <div 
                             className="h-full bg-indigo-500 rounded-full transition-all duration-1000 ease-out"
                             style={{ width: stats.totalCost > 0 ? `${(s.value / stats.totalCost) * 100}%` : '0%' }}
                           ></div>
                           <div className="absolute inset-0 flex items-center justify-end pr-2">
                              <span className="text-[8px] font-black text-slate-400">
                                {stats.totalCost > 0 ? ((s.value / stats.totalCost) * 100).toFixed(0) : 0}%
                              </span>
                           </div>
                        </div>
                     </div>
                   ))}
                </div>
             </div>

             {/* GRÁFICO 2: TOP CATEGORÍAS POR VALOR */}
             <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest mb-8 flex items-center gap-3">
                  <span className="w-2 h-6 bg-emerald-500 rounded-full"></span>
                  Top Líneas de Inventario
                </h3>
                <div className="space-y-6">
                   {stats.categoryData.slice(0, 5).map(c => (
                     <div key={c.name} className="flex items-center gap-4">
                        <div className="w-24 text-[9px] font-black text-slate-400 uppercase truncate">{c.name}</div>
                        <div className="flex-1 h-3 bg-slate-50 rounded-full overflow-hidden">
                           <div 
                             className="h-full bg-emerald-500 rounded-full transition-all duration-1000 delay-300"
                             style={{ width: stats.totalCost > 0 ? `${(c.value / stats.totalCost) * 100}%` : '0%' }}
                           ></div>
                        </div>
                        <div className="w-20 text-right text-[10px] font-black text-slate-600">
                           ${Math.round(c.value / 1000)}k
                        </div>
                     </div>
                   ))}
                   {stats.categoryData.length === 0 && (
                     <p className="text-center py-10 text-slate-300 italic text-xs">Carga productos en el Maestro para ver estadísticas</p>
                   )}
                </div>
             </div>

          </div>
        )}

        {/* TARJETAS DE KPIs RESUMEN */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          <div className="bg-indigo-600 p-8 rounded-[3rem] shadow-xl shadow-indigo-100 text-white group hover:scale-[1.02] transition-transform">
            <p className="text-[10px] font-black text-indigo-200 uppercase tracking-widest">Inversión Actual</p>
            <h2 className="text-4xl font-black mt-2 tracking-tighter">${Math.round(stats.totalCost).toLocaleString()}</h2>
            <div className="mt-6 flex items-center gap-2">
              <span className="bg-white/20 text-[10px] font-black px-3 py-1.5 rounded-xl uppercase tracking-widest">Patrimonio en Bodega</span>
            </div>
          </div>

          <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 group hover:scale-[1.02] transition-transform">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Proyección de Ventas</p>
            <h2 className="text-4xl font-black text-slate-800 mt-2 tracking-tighter">${Math.round(stats.totalSale).toLocaleString()}</h2>
            <div className="mt-6 flex items-center gap-2">
              <span className="bg-emerald-50 text-emerald-600 text-[10px] font-black px-3 py-1.5 rounded-xl uppercase tracking-widest">Utilidad: ${Math.round(stats.totalSale - stats.totalCost).toLocaleString()}</span>
            </div>
          </div>

          <div className="bg-slate-900 p-8 rounded-[3rem] shadow-xl text-white group hover:scale-[1.02] transition-transform">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Rentabilidad Estimada</p>
            <h2 className="text-4xl font-black mt-2 tracking-tighter">
              {stats.totalSale > 0 ? (((stats.totalSale - stats.totalCost)/stats.totalSale)*100).toFixed(1) : 0}%
            </h2>
            <div className="mt-6 flex items-center gap-2">
              <span className="bg-indigo-500 text-[10px] font-black px-3 py-1.5 rounded-xl uppercase tracking-widest">Margen sobre Venta</span>
            </div>
          </div>
        </div>

        {/* TABLA DE KARDEX */}
        <div className="bg-white rounded-[3.5rem] shadow-sm border border-slate-100 overflow-hidden">
          <div className="px-10 py-8 border-b border-slate-50 flex justify-between items-center">
            <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Inventario Real Time</h3>
            <button onClick={() => setIsMovModalOpen(true)} className="bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest px-8 py-4 rounded-2xl hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-100">
              + Registrar Operación
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-10 py-6">Referencia</th>
                  <th className="px-10 py-6">Detalle</th>
                  <th className="px-10 py-6 text-center">Stock</th>
                  {user.role === 'GERENTE' && <th className="px-10 py-6">Inversión</th>}
                  {user.role === 'GERENTE' && <th className="px-10 py-6 text-right">Rentabilidad</th>}
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-10 py-6 font-black text-indigo-600 text-sm tracking-tighter uppercase">{s.Referencia}</td>
                    <td className="px-10 py-6">
                      <div className="text-[11px] font-bold text-slate-700">{s.Nombre}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase mt-1 italic">{s.Tipo}</div>
                    </td>
                    <td className="px-10 py-6 text-center">
                      <div className={`inline-block px-4 py-1.5 rounded-xl font-black text-xs ${s.Stock_Actual < s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} unds
                      </div>
                    </td>
                    {user.role === 'GERENTE' && (
                      <td className="px-10 py-6 text-xs font-bold text-slate-600">
                        ${Math.round(s.Costo * s.Stock_Actual).toLocaleString()}
                      </td>
                    )}
                    {user.role === 'GERENTE' && (
                      <td className="px-10 py-6 text-right">
                        <span className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg border border-indigo-100">
                          {s.Precio_Venta > 0 ? (((s.Precio_Venta - s.Costo)/s.Precio_Venta)*100).toFixed(0) : 0}% Margen
                        </span>
                      </td>
                    )}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </main>

      {/* MODAL MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 Operación de Inventario">
        <div className="space-y-6">
          <Input label="Referencia de la Prenda" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="YEL-001" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Acción" options={[{value:'SALIDA', label:'Venta'}, {value:'ENTRADA', label:'Entrada'}, {value:'TRASLADO', label:'Traslado'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="Sede Destino" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Button fullWidth onClick={registerMovement} disabled={isSubmitting || !movForm.reference} className="py-5 font-black uppercase tracking-widest">
            {isSubmitting ? 'Sincronizando...' : 'Confirmar Registro'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

export type SedeId = 'taller' | 'country' | 'plaza_sol' | 'portal_prado' | 'centro';
export type UserRole = 'OPERADOR' | 'GERENTE';
export type MovementType = 'ENTRADA' | 'SALIDA' | 'TRASLADO' | 'AJUSTE';

export interface Sede {
  id: SedeId;
  name: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

export interface MaestroProducto {
  Referencia: string;
  Nombre: string;
  Tipo: string;
  Costo: number;
  Precio_Venta: number;
  Stock_Minimo: number;
}

// Interfaz actualizada según la captura de pantalla del usuario
export interface LogMovimiento {
  ID_Mov: string;
  Timestamp: string;
  Usuario: string;
  Sede_Origen: string; // Columna "Sede_Origen"
  Sede_Destino: string; // Columna "Sede_Destino"
  Referencia: string;   // Columna "Referencia"
  Cantidad: number;     // Columna "Cantidad"
  Movimiento: string;   // Columna "Movimiento" (ej: "Entrada (Compra)")
}

export interface Movement {
  id: string;
  timestamp: string;
  userId: string;
  username: string;
  sedeId: SedeId;
  reference: string;
  type: string;
  movementType: MovementType;
  quantity: number;
  cost: number;
  salePrice: number;
  margin: number;
  notes?: string;
}

export interface ProductStock extends MaestroProducto {
  Stock_Actual: number;
  SedeId: SedeId;
}

export interface User {
  id: string;
  username: string;
  password?: string;
  sedeId: SedeId;
  role: UserRole;
  name: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
  onLogout: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  const parseSheetNumber = (val: any): number => {
    if (typeof val === 'number') return val;
    if (!val) return 0;
    const cleaned = String(val).replace(/[^0-9,.-]/g, '').replace(',', '.');
    return parseFloat(cleaned) || 0;
  };

  const normalize = (str: string) => String(str || '').trim().toLowerCase();

  // Función para encontrar el ID de sede basado en el nombre del Excel (ej: "Plaza del Sol" -> "plaza_sol")
  const findSedeId = (name: string): SedeId => {
    const norm = normalize(name);
    if (!norm || norm === '-') return '' as SedeId;
    const found = SEDES.find(s => normalize(s.name).includes(norm) || normalize(s.id) === norm);
    return (found ? found.id : norm) as SedeId;
  };

  const loadData = async () => {
    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setIsLoading(false);
      return;
    }
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error cargando datos:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // RECONCILIACIÓN SEGÚN CAPTURA DE PANTALLA
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Inicializar Maestro
    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Costo: parseSheetNumber(p.Costo),
          Precio_Venta: parseSheetNumber(p.Precio_Venta),
          Stock_Minimo: parseSheetNumber(p.Stock_Minimo),
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    // 2. Procesar Logs (Interpretando Sede_Origen, Sede_Destino y Movimiento)
    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      const sedeOrigenId = findSedeId(log.Sede_Origen);
      const sedeDestinoId = findSedeId(log.Sede_Destino);
      const tipo = normalize(log.Movimiento);
      const cantidad = parseSheetNumber(log.Cantidad);

      // Si es un traslado
      if (tipo.includes('traslado')) {
        const keyOrigen = `${normRef}_${sedeOrigenId}`;
        const keyDestino = `${normRef}_${sedeDestinoId}`;
        if (stockMap[keyOrigen]) stockMap[keyOrigen].Stock_Actual -= cantidad;
        if (stockMap[keyDestino]) stockMap[keyDestino].Stock_Actual += cantidad;
      } 
      // Si es Entrada o Salida (en tu Excel las Salidas ya son negativas, así que SUMAMOS)
      else {
        const key = `${normRef}_${sedeOrigenId}`;
        if (stockMap[key]) {
          stockMap[key].Stock_Actual += cantidad; 
        }
      }
    });

    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || s.SedeId === filterSede
    );
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);

    const categoryData = PRODUCT_CATEGORIES.map(cat => {
      const items = allStockData.filter(s => s.Tipo === cat);
      const value = items.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: cat, value };
    }).filter(c => c.value > 0).sort((a,b) => b.value - a.value);

    const sedeData = SEDES.map(sede => {
      const items = allStockData.filter(s => s.SedeId === sede.id);
      const value = items.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: sede.name, value };
    });

    return { totalCost, totalSale, categoryData, sedeData };
  }, [allStockData]);

  const handleQRScan = (ref: string) => {
    setIsQRVisible(false);
    setMovForm({ ...movForm, reference: ref });
    setIsMovModalOpen(true);
  };

  const registerMovement = async () => {
    setIsSubmitting(true);
    try {
      // Ajustar acción para enviar nombres legibles a la hoja
      const movementLabel = movForm.type === 'SALIDA' ? 'Salida (Venta)' : 
                           movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado';

      const rawQuantity = (movForm.type === 'SALIDA') ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity);

      await fetch(GAS_WEB_APP_URL, {
        method: 'POST',
        mode: 'no-cors',
        body: JSON.stringify({
          action: 'REGISTER_MOVEMENT',
          username: user.name,
          sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId, // Enviar nombre para Sede_Origen
          reference: movForm.reference,
          quantity: rawQuantity,
          movementType: movementLabel, // Enviar etiqueta legible
          destinationSedeId: SEDES.find(s => s.id === movForm.destSede)?.name || '' // Nombre para Sede_Destino
        })
      });
      setIsMovModalOpen(false);
      setTimeout(loadData, 1000);
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 font-sans">
      {isQRVisible && <QRScanner onScan={handleQRScan} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40 shadow-sm">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl text-white shadow-lg shadow-indigo-200">
