import React, { useState, useEffect } from 'react';
import { AuthState, SedeId, User, UserRole } from './types';
import { STORAGE_KEYS, GAS_WEB_APP_URL } from './constants';
import { Input, Button } from './components/UI';
import { Dashboard } from './components/Dashboard';

const App: React.FC = () => {
  const [authState, setAuthState] = useState<AuthState>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.AUTH);
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AUTH, JSON.stringify(authState));
  }, [authState]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setError('Error de configuración: URL de Google Sheets no válida.');
      setIsLoading(false);
      return;
    }

    try {
      // 1. Obtener todos los datos (incluyendo usuarios) de Sheets
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      if (!response.ok) throw new Error("No se pudo conectar con el servidor de Google Sheets.");

      const data = await response.json();
      const usersTable = data.usuarios || [];

      if (usersTable.length === 0) {
        throw new Error("La tabla de usuarios en Google Sheets está vacía.");
      }

      // Helper para buscar valores en objetos con llaves que pueden variar (Case Insensitive)
      const getValue = (obj: any, keyName: string) => {
        const foundKey = Object.keys(obj).find(k => k.trim().toLowerCase() === keyName.toLowerCase());
        return foundKey ? obj[foundKey] : null;
      };

      // 2. Validar credenciales
      const foundUser = usersTable.find((u: any) => {
        const emailSheet = String(getValue(u, 'Correo') || '').trim().toLowerCase();
        const passSheet = String(getValue(u, 'Contraseña') || getValue(u, 'Contrasena') || '').trim();

        return emailSheet === loginForm.email.trim().toLowerCase() && 
               passSheet === loginForm.password.trim();
      });

      if (!foundUser) {
        throw new Error("Correo o contraseña incorrectos.");
      }

      const userData: User = {
        id: String(getValue(foundUser, 'Correo')),
        username: String(getValue(foundUser, 'Nombre')),
        sedeId: String(getValue(foundUser, 'Sede')).toLowerCase() as SedeId,
        role: String(getValue(foundUser, 'Perfil')).toUpperCase() as UserRole,
        name: String(getValue(foundUser, 'Nombre'))
      };

      setAuthState({ user: userData, isAuthenticated: true });
    } catch (err: any) {
      console.error("Login Error:", err);
      setError(err.message || 'Error de conexión con la base de datos.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setAuthState({ user: null, isAuthenticated: false });
  };

  if (authState.isAuthenticated && authState.user) {
    return <Dashboard user={authState.user} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-3xl shadow-xl shadow-slate-200 border border-slate-100 overflow-hidden">
        <div className="bg-indigo-600 p-8 text-white text-center">
          <div className="bg-white/20 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-4">
             <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"></path></svg>
          </div>
          <h2 className="text-2xl font-bold uppercase tracking-tighter">Yeilu Store</h2>
          <p className="text-indigo-100 mt-1 opacity-80 font-medium tracking-wide text-xs uppercase">Gestión de Inventario v2.0</p>
        </div>

        <form onSubmit={handleLogin} className="p-8 space-y-5">
          {error && (
            <div className="bg-rose-50 border border-rose-100 text-rose-600 text-[11px] font-bold p-3 rounded-xl flex items-center gap-2 animate-in slide-in-from-top-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z" clipRule="evenodd"></path></svg>
              {error}
            </div>
          )}

          <div className="space-y-4">
            <Input 
              label="Correo Electrónico" 
              type="email"
              placeholder="ejemplo@yeilu.com" 
              value={loginForm.email}
              onChange={e => setLoginForm(prev => ({ ...prev, email: e.target.value }))}
              required
            />
            <Input 
              label="Contraseña" 
              type="password" 
              placeholder="••••••••" 
              value={loginForm.password}
              onChange={e => setLoginForm(prev => ({ ...prev, password: e.target.value }))}
              required
            />
          </div>

          <Button type="submit" fullWidth disabled={isLoading} className="mt-4 py-3 text-sm font-black uppercase tracking-widest shadow-lg shadow-indigo-100">
            {isLoading ? (
              <span className="flex items-center gap-2">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Verificando...
              </span>
            ) : 'Entrar al Sistema'}
          </Button>

          <div className="pt-6 border-t border-slate-100 text-center">
            <p className="text-[9px] text-slate-400 uppercase tracking-widest font-black leading-relaxed">
              Verifica que tus encabezados en Excel sean:<br/>
              "Nombre", "Correo", "Contraseña", "Perfil", "Sede"
            </p>
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

const SPREADSHEET_ID = '1eJAuYVCudO_2aDYwzzegL1yaOe4HL8uVmkfzhBa-USo';

function doPost(e) {
  const data = JSON.parse(e.postData.contents);
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  if (data.action === 'REGISTER_PRODUCT') {
    const sheet = ss.getSheetByName('Maestro_Productos');
    sheet.appendRow([data.reference, data.name, data.type, data.cost, data.salePrice, data.minStock]);
    return response({ status: 'success' });
  }

  if (data.action === 'REGISTER_MOVEMENT') {
    const sheet = ss.getSheetByName('Log_Movimientos');
    sheet.appendRow([
      Utilities.getUuid(),
      new Date().toISOString(),
      data.username,
      data.sedeId, // Sede Origen
      data.destinationSedeId || '-', // Sede Destino
      data.reference,
      data.quantity,
      data.movementType
    ]);
    return response({ status: 'success' });
  }
}

function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.openById(SPREADSHEET_ID);

  if (action === 'GET_ALL') {
    const maestro = getSheetData(ss, 'Maestro_Productos');
    const logs = getSheetData(ss, 'Log_Movimientos');
    const usuarios = getSheetData(ss, 'Usuarios');
    return response({ maestro, logs, usuarios });
  }
}

function getSheetData(ss, name) {
  const sheet = ss.getSheetByName(name);
  if (!sheet) return [];
  const data = sheet.getDataRange().getValues();
  if (data.length < 1) return [];
  const headers = data.shift();
  return data.map(row => {
    let obj = {};
    headers.forEach((h, i) => {
      if (h) obj[h.toString().trim()] = row[i];
    });
    return obj;
  });
}

function response(obj) {
  return ContentService.createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface DashboardProps {
  user: User;
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  const normalize = (str: string) => String(str || '').trim().toLowerCase();

  // Mejora: Limpia nombres de sedes para que "1. Taller" coincida con "Taller"
  const cleanSedeName = (name: string) => {
    return normalize(name).replace(/^[0-9].\s*/, '');
  };

  const findSedeId = (name: string): SedeId => {
    const cleanInput = cleanSedeName(name);
    if (!cleanInput || cleanInput === '-') return '' as SedeId;
    const found = SEDES.find(s => cleanSedeName(s.name) === cleanInput || normalize(s.id) === cleanInput);
    return (found ? found.id : cleanInput) as SedeId;
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error sincronizando:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Crear base desde el Maestro (Si el maestro está vacío, no habrá inversión que calcular)
    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Costo: Number(p.Costo) || 0,
          Precio_Venta: Number(p.Precio_Venta) || 0,
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    // 2. Aplicar movimientos del Excel
    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      const sedeOrigenId = findSedeId(log.Sede_Origen);
      const sedeDestinoId = findSedeId(log.Sede_Destino);
      const tipo = normalize(log.Movimiento);
      const cantidad = Number(log.Cantidad) || 0;

      if (tipo.includes('traslado')) {
        const keyOri = `${normRef}_${sedeOrigenId}`;
        const keyDes = `${normRef}_${sedeDestinoId}`;
        if (stockMap[keyOri]) stockMap[keyOri].Stock_Actual -= Math.abs(cantidad);
        if (stockMap[keyDes]) stockMap[keyDes].Stock_Actual += Math.abs(cantidad);
      } else {
        const key = `${normRef}_${sedeOrigenId}`;
        if (stockMap[key]) stockMap[key].Stock_Actual += cantidad; 
      }
    });

    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || s.SedeId === filterSede
    );
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);

    const sedeStats = SEDES.map(sede => {
      const val = allStockData.filter(s => s.SedeId === sede.id)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: sede.name, value: val };
    });

    const categoryStats = PRODUCT_CATEGORIES.map(cat => {
      const val = allStockData.filter(s => s.Tipo === cat)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: cat, value: val };
    }).filter(c => c.value > 0).sort((a,b) => b.value - a.value);

    return { totalCost, totalSale, sedeStats, categoryStats };
  }, [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu Analytics</h1>
        </div>
        <div className="flex gap-2">
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold">Cerrar Sesión</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-6">

        {/* CONTROL DE VISTA */}
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-100 flex justify-between items-center">
          {user.role === 'GERENTE' && (
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 VISTA GLOBAL (TODAS LAS SEDES)'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
              className="max-w-xs font-bold text-xs"
            />
          )}
          <Button variant="ghost" onClick={loadData} className={isLoading ? 'animate-spin' : ''}>
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
          </Button>
        </div>

        {/* KPIs PRINCIPALES */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-indigo-600 p-6 rounded-[2rem] text-white shadow-lg shadow-indigo-100">
            <p className="text-[10px] font-black uppercase tracking-widest opacity-70">Inversión en Bodega</p>
            <h2 className="text-3xl font-black mt-1">${Math.round(stats.totalCost).toLocaleString()}</h2>
            {stats.totalCost === 0 && !isLoading && <p className="text-[9px] mt-2 bg-white/20 p-2 rounded-lg font-bold">⚠️ Revisa el costo en Maestro_Productos</p>}
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-slate-100">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Venta Estimada</p>
            <h2 className="text-3xl font-black text-slate-800 mt-1">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>
          <div className="bg-slate-900 p-6 rounded-[2rem] text-white">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Margen de Utilidad</p>
            <h2 className="text-3xl font-black mt-1">{stats.totalSale > 0 ? (((stats.totalSale - stats.totalCost)/stats.totalSale)*100).toFixed(1) : 0}%</h2>
          </div>
        </div>

        {/* GRÁFICOS GERENCIALES */}
        {user.role === 'GERENTE' && (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-indigo-500 rounded-full"></span> Inversión por Sede
              </h3>
              <div className="space-y-4">
                {stats.sedeStats.map(s => (
                  <div key={s.name}>
                    <div className="flex justify-between text-[10px] font-bold mb-1 uppercase text-slate-500">
                      <span>{s.name}</span>
                      <span className="text-slate-800">${Math.round(s.value).toLocaleString()}</span>
                    </div>
                    <div className="h-2 bg-slate-50 rounded-full overflow-hidden">
                      <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${stats.totalCost > 0 ? (s.value/stats.totalCost)*100 : 0}%` }}></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className="bg-white p-6 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h3 className="text-[11px] font-black text-slate-800 uppercase tracking-widest mb-6 flex items-center gap-2">
                <span className="w-1.5 h-4 bg-emerald-500 rounded-full"></span> Top Categorías (Valor)
              </h3>
              <div className="space-y-4">
                {stats.categoryStats.slice(0, 5).map(c => (
                  <div key={c.name} className="flex items-center gap-3">
                    <span className="w-20 text-[9px] font-black text-slate-400 uppercase truncate">{c.name}</span>
                    <div className="flex-1 h-2 bg-slate-50 rounded-full overflow-hidden">
                      <div className="h-full bg-emerald-500" style={{ width: `${(c.value/stats.totalCost)*100}%` }}></div>
                    </div>
                    <span className="text-[10px] font-bold text-slate-700">${Math.round(c.value/1000)}k</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

        {/* LISTADO DE STOCK */}
        <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
          <div className="p-6 border-b border-slate-50 flex justify-between items-center">
            <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest">Estado de Inventario</h3>
            <div className="flex gap-2">
              <button onClick={() => setIsQRVisible(true)} className="bg-slate-100 p-2 rounded-xl text-slate-600 hover:bg-slate-200 transition-colors">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
              <Button onClick={() => setIsMovModalOpen(true)} className="text-[10px] px-6 py-2">Registrar Venta/Mov</Button>
            </div>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                  <th className="px-6 py-4">Referencia</th>
                  <th className="px-6 py-4">Producto</th>
                  <th className="px-6 py-4 text-center">Stock</th>
                  <th className="px-6 py-4 text-right">Valor Inversión</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-indigo-50/20 transition-colors">
                    <td className="px-6 py-4 font-black text-indigo-600 text-xs">{s.Referencia}</td>
                    <td className="px-6 py-4">
                      <div className="text-[11px] font-bold text-slate-700">{s.Nombre || '---'}</div>
                      <div className="text-[9px] font-black text-slate-400 uppercase italic">{s.Tipo}</div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={`px-3 py-1 rounded-lg font-black text-[10px] ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right font-bold text-slate-600 text-xs">
                      ${Math.round(s.Costo * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
                {allStockData.length === 0 && !isLoading && (
                  <tr>
                    <td colSpan={4} className="py-12 text-center text-[10px] font-black text-slate-300 uppercase tracking-widest italic">
                      No hay productos vinculados. Asegúrate que las referencias en 'Maestro_Productos' existan.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📝 Registro de Operación">
        <div className="space-y-4">
          <Input label="Referencia (SKU)" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="YEL-001" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Movimiento" options={[{value:'SALIDA', label:'Venta (-)'}, {value:'ENTRADA', label:'Carga (+)'}, {value:'TRASLADO', label:'Traslado'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="Enviar a Sede" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Button fullWidth onClick={async () => {
            setIsSubmitting(true);
            try {
              const label = movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado';
              const qty = movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity);
              await fetch(GAS_WEB_APP_URL, {
                method: 'POST', mode: 'no-cors',
                body: JSON.stringify({
                  action: 'REGISTER_MOVEMENT',
                  username: user.name,
                  sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
                  reference: movForm.reference,
                  quantity: qty,
                  movementType: label,
                  destinationSedeId: SEDES.find(s => s.id === movForm.destSede)?.name || ''
                })
              });
              setIsMovModalOpen(false);
              setTimeout(loadData, 800);
            } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
          }} disabled={isSubmitting || !movForm.reference}>
            {isSubmitting ? 'Guardando...' : 'Confirmar Registro'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { AuthState, SedeId, User, UserRole } from './types';
import { STORAGE_KEYS, GAS_WEB_APP_URL } from './constants';
import { Input, Button } from './components/UI';
import { Dashboard } from './components/Dashboard';

const App: React.FC = () => {
  const [authState, setAuthState] = useState<AuthState>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.AUTH);
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AUTH, JSON.stringify(authState));
  }, [authState]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setError('Configuración incompleta: URL de Google Sheets no válida.');
      setIsLoading(false);
      return;
    }

    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      if (!response.ok) throw new Error("Error de conexión con Google Sheets.");

      const data = await response.json();
      const usersTable = data.usuarios || [];

      if (usersTable.length === 0) {
        throw new Error("No se encontraron usuarios en la pestaña 'Usuarios' de tu Excel.");
      }

      // Helper ultra-flexible para encontrar valores por múltiples nombres de columna
      const getFlexibleValue = (obj: any, aliases: string[]) => {
        const keys = Object.keys(obj);
        for (const alias of aliases) {
          const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
          if (foundKey) return obj[foundKey];
        }
        return null;
      };

      // 2. Buscar usuario con lógica flexible
      const foundUser = usersTable.find((u: any) => {
        const emailInSheet = String(getFlexibleValue(u, ['Correo', 'Email', 'Usuario', 'ID']) || '').trim().toLowerCase();
        const passInSheet = String(getFlexibleValue(u, ['Contraseña', 'Contrasena', 'Password', 'Clave', 'Pass']) || '').trim();

        return emailInSheet === loginForm.email.trim().toLowerCase() && 
               passInSheet === loginForm.password.trim();
      });

      if (!foundUser) {
        throw new Error("Correo o contraseña incorrectos. Revisa tu Excel.");
      }

      // 3. Mapear datos del usuario
      const userData: User = {
        id: String(getFlexibleValue(foundUser, ['Correo', 'Email', 'ID']) || 'unknown'),
        username: String(getFlexibleValue(foundUser, ['Nombre', 'Name', 'Usuario']) || 'Usuario'),
        sedeId: String(getFlexibleValue(foundUser, ['Sede', 'Tienda', 'Local']) || '').toLowerCase().replace(/^[0-9].\s*/, '') as SedeId,
        role: String(getFlexibleValue(foundUser, ['Perfil', 'Rol', 'Role']) || 'OPERADOR').toUpperCase() as UserRole,
        name: String(getFlexibleValue(foundUser, ['Nombre', 'Name']) || 'Usuario')
      };

      setAuthState({ user: userData, isAuthenticated: true });
    } catch (err: any) {
      console.error("Login Error:", err);
      setError(err.message || 'Error inesperado al intentar entrar.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setAuthState({ user: null, isAuthenticated: false });
  };

  if (authState.isAuthenticated && authState.user) {
    return <Dashboard user={authState.user} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border border-slate-100 overflow-hidden">
        <div className="bg-indigo-600 p-10 text-white text-center">
          <div className="bg-white/20 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 backdrop-blur-md">
             <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
          </div>
          <h2 className="text-3xl font-black uppercase tracking-tighter">Yeilu Store</h2>
          <p className="text-indigo-100 mt-2 font-bold tracking-widest text-[10px] uppercase opacity-80">Inventory Intelligence v2.1</p>
        </div>

        <form onSubmit={handleLogin} className="p-10 space-y-6">
          {error && (
            <div className="bg-rose-50 border border-rose-100 text-rose-600 text-[11px] font-black p-4 rounded-2xl flex items-center gap-3 animate-bounce">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"></path></svg>
              {error}
            </div>
          )}

          <div className="space-y-4">
            <Input 
              label="Correo o Usuario" 
              type="text"
              placeholder="tu@correo.com" 
              value={loginForm.email}
              onChange={e => setLoginForm(prev => ({ ...prev, email: e.target.value }))}
              required
              className="rounded-xl py-3"
            />
            <Input 
              label="Contraseña" 
              type="password" 
              placeholder="••••••••" 
              value={loginForm.password}
              onChange={e => setLoginForm(prev => ({ ...prev, password: e.target.value }))}
              required
              className="rounded-xl py-3"
            />
          </div>

          <Button type="submit" fullWidth disabled={isLoading} className="py-4 text-[11px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 rounded-2xl">
            {isLoading ? (
              <span className="flex items-center gap-3">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Sincronizando...
              </span>
            ) : 'Iniciar Sesión'}
          </Button>

          <div className="pt-8 border-t border-slate-50 text-center">
            <p className="text-[9px] text-slate-400 uppercase tracking-[0.2em] font-black leading-relaxed">
              Sistema vinculado a Google Sheets<br/>
              Pestaña: "Usuarios"
            </p>
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  const normalize = (str: string) => String(str || '').trim().toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, ""); // Quita tildes

  const cleanSedeName = (name: string) => {
    return normalize(name).replace(/^[0-9]\.\s*/, ''); // Quita el "1. " o "2. "
  };

  const findSedeId = (name: string): SedeId => {
    const cleanInput = cleanSedeName(name);
    if (!cleanInput || cleanInput === '-') return '' as SedeId;
    const found = SEDES.find(s => cleanSedeName(s.name) === cleanInput || normalize(s.id) === cleanInput);
    return (found ? found.id : cleanInput) as SedeId;
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(data.logs || []);
      setMaestro(data.maestro || []);
    } catch (error) {
      console.error("Error sincronizando:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Inicializar con datos del Maestro
    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Costo: Number(p.Costo) || 0,
          Precio_Venta: Number(p.Precio_Venta) || 0,
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    // 2. Procesar Movimientos (Crucial para que coincida con Sheets)
    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      const sedeOriId = findSedeId(log.Sede_Origen);
      const sedeDesId = findSedeId(log.Sede_Destino);
      const cant = Number(log.Cantidad) || 0;
      const mov = normalize(log.Movimiento);

      // Si el producto NO está en el maestro, lo creamos dinámicamente para no perder el dato
      const ensureEntry = (ref: string, sId: SedeId) => {
        const k = `${ref}_${sId}`;
        if (!stockMap[k]) {
          stockMap[k] = {
            Referencia: log.Referencia, // Usamos la original para visualización
            Nombre: '⚠️ NO EN MAESTRO',
            Tipo: 'Sin Categoría',
            Costo: 0,
            Precio_Venta: 0,
            Stock_Minimo: 0,
            Stock_Actual: 0,
            SedeId: sId
          };
        }
        return k;
      };

      if (mov.includes('traslado')) {
        const kOri = ensureEntry(normRef, sedeOriId);
        const kDes = ensureEntry(normRef, sedeDesId);
        if (stockMap[kOri]) stockMap[kOri].Stock_Actual -= Math.abs(cant);
        if (stockMap[kDes]) stockMap[kDes].Stock_Actual += Math.abs(cant);
      } else {
        const k = ensureEntry(normRef, sedeOriId);
        if (stockMap[k]) stockMap[k].Stock_Actual += cant;
      }
    });

    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || s.SedeId === filterSede
    );
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);

    const sedeStats = SEDES.map(sede => {
      const val = allStockData.filter(s => s.SedeId === sede.id)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: sede.name, value: val };
    });

    const categoryStats = PRODUCT_CATEGORIES.map(cat => {
      const val = allStockData.filter(s => s.Tipo === cat)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: cat, value: val };
    }).filter(c => c.value !== 0).sort((a,b) => b.value - a.value);

    return { totalCost, totalSale, sedeStats, categoryStats };
  }, [allStockData]);

  return (
