              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-indigo-50/30 transition-colors group">
                    <td className="px-8 py-5 font-black text-indigo-600 text-xs">
                       <span className="bg-indigo-50 px-2 py-1 rounded text-[10px]">{s.Referencia}</span>
                    </td>
                    <td className="px-8 py-5">
                      <div className={`text-[11px] font-black uppercase ${s.Nombre.includes('⚠️') ? 'text-amber-600' : 'text-slate-700'}`}>{s.Nombre}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase tracking-tight">{s.Tipo}</div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] shadow-sm ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-500 text-white' : 'bg-emerald-500 text-white'}`}>
                        {s.Stock_Actual} UND
                      </span>
