            <Select label="SEDE DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} className="font-bold" />
          )}
          <Button fullWidth onClick={async () => {
            setIsSubmitting(true);
            try {
              const label = movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado';
              const qty = movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity);
              await fetch(GAS_WEB_APP_URL, {
                method: 'POST', mode: 'no-cors',
                body: JSON.stringify({
                  action: 'REGISTER_MOVEMENT',
                  username: user.name,
                  sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
                  reference: movForm.reference,
                  quantity: qty,
                  movementType: label,
                  destinationSedeId: SEDES.find(s => s.id === movForm.destSede)?.name || ''
                })
              });
              setIsMovModalOpen(false);
              setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId });
              setTimeout(loadData, 1000);
            } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
          }} disabled={isSubmitting || !movForm.reference} className="py-4 text-xs font-black">
            {isSubmitting ? 'GUARDANDO EN GOOGLE...' : 'CONFIRMAR Y SINCRONIZAR'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, GAS_WEB_APP_URL } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  // Normalización segura: garantiza que siempre devuelva un string
  const normalize = (str: any) => String(str || '').trim().toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "");

  const cleanSedeName = (name: string) => {
    return normalize(name).replace(/^[0-9]\.\s*/, '');
  };

  const findSedeId = (name: string): SedeId => {
    const cleanInput = cleanSedeName(name);
    if (!cleanInput || cleanInput === '-') return '' as SedeId;
    const found = SEDES.find(s => cleanSedeName(s.name) === cleanInput || normalize(s.id) === cleanInput);
    return (found ? found.id : cleanInput) as SedeId;
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      const data = await response.json();
      setLogs(Array.isArray(data.logs) ? data.logs : []);
      setMaestro(Array.isArray(data.maestro) ? data.maestro : []);
    } catch (error) {
      console.error("Error sincronizando:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Inicializar con datos del Maestro
    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      if (!normRef) return;

      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Nombre: String(p.Nombre || 'Producto sin nombre'),
          Tipo: String(p.Tipo || 'Sin Categoría'),
          Costo: Number(p.Costo) || 0,
          Precio_Venta: Number(p.Precio_Venta) || 0,
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    // 2. Procesar Movimientos
    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      if (!normRef) return;

      const sedeOriId = findSedeId(log.Sede_Origen);
      const sedeDesId = findSedeId(log.Sede_Destino);
      const cant = Number(log.Cantidad) || 0;
      const movStr = normalize(log.Movimiento);

      const ensureEntry = (ref: string, sId: SedeId) => {
        const k = `${ref}_${sId}`;
        if (!stockMap[k]) {
          stockMap[k] = {
            Referencia: String(log.Referencia || ref),
            Nombre: '⚠️ NO EN MAESTRO',
            Tipo: 'Sin Categoría',
            Costo: 0,
            Precio_Venta: 0,
            Stock_Minimo: 0,
            Stock_Actual: 0,
            SedeId: sId
          };
        }
        return k;
      };

      if (movStr.includes('traslado')) {
        const kOri = ensureEntry(normRef, sedeOriId);
        const kDes = ensureEntry(normRef, sedeDesId);
        if (stockMap[kOri]) stockMap[kOri].Stock_Actual -= Math.abs(cant);
        if (stockMap[kDes]) stockMap[kDes].Stock_Actual += Math.abs(cant);
      } else {
        const k = ensureEntry(normRef, sedeOriId);
        if (stockMap[k]) stockMap[k].Stock_Actual += cant;
      }
    });

    return Object.values(stockMap).filter(s => 
      filterSede === 'ALL' || s.SedeId === filterSede
    );
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);

    const sedeStats = SEDES.map(sede => {
      const val = allStockData.filter(s => s.SedeId === sede.id)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: sede.name, value: val };
    });

    const categoryStats = PRODUCT_CATEGORIES.map(cat => {
      const val = allStockData.filter(s => s.Tipo === cat)
                              .reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
      return { name: cat, value: val };
    }).filter(c => c.value !== 0).sort((a,b) => b.value - a.value);

    return { totalCost, totalSale, sedeStats, categoryStats };
  }, [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu Inventory</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
            <p className="text-xs font-bold text-slate-700">{user.name}</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-6">

        {/* WIDGET DE ALERTA DE DATOS */}
        {user.role === 'GERENTE' && maestro.length === 0 && !isLoading && (
          <div className="bg-amber-50 border border-amber-200 p-4 rounded-2xl flex items-center gap-4 text-amber-800">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round"/></svg>
            <p className="text-xs font-bold uppercase tracking-tight">Atención: No hay datos en 'Maestro_Productos'. Revisa tu Google Sheet.</p>
          </div>
        )}

        <div className="bg-white p-2 rounded-2xl shadow-sm border border-slate-100 flex gap-2">
          {user.role === 'GERENTE' ? (
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 TODAS LAS SEDES (GLOBAL)'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
              className="border-none font-black text-xs text-indigo-600 focus:ring-0 bg-transparent"
            />
          ) : (
            <div className="px-4 py-2 flex items-center gap-2">
              <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
              <span className="text-xs font-black text-slate-500 uppercase">Sede Actual: {SEDES.find(s => s.id === user.sedeId)?.name}</span>
            </div>
          )}
          <div className="flex-1"></div>
          <button onClick={loadData} disabled={isLoading} className={`p-2 rounded-xl hover:bg-slate-50 transition-all ${isLoading ? 'animate-spin opacity-50' : ''}`}>
            <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
          </button>
        </div>

        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-slate-900 p-6 rounded-[2rem] text-white shadow-xl">
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Valor de Inversión</p>
            <div className="flex items-baseline gap-2">
              <h2 className="text-3xl font-black mt-2">${Math.round(stats.totalCost).toLocaleString()}</h2>
              <span className="text-[10px] font-bold text-slate-500">COP</span>
            </div>
          </div>

          <div className="bg-indigo-600 p-6 rounded-[2rem] text-white shadow-xl shadow-indigo-100">
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200">Venta Proyectada</p>
            <h2 className="text-3xl font-black mt-2">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>

          <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Margen Estimado</p>
            <h2 className="text-3xl font-black mt-2 text-slate-800">{stats.totalSale > 0 ? (((stats.totalSale - stats.totalCost)/stats.totalSale)*100).toFixed(1) : 0}%</h2>
          </div>
        </div>

        {/* LISTADO DE STOCK */}
        <div className="bg-white rounded-[2.5rem] shadow-xl shadow-slate-200/50 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex flex-col md:flex-row justify-between items-center gap-4">
            <div>
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-tighter">Inventario en Tiempo Real</h3>
              <p className="text-[10px] font-bold text-slate-400 uppercase mt-1">Datos Sincronizados</p>
            </div>
            <div className="flex gap-3">
              <button onClick={() => setIsQRVisible(true)} className="bg-slate-900 text-white p-3 rounded-2xl hover:bg-indigo-600 transition-all shadow-lg shadow-slate-200">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
              <Button onClick={() => setIsMovModalOpen(true)} className="text-[11px] px-8 rounded-2xl font-black uppercase tracking-widest">Registrar Mov</Button>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-slate-50/50 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-100">
                  <th className="px-8 py-5">Referencia</th>
                  <th className="px-8 py-5">Producto / Categoría</th>
                  <th className="px-8 py-5 text-center">Stock</th>
                  <th className="px-8 py-5 text-right">Inversión</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-indigo-50/30 transition-colors group">
                    <td className="px-8 py-5 font-black text-indigo-600 text-xs">
                       <span className="bg-indigo-50 px-2 py-1 rounded text-[10px]">{s.Referencia}</span>
                    </td>
                    <td className="px-8 py-5">
                      <div className={`text-[11px] font-black uppercase ${String(s.Nombre || '').includes('⚠️') ? 'text-amber-600' : 'text-slate-700'}`}>
                        {s.Nombre || 'Sin Nombre'}
                      </div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase tracking-tight">{s.Tipo || 'Sin Categoría'}</div>
                    </td>
                    <td className="px-8 py-5 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] shadow-sm ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-500 text-white' : 'bg-emerald-500 text-white'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-slate-800 text-xs">
                      ${Math.round((s.Costo || 0) * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
                {allStockData.length === 0 && !isLoading && (
                  <tr>
                    <td colSpan={4} className="py-20 text-center text-[11px] font-black text-slate-300 uppercase tracking-[0.3em] italic">
                      Sin datos disponibles
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR OPERACIÓN">
        <div className="space-y-5">
          <Input label="REFERENCIA / SKU" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Eje: YEL-001" className="font-bold" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="TIPO DE MOV" options={[{value:'SALIDA', label:'VENTA (-)'}, {value:'ENTRADA', label:'CARGA (+)'}, {value:'TRASLADO', label:'TRASLADO'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} className="font-bold" />
            <Input label="CANTIDAD" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} className="font-bold text-center" />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="SEDE DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} className="font-bold" />
          )}
          <Button fullWidth onClick={async () => {
            setIsSubmitting(true);
            try {
              const label = movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado';
              const qty = movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity);
              await fetch(GAS_WEB_APP_URL, {
                method: 'POST', mode: 'no-cors',
                body: JSON.stringify({
                  action: 'REGISTER_MOVEMENT',
                  username: user.name,
                  sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
                  reference: movForm.reference,
                  quantity: qty,
                  movementType: label,
                  destinationSedeId: SEDES.find(s => s.id === movForm.destSede)?.name || ''
                })
              });
              setIsMovModalOpen(false);
              setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId });
              setTimeout(loadData, 1000);
            } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
          }} disabled={isSubmitting || !movForm.reference} className="py-4 text-xs font-black">
            {isSubmitting ? 'GUARDANDO...' : 'CONFIRMAR OPERACIÓN'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

