import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId });

  const normalize = (val: any) => String(val || '').trim().toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "");

  const findSedeId = (name: string): SedeId => {
    const cleanInput = normalize(name).replace(/^[0-9]\.\s*/, '');
    if (!cleanInput || cleanInput === '-') return '' as SedeId;
    const found = SEDES.find(s => normalize(s.name).replace(/^[0-9]\.\s*/, '') === cleanInput || normalize(s.id) === cleanInput);
    return (found ? found.id : cleanInput) as SedeId;
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      // Usamos el Webhook 1: Consulta Global
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      // n8n debe retornar { maestro: [], logs: [] }
      setLogs(Array.isArray(data.logs) ? data.logs : []);
      setMaestro(Array.isArray(data.maestro) ? data.maestro : []);
    } catch (error) {
      console.error("Error n8n (Consulta):", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    maestro.forEach(p => {
      const normRef = normalize(p.Referencia);
      if (!normRef) return;
      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Nombre: String(p.Nombre || 'Sin Nombre'),
          Costo: Number(p.Costo) || 0,
          Precio_Venta: Number(p.Precio_Venta) || 0,
          Stock_Actual: 0,
          SedeId: sede.id
        };
      });
    });

    logs.forEach(log => {
      const normRef = normalize(log.Referencia);
      if (!normRef) return;
      const sOri = findSedeId(log.Sede_Origen);
      const sDes = findSedeId(log.Sede_Destino);
      const cant = Number(log.Cantidad) || 0;
      const type = normalize(log.Movimiento);

      const ensure = (ref: string, sId: SedeId) => {
        const k = `${ref}_${sId}`;
        if (!stockMap[k]) {
          stockMap[k] = { Referencia: ref.toUpperCase(), Nombre: '⚠️ NO EN MAESTRO', Tipo: 'Otros', Costo: 0, Precio_Venta: 0, Stock_Minimo: 0, Stock_Actual: 0, SedeId: sId };
        }
        return k;
      };

      if (type.includes('traslado')) {
        const kO = ensure(normRef, sOri);
        const kD = ensure(normRef, sDes);
        if (stockMap[kO]) stockMap[kO].Stock_Actual -= Math.abs(cant);
        if (stockMap[kD]) stockMap[kD].Stock_Actual += Math.abs(cant);
      } else {
        const k = ensure(normRef, sOri);
        if (stockMap[k]) stockMap[k].Stock_Actual += cant;
      }
    });

    return Object.values(stockMap).filter(s => filterSede === 'ALL' || s.SedeId === filterSede);
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    const totalCost = allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0);
    const totalSale = allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0);
    return { totalCost, totalSale };
  }, [allStockData]);

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const payload = {
        action: 'REGISTER_MOVEMENT',
        username: user.name,
        sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
        reference: movForm.reference,
        quantity: movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity),
        movementType: movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado',
        destinationSedeId: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : ''
      };

      // Usamos el Webhook 2: Registro de Movimiento
      await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      setIsMovModalOpen(false);
      setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId });
      setTimeout(loadData, 1500);
    } catch (e) {
      console.error("Error n8n (Registro):", e);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg shadow-indigo-100">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu n8n Sync</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
            <p className="text-xs font-bold text-slate-700">{user.name}</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-6">

        {/* KPI CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-2xl"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual ({filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalCost).toLocaleString()}</h2>
          </div>
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-xl shadow-slate-200/50">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black text-indigo-600">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>
        </div>

        <div className="bg-white p-3 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          {user.role === 'GERENTE' && (
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
              className="border-none font-black text-xs text-indigo-600 bg-transparent"
            />
          )}
          <div className="flex-1"></div>
          <button onClick={loadData} disabled={isLoading} className={`p-3 rounded-xl hover:bg-slate-50 transition-all ${isLoading ? 'animate-spin opacity-50' : ''}`}>
            <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
          </button>
        </div>

        {/* STOCK TABLE */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/30">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Estado de Bodega</h3>
            <div className="flex gap-2">
              <button onClick={() => setIsQRVisible(true)} className="bg-white border border-slate-200 p-3 rounded-2xl shadow-sm hover:border-indigo-500 transition-all group">
                <svg className="w-6 h-6 text-slate-400 group-hover:text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round"/></svg>
              </button>
              <Button onClick={() => setIsMovModalOpen(true)} className="text-[10px] px-6 rounded-2xl font-black uppercase tracking-widest shadow-lg shadow-indigo-100">Nuevo Movimiento</Button>
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Detalle</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-8 py-6">
                       <span className="bg-slate-100 px-3 py-1.5 rounded-lg text-[11px] font-black text-slate-600 group-hover:bg-indigo-600 group-hover:text-white transition-colors">{s.Referencia}</span>
                    </td>
                    <td className="px-8 py-6">
                      <div className={`text-[11px] font-black uppercase ${String(s.Nombre).includes('⚠️') ? 'text-amber-500' : 'text-slate-800'}`}>{s.Nombre}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase tracking-tight mt-1">{s.Tipo}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">
                      ${Math.round((s.Costo || 0) * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR OPERACIÓN">
        <div className="space-y-6">
          <Input label="REFERENCIA / SKU" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Eje: YEL-001" className="font-bold py-3" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="TIPO" options={[{value:'SALIDA', label:'VENTA'}, {value:'ENTRADA', label:'CARGA'}, {value:'TRASLADO', label:'TRASLADO'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} className="font-bold py-3" />
            <Input label="CANTIDAD" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} className="font-bold text-center py-3" />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="SEDE DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} className="font-bold py-3" />
          )}
          <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting || !movForm.reference} className="py-4 text-[11px] font-black uppercase tracking-widest">
            {isSubmitting ? 'Sincronizando n8n...' : 'Confirmar Operación'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS, TYPE_UNSPECIFIED } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
