          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                Referencia: { type: Type.STRING },
                Nombre: { type: Type.STRING },
                Tipo: { type: Type.STRING },
                Costo: { type: Type.NUMBER },
                Precio_Venta: { type: Type.NUMBER },
                Stock_Minimo: { type: Type.NUMBER },
