      const cant = Number(log.Cantidad) || 0;
      const type = normalize(log.Movimiento);
      const ensure = (ref: string, sId: SedeId) => {
        const k = `${ref}_${sId}`;
        if (!stockMap[k]) stockMap[k] = { Referencia: ref.toUpperCase(), Nombre: '⚠️ NO EN MAESTRO', Tipo: 'Otros', Costo: 0, Precio_Venta: 0, Stock_Minimo: 0, Stock_Actual: 0, SedeId: sId };
        return k;
      };
      if (type.includes('traslado')) {
        const kO = ensure(normRef, sOri); const kD = ensure(normRef, sDes);
        if (stockMap[kO]) stockMap[kO].Stock_Actual -= Math.abs(cant);
        if (stockMap[kD]) stockMap[kD].Stock_Actual += Math.abs(cant);
      } else {
        const k = ensure(normRef, sOri);
        if (stockMap[k]) stockMap[k].Stock_Actual += cant;
      }
    });
