        <div className="space-y-6">
          <Input label="REFERENCIA / SKU" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Escanea o escribe" className="font-bold py-3" />
