             setIsSubmitting(true);
             try {
               await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
                 method: 'POST', headers: { 'Content-Type': 'application/json' },
                 body: JSON.stringify({
                   action: 'REGISTER_MOVEMENT',
                   username: user.name,
                   sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
                   reference: movForm.reference,
                   quantity: movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity),
                   movementType: movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado',
                   destinationSedeId: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : ''
                 })
               });
               setIsMovModalOpen(false); setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId });
               setTimeout(loadData, 1500);
             } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
          }} disabled={isSubmitting || !movForm.reference} className="py-4 text-[11px] font-black uppercase">
            {isSubmitting ? 'Sincronizando...' : 'Confirmar Operación'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

