  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => ({
    totalCost: allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
    totalSale: allStockData.reduce((acc, s) => acc + (s.Precio_Venta * s.Stock_Actual), 0)
  }), [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu n8n AI</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
            <p className="text-xs font-bold text-slate-700">{user.name}</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-6">

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión ({filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalCost).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black text-white">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select value={filterSede} onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Cargue por Voz'}
            </button>
            {user.role === 'GERENTE' && (
              <Button onClick={() => setIsMaestroModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">
                Nuevo Maestro
              </Button>
            )}
          </div>
        </div>

        {/* TABLA DE STOCK */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Existencias en Bodega</h3>
            <Button onClick={() => setIsMovModalOpen(true)} className="text-[10px] px-6 rounded-2xl font-black uppercase">Registrar Operación</Button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">
                  <th className="px-8 py-6">Ref</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Inversión</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map(s => (
                  <tr key={`${s.Referencia}-${s.SedeId}`} className="hover:bg-indigo-50/20 transition-all">
                    <td className="px-8 py-6">
                       <span className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg text-[11px] font-black">{s.Referencia}</span>
                    </td>
                    <td className="px-8 py-6">
                      <div className={`text-[11px] font-black uppercase ${String(s.Nombre).includes('⚠️') ? 'text-amber-500' : 'text-slate-800'}`}>{s.Nombre}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Tipo}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-500 text-white shadow-lg shadow-rose-100' : 'bg-emerald-500 text-white shadow-lg shadow-emerald-100'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">
                      ${Math.round((s.Costo || 0) * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL MAESTRO (PARA VOZ O MANUAL) */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 REGISTRO DE PRODUCTO MAESTRO">
        <div className="space-y-4">
          <p className="text-[10px] font-bold text-indigo-600 uppercase mb-4 bg-indigo-50 p-3 rounded-xl">
            {maestroForm.Nombre ? "✨ Datos detectados automáticamente" : "Completa los datos del nuevo producto"}
          </p>
          <Input label="REFERENCIA" value={maestroForm.Referencia} onChange={e => setMaestroForm({...maestroForm, Referencia: e.target.value.toUpperCase()})} placeholder="Eje: YEL-123" className="font-bold"/>
          <Input label="NOMBRE" value={maestroForm.Nombre} onChange={e => setMaestroForm({...maestroForm, Nombre: e.target.value})} placeholder="Eje: Blusa Seda Blanca" className="font-bold"/>
          <Select label="CATEGORÍA" options={PRODUCT_CATEGORIES.map(c => ({value:c, label:c}))} value={maestroForm.Tipo} onChange={e => setMaestroForm({...maestroForm, Tipo: e.target.value})} className="font-bold"/>
          <div className="grid grid-cols-2 gap-4">
            <Input label="COSTO ($)" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} className="font-bold"/>
            <Input label="PRECIO VENTA ($)" type="number" value={maestroForm.Precio_Venta} onChange={e => setMaestroForm({...maestroForm, Precio_Venta: Number(e.target.value)})} className="font-bold"/>
          </div>
          <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting || !maestroForm.Referencia} className="py-4 text-[11px] font-black uppercase">
            {isSubmitting ? 'Guardando en Maestro...' : 'Confirmar en Catálogo'}
          </Button>
        </div>
      </Modal>

      {/* MODAL MOVIMIENTOS */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR OPERACIÓN">
        <div className="space-y-6">
          <Input label="REFERENCIA / SKU" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Escanea o escribe" className="font-bold py-3" />
          <div className="grid grid-cols-2 gap-4">
            <Select label="TIPO" options={[{value:'SALIDA', label:'VENTA'}, {value:'ENTRADA', label:'CARGA'}, {value:'TRASLADO', label:'TRASLADO'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} className="font-bold py-3" />
            <Input label="CANTIDAD" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} className="font-bold text-center py-3" />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="SEDE DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} className="font-bold py-3" />
          )}
          <Button fullWidth onClick={async () => {
             setIsSubmitting(true);
             try {
               await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
                 method: 'POST', headers: { 'Content-Type': 'application/json' },
                 body: JSON.stringify({
                   action: 'REGISTER_MOVEMENT',
                   username: user.name,
                   sedeId: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
                   reference: movForm.reference,
                   quantity: movForm.type === 'SALIDA' ? -Math.abs(movForm.quantity) : Math.abs(movForm.quantity),
                   movementType: movForm.type === 'SALIDA' ? 'Salida (Venta)' : movForm.type === 'ENTRADA' ? 'Entrada (Carga)' : 'Traslado',
                   destinationSedeId: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : ''
                 })
               });
               setIsMovModalOpen(false); setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId });
               setTimeout(loadData, 1500);
             } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
          }} disabled={isSubmitting || !movForm.reference} className="py-4 text-[11px] font-black uppercase">
            {isSubmitting ? 'Sincronizando...' : 'Confirmar Operación'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

{
  "name": "Yeilu Store Inventory Relational",
  "description": "Multi-location inventory with QR scanning, n8n sync and Voice AI loading.",
  "requestFramePermissions": ["camera", "microphone"]
}

import { Sede } from './types';

/**
 * CONFIGURACIÓN n8n (URLs Proporcionadas)
 */
export const N8N_WEBHOOKS = {
  CONSULTA_GLOBAL: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/consulta-inventario',
  REGISTRO_MOVIMIENTO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/movimiento',
  GESTION_MAESTRO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/producto-nuevo'
};

export const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzYf1o2Q0DNm2hGPksEYP8GQ5nOhVRt48mnDp41n6igS5mdq3uezQA40BRQWvIYjQlVnA/exec';

export const SEDES: Sede[] = [
  { id: 'taller', name: '1. Taller' },
  { id: 'country', name: '2. Country' },
  { id: 'plaza_sol', name: '3. Plaza del Sol' },
  { id: 'portal_prado', name: '4. Portal del Prado' },
  { id: 'centro', name: '5. Centro' }
];

export const PRODUCT_CATEGORIES = [
  'Vestidos',
  'Blusas / Tops',
  'Pantalones / Jeans',
  'Faldas',
  'Chaquetas / Abrigos',
  'Calzado',
  'Accesorios',
  'Lencería / Intima',
  'Vestidos de Baño'
];

export const STORAGE_KEYS = {
  AUTH: 'yeilu_auth_state',
  CACHED_DATA: 'yeilu_cached_data'
};

export type SedeId = 'taller' | 'country' | 'plaza_sol' | 'portal_prado' | 'centro';
export type UserRole = 'OPERADOR' | 'GERENTE';
export type MovementType = 'ENTRADA' | 'SALIDA' | 'TRASLADO';

export interface Sede {
  id: SedeId;
  name: string;
}

export interface MaestroProducto {
  Codigo: string;       // Antes Referencia
  Descripcion: string;  // Antes Nombre
  Categoria: string;    // Antes Tipo
  Costo: number;
  Venta: number;        // Antes Precio_Venta
  Activo: string;       // "SI" o "NO"
}

export interface LogMovimiento {
  Fecha: string;
  Operador: string;
  Tipo: string;         // ENTRADA / SALIDA / TRASLADO
  Codigo: string;
  Cantidad: number;
  Bodega: string;       // Sede Origen
  Destino: string;      // Sede Destino (opcional)
  Observaciones: string;
}

export interface ProductStock extends MaestroProducto {
  Stock_Actual: number;
  SedeId: SedeId;
}

export interface User {
  id: string;
  username: string;
  sedeId: SedeId;
  role: UserRole;
  name: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [logs, setLogs] = useState<LogMovimiento[]>([]);
  const [maestro, setMaestro] = useState<MaestroProducto[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId, notes: '' });
  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const normalize = (val: any) => String(val || '').trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

  const findSedeId = (name: string): SedeId => {
    const cleanInput = normalize(name).replace(/^[0-9]\.\s*/, '');
    const found = SEDES.find(s => normalize(s.name).replace(/^[0-9]\.\s*/, '') === cleanInput || normalize(s.id) === cleanInput);
    return (found ? found.id : cleanInput) as SedeId;
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      // Flujo 1: Consulta
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      // Adaptamos la respuesta de n8n
      setMaestro(Array.isArray(data.maestro) ? data.maestro : []);
      setLogs(Array.isArray(data.logs) ? data.logs : []);
    } catch (error) {
      console.error("Error al cargar datos de n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // Lógica de Voz + Gemini
  const handleVoiceInput = async () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Tu navegador no soporta reconocimiento de voz. Usa Chrome.");
      return;
    }

    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'es-CO';
    recognition.start();
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const text = event.results[0][0].transcript;
      setIsListening(false);
      setIsLoading(true);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Analiza este dictado para crear un producto en inventario: "${text}". 
          Extrae los datos en JSON con estas claves exactas: Codigo (ej: YEL-100), Descripcion (ej: Vestido Seda), Categoria (ej: Vestidos), Costo (numero), Venta (numero). 
          Si no menciona la categoría, usa "Otros". Los números deben ser enteros sin puntos.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                Codigo: { type: Type.STRING },
                Descripcion: { type: Type.STRING },
                Categoria: { type: Type.STRING },
                Costo: { type: Type.NUMBER },
                Venta: { type: Type.NUMBER },
              },
              required: ["Codigo", "Descripcion", "Costo", "Venta"]
            }
          }
        });

        const extracted = JSON.parse(response.text);
        setMaestroForm({ ...extracted, Activo: 'SI' });
        setIsMaestroModalOpen(true);
      } catch (err) {
        alert("Gemini no pudo procesar el audio. Intenta de nuevo.");
      } finally {
        setIsLoading(false);
      }
    };

    recognition.onerror = () => setIsListening(false);
  };

  const handleRegisterMaestro = async () => {
    if (!maestroForm.Codigo || !maestroForm.Descripcion) return;
    setIsSubmitting(true);
    try {
      // Flujo 3: Producto Nuevo
      const res = await fetch(N8N_WEBHOOKS.GESTION_MAESTRO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          codigo: maestroForm.Codigo,
          descripcion: maestroForm.Descripcion,
          categoria: maestroForm.Categoria,
          precioCosto: maestroForm.Costo,
          precioVenta: maestroForm.Venta,
          activo: "SI"
        })
      });
      if (res.ok) {
        setIsMaestroModalOpen(false);
        setMaestroForm({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      // Flujo 2: Movimientos
      const payload = {
        operador: user.name,
        tipo: movForm.type,
        codigo: movForm.reference,
        cantidad: Math.abs(movForm.quantity),
        bodega: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
        destino: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : '',
        observaciones: movForm.notes || 'Registrado desde App'
      };

      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        setIsMovModalOpen(false);
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId, notes: '' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Cálculo de Stock basado en Logs (en caso de que el flujo 1 no traiga el stock final pre-calculado)
  const allStockData = useMemo(() => {
    const stockMap: Record<string, ProductStock> = {};

    // 1. Inicializar con Maestro
    maestro.forEach(p => {
      const normRef = normalize(p.Codigo);
      if (!normRef) return;
      SEDES.forEach(sede => {
        const key = `${normRef}_${sede.id}`;
        stockMap[key] = {
          ...p,
          Stock_Actual: 0,
          SedeId: sede.id,
          Stock_Minimo: 5 // Default
        };
      });
    });

    // 2. Procesar Logs para el Stock Actual por Sede
    logs.forEach(log => {
      const normRef = normalize(log.Codigo);
      const sId = findSedeId(log.Bodega);
      const type = normalize(log.Tipo);
      const cant = Number(log.Cantidad) || 0;

      const ensureKey = (ref: string, sede: SedeId) => {
        const k = `${ref}_${sede}`;
        if (!stockMap[k]) {
          stockMap[k] = { Codigo: ref.toUpperCase(), Descripcion: '⚠️ DESCONOCIDO', Categoria: 'Otros', Costo: 0, Venta: 0, Activo: 'SI', Stock_Actual: 0, SedeId: sede, Stock_Minimo: 5 };
        }
        return k;
      };

      if (type.includes('traslado')) {
        const sDestId = findSedeId(log.Destino);
        const kO = ensureKey(normRef, sId);
        const kD = ensureKey(normRef, sDestId);
        stockMap[kO].Stock_Actual -= cant;
        stockMap[kD].Stock_Actual += cant;
      } else if (type.includes('entrada')) {
        const k = ensureKey(normRef, sId);
        stockMap[k].Stock_Actual += cant;
      } else if (type.includes('salida')) {
        const k = ensureKey(normRef, sId);
        stockMap[k].Stock_Actual -= cant;
      }
    });

    return Object.values(stockMap).filter(s => filterSede === 'ALL' || s.SedeId === filterSede);
  }, [logs, maestro, filterSede]);

  const stats = useMemo(() => {
    return {
      totalCost: allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
      totalSale: allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)
    };
  }, [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && (
        <QRScanner 
          onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu n8n AI</h1>
        </div>
        <div className="flex items-center gap-4">
