import React, { useEffect, useState, useRef } from 'react';

interface QRScannerProps {
  onScan: (decodedText: string) => void;
  onClose: () => void;
}

export const QRScanner: React.FC<QRScannerProps> = ({ onScan, onClose }) => {
  const [error, setError] = useState<string | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);
  const scannerRef = useRef<any>(null);

  const startScanner = async () => {
    setIsInitializing(true);
    setError(null);

    try {
      // 1. Verificar contexto seguro (HTTPS o localhost)
      if (!window.isSecureContext) {
        throw new Error("La cámara solo está disponible en sitios seguros (HTTPS).");
      }

      // 2. Verificar disponibilidad de dispositivos
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Tu navegador no soporta el acceso a la cámara.");
      }

      const html5QrCode = new (window as any).Html5Qrcode("reader");
      scannerRef.current = html5QrCode;

      const config = { 
        fps: 10, 
        qrbox: { width: 250, height: 250 },
        aspectRatio: 1.0
      };

      await html5QrCode.start(
        { facingMode: "environment" }, 
        config, 
        (decodedText: string) => {
          onScan(decodedText);
          stopScanner();
        },
        () => {
          // Callback de error de escaneo silencioso (no es error de cámara)
        }
      );

      setIsInitializing(false);
    } catch (err: any) {
      console.error("Error QR:", err);
      setIsInitializing(false);

      const errorMsg = err?.toString() || "";
      if (errorMsg.includes("NotAllowedError") || errorMsg.includes("Permission denied")) {
        setError("Acceso Denegado: Debes permitir el uso de la cámara en la barra de direcciones del navegador (haz clic en el icono del candado o la cámara).");
      } else if (errorMsg.includes("NotFoundError")) {
        setError("No se detectó ninguna cámara en este dispositivo.");
      } else if (errorMsg.includes("NotReadableError")) {
        setError("La cámara está siendo usada por otra aplicación.");
      } else {
        setError(err.message || "Error desconocido al iniciar la cámara.");
      }
    }
  };

  const stopScanner = async () => {
    if (scannerRef.current && scannerRef.current.isScanning) {
      try {
        await scannerRef.current.stop();
        scannerRef.current = null;
      } catch (e) {
        console.error("Error stopping scanner", e);
      }
    }
  };

  useEffect(() => {
    startScanner();
    return () => {
      stopScanner();
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[60] bg-black/95 flex flex-col items-center justify-center p-4 backdrop-blur-sm">
      <div className="w-full max-w-sm bg-white rounded-[2.5rem] overflow-hidden relative shadow-2xl border border-white/10">
        <button 
          onClick={onClose} 
          className="absolute top-4 right-4 z-[70] bg-slate-900/60 hover:bg-slate-900 text-white p-3 rounded-full transition-all active:scale-95"
          aria-label="Cerrar escáner"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"></path>
          </svg>
        </button>

        <div className="relative">
          <div id="reader" className="w-full aspect-square bg-slate-900 overflow-hidden"></div>

          {isInitializing && !error && (
            <div className="absolute inset-0 flex flex-col items-center justify-center bg-slate-900 text-white">
              <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-500 rounded-full animate-spin mb-4"></div>
              <p className="text-[10px] font-black uppercase tracking-widest opacity-60">Iniciando Cámara...</p>
            </div>
          )}

          {error && (
            <div className="absolute inset-0 bg-white flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-300">
              <div className="bg-rose-100 text-rose-600 p-5 rounded-3xl mb-6">
                <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"></path>
                </svg>
              </div>
              <h4 className="text-sm font-black text-slate-900 uppercase tracking-tighter mb-3">Permiso Requerido</h4>
              <p className="text-xs text-slate-500 mb-8 leading-relaxed font-medium px-4">{error}</p>

              <div className="flex flex-col gap-3 w-full">
                <button 
                  onClick={startScanner} 
                  className="bg-indigo-600 text-white py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 active:scale-95"
                >
                  Intentar de nuevo
                </button>
                <button 
                  onClick={() => window.location.reload()} 
                  className="bg-slate-100 text-slate-600 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200 transition-all active:scale-95"
                >
                  Recargar Aplicación
                </button>
              </div>
            </div>
          )}
        </div>

        {!error && !isInitializing && (
          <div className="p-8 text-center bg-white border-t border-slate-50 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-1 bg-indigo-500 animate-progress origin-left"></div>
            <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Escáner de Referencia</h3>
            <p className="text-[9px] font-bold text-slate-400 mt-2 uppercase tracking-tight">Centra el código QR en el recuadro para detectar el producto</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId, notes: '' });
  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      // n8n a veces devuelve un array con el objeto dentro
      const source = Array.isArray(data) ? data[0] : data;

      if (source && source.productos) {
        setRawProducts(source.productos);
      } else {
        console.warn("Estructura de JSON no reconocida:", source);
        setRawProducts([]);
      }
    } catch (error) {
      console.error("Error al cargar datos de n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  // Mapeo de Sede IDs del App a las llaves del JSON de n8n
  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller',
      'country': 'country',
      'plaza_sol': 'plazaDelSol',
      'portal_prado': 'portalDelPrado',
      'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  // Lógica de Voz + Gemini
  const handleVoiceInput = async () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Tu navegador no soporta reconocimiento de voz. Usa Chrome.");
      return;
    }

    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'es-CO';
    recognition.start();
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const text = event.results[0][0].transcript;
      setIsListening(false);
      setIsLoading(true);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Analiza este dictado para crear un producto en inventario: "${text}". 
          Extrae los datos en JSON con estas claves exactas: Codigo (ej: YEL-100), Descripcion (ej: Vestido Seda), Categoria (ej: Vestidos), Costo (numero), Venta (numero). 
          Si no menciona la categoría, usa "Otros". Los números deben ser enteros sin puntos.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                Codigo: { type: Type.STRING },
                Descripcion: { type: Type.STRING },
                Categoria: { type: Type.STRING },
                Costo: { type: Type.NUMBER },
                Venta: { type: Type.NUMBER },
              },
              required: ["Codigo", "Descripcion", "Costo", "Venta"]
            }
          }
        });

        const extracted = JSON.parse(response.text);
        setMaestroForm({ ...extracted, Activo: 'SI' });
        setIsMaestroModalOpen(true);
      } catch (err) {
        alert("Gemini no pudo procesar el audio. Intenta de nuevo.");
      } finally {
        setIsLoading(false);
      }
    };

    recognition.onerror = () => setIsListening(false);
  };

  const handleRegisterMaestro = async () => {
    if (!maestroForm.Codigo || !maestroForm.Descripcion) return;
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.GESTION_MAESTRO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          codigo: maestroForm.Codigo,
          descripcion: maestroForm.Descripcion,
          categoria: maestroForm.Categoria,
          precioCosto: maestroForm.Costo,
          precioVenta: maestroForm.Venta,
          activo: "SI"
        })
      });
      if (res.ok) {
        setIsMaestroModalOpen(false);
        setMaestroForm({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const payload = {
        operador: user.name,
        tipo: movForm.type,
        codigo: movForm.reference,
        cantidad: Math.abs(movForm.quantity),
        bodega: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
        destino: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : '',
        observaciones: movForm.notes || 'Registrado desde App'
      };

      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        setIsMovModalOpen(false);
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId, notes: '' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  // Cálculo de Stock basado en el JSON pre-calculado de n8n
  const allStockData = useMemo(() => {
    const products: ProductStock[] = [];

    rawProducts.forEach(p => {
      // Mapear campos de n8n a nuestras interfaces
      const baseProd = {
        Codigo: p.referencia || 'SIN-REF',
        Descripcion: p.nombre || 'Sin nombre',
        Categoria: p.tipo || 'Otros',
        Costo: Number(p.precioCosto) || 0,
        Venta: Number(p.precioVenta) || 0,
        Activo: 'SI',
        Stock_Minimo: Number(p.stockMinimo) || 5
      };

      if (filterSede === 'ALL') {
        // En vista global, mostramos el total
        products.push({
          ...baseProd,
          Stock_Actual: p.stock?.total || 0,
          SedeId: 'taller' as SedeId // Placeholder para vista global
        });
      } else {
        // En vista por sede, buscamos la propiedad correspondiente
        const jsonKey = mapAppSedeToJsonProperty(filterSede);
        products.push({
          ...baseProd,
          Stock_Actual: p.stock ? (p.stock[jsonKey] || 0) : 0,
          SedeId: filterSede
        });
      }
    });

    return products;
  }, [rawProducts, filterSede]);

  const stats = useMemo(() => {
    return {
      totalCost: allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
      totalSale: allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)
    };
  }, [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && (
        <QRScanner 
          onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilu n8n AI</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
            <p className="text-xs font-bold text-slate-700">{user.name}</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-6">

        {/* KPI CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión ({filterSede === 'ALL' ? 'Global' : filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalCost).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group">
             <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/10 rounded-full -ml-16 -mb-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={handleVoiceInput} 
              className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Carga por Voz AI'}
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">
              Nuevo Movimiento
            </Button>
          </div>
        </div>

        {/* DATA TABLE */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Existencias de Inventario</h3>
            <button onClick={loadData} className={`p-2 hover:bg-slate-100 rounded-full transition-all ${isLoading ? 'animate-spin opacity-50' : ''}`}>
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Código</th>
                  <th className="px-8 py-6">Descripción</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all group">
                    <td className="px-8 py-6">
                       <span className="bg-slate-100 px-3 py-1.5 rounded-lg text-[11px] font-black text-slate-600 group-hover:bg-indigo-600 group-hover:text-white transition-all">{s.Codigo}</span>
                    </td>
                    <td className="px-8 py-6">
                      <div className={`text-[11px] font-black uppercase ${String(s.Descripcion).includes('⚠️') ? 'text-amber-500' : 'text-slate-800'}`}>{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">
                      ${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {allStockData.length === 0 && !isLoading && (
              <div className="py-20 text-center text-slate-300 font-black text-xs uppercase tracking-widest">No hay datos en esta sede</div>
            )}
          </div>
        </div>
      </main>

      {/* MODAL MAESTRO (PARA VOZ O MANUAL) */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 NUEVO PRODUCTO MAESTRO">
        <div className="space-y-4">
          <p className="text-[10px] font-bold text-indigo-600 uppercase mb-4 bg-indigo-50 p-3 rounded-xl border border-indigo-100">
            {maestroForm.Descripcion ? "✨ Datos procesados por AI" : "Completa los datos del producto"}
          </p>
          <Input label="CÓDIGO (Referencia)" value={maestroForm.Codigo} onChange={e => setMaestroForm({...maestroForm, Codigo: e.target.value.toUpperCase()})} placeholder="YEL-000" />
          <Input label="DESCRIPCIÓN" value={maestroForm.Descripcion} onChange={e => setMaestroForm({...maestroForm, Descripcion: e.target.value})} placeholder="Nombre del producto" />
          <Select label="CATEGORÍA" options={PRODUCT_CATEGORIES.map(c => ({value:c, label:c}))} value={maestroForm.Categoria} onChange={e => setMaestroForm({...maestroForm, Categoria: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="COSTO ($)" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} />
            <Input label="VENTA ($)" type="number" value={maestroForm.Venta} onChange={e => setMaestroForm({...maestroForm, Venta: Number(e.target.value)})} />
          </div>
          <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting || !maestroForm.Codigo} className="py-4 text-[11px] font-black uppercase">
            {isSubmitting ? 'Sincronizando...' : 'Confirmar en Maestro'}
          </Button>
        </div>
      </Modal>

      {/* MODAL MOVIMIENTOS */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
        <div className="space-y-6">
          <div className="flex gap-2">
            <Input label="CÓDIGO PRODUCTO" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Eje: YEL-100" />
            <button onClick={() => setIsQRVisible(true)} className="mt-7 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 text-indigo-600 transition-all">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Select label="TIPO MOVIMIENTO" options={[{value:'SALIDA', label:'Venta / Salida'}, {value:'ENTRADA', label:'Carga / Entrada'}, {value:'TRASLADO', label:'Traslado Inter-sede'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="CANTIDAD" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} className="text-center font-black" />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Input label="OBSERVACIONES" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="Opcional..." />
          <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting || !movForm.reference} className="py-4 text-[11px] font-black uppercase tracking-widest">
            {isSubmitting ? 'Sincronizando n8n...' : 'Registrar en Log'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, LogMovimiento, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId, notes: '' });
  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      const source = Array.isArray(data) ? data[0] : data;

      if (source && source.productos) {
        setRawProducts(source.productos);
      } else {
        console.warn("Estructura de JSON no reconocida:", source);
        setRawProducts([]);
      }
    } catch (error) {
      console.error("Error al cargar datos de n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller',
      'country': 'country',
      'plaza_sol': 'plazaDelSol',
      'portal_prado': 'portalDelPrado',
      'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleVoiceInput = async () => {
    if (!('webkitSpeechRecognition' in window)) {
      alert("Tu navegador no soporta reconocimiento de voz. Usa Chrome.");
      return;
    }

    const recognition = new (window as any).webkitSpeechRecognition();
    recognition.lang = 'es-CO';
    recognition.start();
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const text = event.results[0][0].transcript;
      setIsListening(false);
      setIsLoading(true);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Analiza este dictado para crear un producto en inventario: "${text}". 
          Extrae los datos en JSON con estas claves exactas: Codigo (ej: YEL-100), Descripcion (ej: Vestido Seda), Categoria (ej: Vestidos), Costo (numero), Venta (numero). 
          Si no menciona la categoría, usa "Otros". Los números deben ser enteros sin puntos.`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                Codigo: { type: Type.STRING },
                Descripcion: { type: Type.STRING },
                Categoria: { type: Type.STRING },
                Costo: { type: Type.NUMBER },
                Venta: { type: Type.NUMBER },
              },
              required: ["Codigo", "Descripcion", "Costo", "Venta"]
            }
          }
        });

        const extracted = JSON.parse(response.text);
        setMaestroForm({ ...extracted, Activo: 'SI' });
        setIsMaestroModalOpen(true);
      } catch (err) {
        alert("Gemini no pudo procesar el audio. Intenta de nuevo.");
      } finally {
        setIsLoading(false);
      }
    };

    recognition.onerror = () => setIsListening(false);
  };

  const handleRegisterMaestro = async () => {
    if (!maestroForm.Codigo || !maestroForm.Descripcion) return;
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.GESTION_MAESTRO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          codigo: maestroForm.Codigo,
          descripcion: maestroForm.Descripcion,
          categoria: maestroForm.Categoria,
          precioCosto: maestroForm.Costo,
          precioVenta: maestroForm.Venta,
          activo: "SI"
        })
      });
      if (res.ok) {
        setIsMaestroModalOpen(false);
        setMaestroForm({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const payload = {
        operador: user.name,
        tipo: movForm.type,
        codigo: movForm.reference,
        cantidad: Math.abs(movForm.quantity),
        bodega: SEDES.find(s => s.id === user.sedeId)?.name || user.sedeId,
        destino: movForm.type === 'TRASLADO' ? (SEDES.find(s => s.id === movForm.destSede)?.name || '') : '',
        observaciones: movForm.notes || 'Registrado desde App'
      };

      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (res.ok) {
        setIsMovModalOpen(false);
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '' as SedeId, notes: '' });
        setTimeout(loadData, 1500);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setIsSubmitting(false);
    }
  };

  const allStockData = useMemo(() => {
    const products: ProductStock[] = [];

    rawProducts.forEach(p => {
      const baseProd = {
        Codigo: p.referencia || 'SIN-REF',
        Descripcion: p.nombre || 'Sin nombre',
        Categoria: p.tipo || 'Otros',
        Costo: Number(p.precioCosto) || 0,
        Venta: Number(p.precioVenta) || 0,
        Activo: 'SI',
        Stock_Minimo: Number(p.stockMinimo) || 5
      };

      if (filterSede === 'ALL') {
        products.push({
          ...baseProd,
          Stock_Actual: p.stock?.total || 0,
          SedeId: 'taller' as SedeId 
        });
      } else {
        const jsonKey = mapAppSedeToJsonProperty(filterSede);
        products.push({
          ...baseProd,
          Stock_Actual: p.stock ? (p.stock[jsonKey] || 0) : 0,
          SedeId: filterSede
        });
      }
    });

    return products;
  }, [rawProducts, filterSede]);

  const stats = useMemo(() => {
    return {
      totalCost: allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0),
      totalSale: allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)
    };
  }, [allStockData]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && (
        <QRScanner 
          onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore inventariapp</h1>
        </div>
        <div className="flex items-center gap-4">
          <div className="hidden md:block text-right">
            <p className="text-[10px] font-black text-slate-400 uppercase leading-none">{user.role}</p>
            <p className="text-xs font-bold text-slate-700">{user.name}</p>
          </div>
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">

        {/* KPI CARDS */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión ({filterSede === 'ALL' ? 'Global' : filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalCost).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group">
             <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/10 rounded-full -ml-16 -mb-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(stats.totalSale).toLocaleString()}</h2>
          </div>
        </div>

        {/* INSIGHTS EJECUTIVOS SECTION */}
        <section className="bg-white rounded-[2.5rem] p-8 shadow-xl border border-slate-100">
          <div className="flex items-center gap-3 mb-6">
            <div className="bg-amber-100 p-2 rounded-lg">
              <svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg>
            </div>
            <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Insights Ejecutivos (Resumen)</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
            <div className="p-5 bg-emerald-50 rounded-3xl border border-emerald-100 transition-hover hover:scale-[1.02]">
              <p className="text-[10px] font-black text-emerald-600 uppercase mb-2">⭐ Producto Estrella</p>
              <h4 className="text-sm font-black text-slate-800">YEL-006</h4>
              <p className="text-[11px] text-slate-500 font-medium mt-1">Medias Pack x3 (57% ingreso total)</p>
            </div>
            <div className="p-5 bg-rose-50 rounded-3xl border border-rose-100 transition-hover hover:scale-[1.02]">
              <p className="text-[10px] font-black text-rose-600 uppercase mb-2">❌ Menos Vendido</p>
              <h4 className="text-sm font-black text-slate-800">YEL-005</h4>
              <p className="text-[11px] text-slate-500 font-medium mt-1">Tenis Sport Pro (Baja rotación)</p>
            </div>
            <div className="p-5 bg-indigo-50 rounded-3xl border border-indigo-100 transition-hover hover:scale-[1.02]">
              <p className="text-[10px] font-black text-indigo-600 uppercase mb-2">📈 Sede Líder</p>
              <h4 className="text-sm font-black text-slate-800">Centro</h4>
              <p className="text-[11px] text-slate-500 font-medium mt-1">Mayor volumen de ventas histórico</p>
            </div>
            <div className="p-5 bg-amber-50 rounded-3xl border border-amber-100 transition-hover hover:scale-[1.02]">
              <p className="text-[10px] font-black text-amber-600 uppercase mb-2">🕒 Horarios Pico</p>
              <h4 className="text-[11px] font-black text-slate-800 leading-tight">M: Cen, Cou, Tal</h4>
              <h4 className="text-[11px] font-black text-slate-800 leading-tight">T: P. Sol, P. Prado</h4>
            </div>
          </div>
        </section>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>

          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={handleVoiceInput} 
              className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Carga por Voz AI'}
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">
              Nuevo Movimiento
            </Button>
          </div>
        </div>

        {/* DATA TABLE */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Existencias de Inventario</h3>
            <button onClick={loadData} className={`p-2 hover:bg-slate-100 rounded-full transition-all ${isLoading ? 'animate-spin opacity-50' : ''}`}>
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Código</th>
                  <th className="px-8 py-6">Descripción</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all group">
                    <td className="px-8 py-6">
                       <span className="bg-slate-100 px-3 py-1.5 rounded-lg text-[11px] font-black text-slate-600 group-hover:bg-indigo-600 group-hover:text-white transition-all">{s.Codigo}</span>
                    </td>
                    <td className="px-8 py-6">
                      <div className={`text-[11px] font-black uppercase ${String(s.Descripcion).includes('⚠️') ? 'text-amber-500' : 'text-slate-800'}`}>{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">
                      ${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {allStockData.length === 0 && !isLoading && (
              <div className="py-20 text-center text-slate-300 font-black text-xs uppercase tracking-widest">No hay datos en esta sede</div>
            )}
          </div>
        </div>
      </main>

      {/* MODAL MAESTRO (PARA VOZ O MANUAL) */}
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 NUEVO PRODUCTO MAESTRO">
        <div className="space-y-4">
          <p className="text-[10px] font-bold text-indigo-600 uppercase mb-4 bg-indigo-50 p-3 rounded-xl border border-indigo-100">
            {maestroForm.Descripcion ? "✨ Datos procesados por AI" : "Completa los datos del producto"}
          </p>
          <Input label="CÓDIGO (Referencia)" value={maestroForm.Codigo} onChange={e => setMaestroForm({...maestroForm, Codigo: e.target.value.toUpperCase()})} placeholder="YEL-000" />
          <Input label="DESCRIPCIÓN" value={maestroForm.Descripcion} onChange={e => setMaestroForm({...maestroForm, Descripcion: e.target.value})} placeholder="Nombre del producto" />
          <Select label="CATEGORÍA" options={PRODUCT_CATEGORIES.map(c => ({value:c, label:c}))} value={maestroForm.Categoria} onChange={e => setMaestroForm({...maestroForm, Categoria: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="COSTO ($)" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} />
            <Input label="VENTA ($)" type="number" value={maestroForm.Venta} onChange={e => setMaestroForm({...maestroForm, Venta: Number(e.target.value)})} />
          </div>
          <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting || !maestroForm.Codigo} className="py-4 text-[11px] font-black uppercase">
            {isSubmitting ? 'Sincronizando...' : 'Confirmar en Maestro'}
          </Button>
        </div>
      </Modal>

      {/* MODAL MOVIMIENTOS */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
        <div className="space-y-6">
          <div className="flex gap-2">
            <Input label="CÓDIGO PRODUCTO" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="Eje: YEL-100" />
            <button onClick={() => setIsQRVisible(true)} className="mt-7 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 text-indigo-600 transition-all">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m6 11h2m-6 0h-2v4m0-11v3m0 0h.01M12 12h4.01M16 20h4M4 12h4m12 0h.01M5 8h2a1 1 0 001-1V5a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1zm12 0h2a1 1 0 001-1V5a1 1 0 00-1-1h-2a1 1 0 00-1 1v2a1 1 0 001 1zM5 20h2a1 1 0 001-1v-2a1 1 0 00-1-1H5a1 1 0 00-1 1v2a1 1 0 001 1z" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Select label="TIPO MOVIMIENTO" options={[{value:'SALIDA', label:'Venta / Salida'}, {value:'ENTRADA', label:'Carga / Entrada'}, {value:'TRASLADO', label:'Traslado Inter-sede'}]} value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} />
            <Input label="CANTIDAD" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} className="text-center font-black" />
          </div>
          {movForm.type === 'TRASLADO' && (
            <Select label="DESTINO" options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value:s.id, label:s.name}))} value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as any})} />
          )}
          <Input label="OBSERVACIONES" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="Opcional..." />
          <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting || !movForm.reference} className="py-4 text-[11px] font-black uppercase tracking-widest">
            {isSubmitting ? 'Sincronizando n8n...' : 'Registrar en Log'}
          </Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [statsBackend, setStatsBackend] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId, notes: '' });
  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;

      if (source && source.productos) {
        setRawProducts(source.productos);
        setStatsBackend(source.estadisticas);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  // --- CÁLCULO DINÁMICO DE INSIGHTS ---
  const executiveInsights = useMemo(() => {
    if (!rawProducts.length) return null;

    // 1. Producto Estrella (Por valor de inventario/potencial)
    const estrella = [...rawProducts].sort((a, b) => Number(b.valorInventario) - Number(a.valorInventario))[0];

    // 2. Menos Vendido (Menor stock positivo o margen crítico)
    const menosVendido = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // 3. Sede Líder (Suma de valor por sede)
    const sedesValor = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      return { name: s.name, total: totalSede };
    }).sort((a, b) => b.total - a.total);

    return {
