            <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Insights Ejecutivos (Basado en n8n)</h3>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group">
              <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
              <h4 className="text-sm font-black text-slate-800 group-hover:text-indigo-600 transition-colors">{executiveInsights?.estrella.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.estrella.nombre || 'Calculando'}</p>
              <div className="mt-4 text-[9px] font-black bg-emerald-50 text-emerald-600 px-2 py-1 rounded-md inline-block">{executiveInsights?.estrella.info}</div>
            </div>

            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group">
              <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">❌ Menos Vendido</p>
              <h4 className="text-sm font-black text-slate-800">{executiveInsights?.critico.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.critico.nombre || 'Bajo stock'}</p>
              <div className="mt-4 text-[9px] font-black bg-rose-50 text-rose-600 px-2 py-1 rounded-md inline-block">Revisar rotación</div>
            </div>

            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">📍 Sede Líder</p>
              <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights?.sedeLider || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Máximo Volumen Stock</p>
              <div className="mt-4 flex -space-x-2">
                {[1,2,3].map(i => <div key={i} className="w-5 h-5 rounded-full border-2 border-white bg-slate-200"></div>)}
              </div>
            </div>

            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">🕒 Horarios Pico</p>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight">M: Cen, Cou, Tal</h4>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight mt-1">T: P. Sol, P. Prado</h4>
              <p className="text-[9px] text-slate-300 font-bold mt-3 uppercase">Análisis n8n AI</p>
            </div>
          </div>
        </section>

        {/* ACCIONES Y FILTROS */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Voz AI'}
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Nuevo Movimiento</Button>
          </div>
        </div>

        {/* TABLA DE PRODUCTOS */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className={`p-2 hover:bg-slate-100 rounded-full transition-all ${isLoading ? 'animate-spin' : ''}`}>
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all group">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODALES (MAESTRO Y MOVIMIENTOS) */}
      // Fix: Added the missing children to the Modal component for creating a new product
      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 NUEVO PRODUCTO MAESTRO">
         <div className="space-y-4">
           <Input label="Referencia" value={maestroForm.Codigo} onChange={e => setMaestroForm({...maestroForm, Codigo: e.target.value})} />
           <Input label="Nombre" value={maestroForm.Descripcion} onChange={e => setMaestroForm({...maestroForm, Descripcion: e.target.value})} />
           <Select 
             label="Categoría" 
             value={maestroForm.Categoria} 
             onChange={e => setMaestroForm({...maestroForm, Categoria: e.target.value})} 
             options={PRODUCT_CATEGORIES.map(c => ({value: c, label: c}))} 
           />
           <div className="grid grid-cols-2 gap-4">
             <Input label="Costo" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} />
             <Input label="Venta" type="number" value={maestroForm.Venta} onChange={e => setMaestroForm({...maestroForm, Venta: Number(e.target.value)})} />
           </div>
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMaestroModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting}>
               {isSubmitting ? 'Guardando...' : 'Crear Producto'}
             </Button>
           </div>
         </div>
      </Modal>

      // Fix: Added the missing children to the Modal component for recording stock movements
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select 
               label="Tipo" 
               value={movForm.type} 
               onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} 
               options={[
                 {value: 'ENTRADA', label: 'Entrada'},
                 {value: 'SALIDA', label: 'Salida'},
                 {value: 'TRASLADO', label: 'Traslado'}
               ]} 
             />
           </div>
           {movForm.type === 'TRASLADO' && (
             <Select 
               label="Sede Destino" 
               value={movForm.destSede} 
               onChange={e => setMovForm({...movForm, destSede: e.target.value as SedeId})} 
               options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value: s.id, label: s.name}))} 
             />
           )}
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>
               {isSubmitting ? 'Procesando...' : 'Confirmar Operación'}
             </Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [statsBackend, setStatsBackend] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  const [movForm, setMovForm] = useState({ reference: '', quantity: 1, type: 'SALIDA' as MovementType, destSede: '' as SedeId, notes: '' });
  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;

      if (source && source.productos) {
        setRawProducts(source.productos);
        setStatsBackend(source.estadisticas);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  // --- CÁLCULO DINÁMICO DE LOS 6 INSIGHTS ---
  const executiveInsights = useMemo(() => {
    if (!rawProducts.length) return null;

    // 1. Producto Estrella (Mayor Venta Potencial: Precio * Stock Total)
    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    // 2. Producto con Mayor Stock Físico
    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // 3. Sede Líder en Venta (Suma de Valor de Venta por sede)
    // 4. Sede con Mayor Stock Físico (Suma de unidades por sede)
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const sedeMayorStock = [...sedesData].sort((a, b) => b.totalUnidades - a.totalUnidades)[0];

    // 5. Stock Crítico (Producto con menos stock total)
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: {
        ref: estrella.referencia,
        nombre: estrella.nombre,
        valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString()
      },
      mayorStockProd: {
        ref: mayorStockProd.referencia,
        nombre: mayorStockProd.nombre,
        cantidad: mayorStockProd.stock?.total || 0
      },
      sedeLiderVenta: {
        name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''),
        monto: sedeLiderVenta.totalVenta.toLocaleString()
      },
      sedeMayorStock: {
        name: sedeMayorStock.name.replace(/^[0-9].\s*/, ''),
        cantidad: sedeMayorStock.totalUnidades
      },
      critico: {
        ref: critico.referencia,
        nombre: critico.nombre,
        info: critico.stock?.total || 0
      },
      horarios: "Mañana (Cen, Tal) / Tarde (Plaza)"
    };
  }, [rawProducts]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Activo: 'SI',
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
      SedeId: filterSede === 'ALL' ? 'taller' : filterSede
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Actúa como asistente de inventario experto. Procesa esta instrucción de voz: "${transcript}".
          Extrae: referencia, cantidad y tipo de movimiento (ENTRADA, SALIDA, TRASLADO).
          Responde en JSON: { "reference": string, "quantity": number, "type": "ENTRADA"|"SALIDA"|"TRASLADO", "destSede": string|null, "notes": string }`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                reference: { type: Type.STRING },
                quantity: { type: Type.NUMBER },
                type: { type: Type.STRING },
                destSede: { type: Type.STRING },
                notes: { type: Type.STRING }
              }
            }
          }
        });

        const data = JSON.parse(response.text);
        setMovForm({
          reference: data.reference || '',
          quantity: data.quantity || 1,
          type: (data.type as MovementType) || 'SALIDA',
          destSede: (data.destSede as SedeId) || '',
          notes: data.notes || 'Vía Voz AI'
        });
        setIsMovModalOpen(true);
      } catch (e) {
        console.error("AI Error:", e);
      }
    };
    recognition.onerror = () => setIsListening(false);
    recognition.start();
  };

  const handleRegisterMaestro = async () => {
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.GESTION_MAESTRO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...maestroForm, usuario: user.username })
      });
      if (response.ok) { setIsMaestroModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore inventariapp</h1>
        </div>
        <div className="flex items-center gap-4">
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">

        {/* KPI CARDS (RESUMEN) */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión ({filterSede === 'ALL' ? 'Global' : filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group">
             <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/10 rounded-full -ml-16 -mb-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {/* INSIGHTS EJECUTIVOS - 6 CASILLAS (3x2 Desktop, Responsive Mobile) */}
        <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="flex items-center gap-3 mb-6 px-2">
            <div className="bg-amber-100 p-2 rounded-lg">
              <svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg>
            </div>
            <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Insights Ejecutivos</h3>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {/* 1. Sede Líder Venta */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder (Ventas)</p>
              <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights?.sedeLiderVenta.name || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Monto: ${executiveInsights?.sedeLiderVenta.monto}</p>
            </div>

            {/* 2. Sede Mayor Stock */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-blue-500 uppercase mb-3 tracking-widest">🏢 Sede Mayor Stock</p>
              <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights?.sedeMayorStock.name || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Unidades: {executiveInsights?.sedeMayorStock.cantidad}</p>
            </div>

            {/* 3. Producto Estrella */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group">
              <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
              <h4 className="text-sm font-black text-slate-800 group-hover:text-indigo-600 transition-colors truncate">{executiveInsights?.estrella.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.estrella.nombre}</p>
              <div className="mt-2 text-[9px] font-black text-emerald-600">Venta Est.: ${executiveInsights?.estrella.valor}</div>
            </div>

            {/* 4. Producto Mayor Stock */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-purple-500 uppercase mb-3 tracking-widest">📦 Mayor Stock (Prod)</p>
              <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights?.mayorStockProd.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.mayorStockProd.nombre}</p>
              <div className="mt-2 text-[9px] font-black text-purple-600">{executiveInsights?.mayorStockProd.cantidad} Unidades</div>
            </div>

            {/* 5. Stock Crítico */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
              <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights?.critico.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.critico.nombre}</p>
              <div className="mt-2 text-[9px] font-black bg-rose-50 text-rose-600 px-2 py-1 rounded-md inline-block">Quedan: {executiveInsights?.critico.info}</div>
            </div>

            {/* 6. Horarios Pico */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">🕒 Horarios Pico (AI)</p>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight">M: Cen, Tal, Cou</h4>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight mt-1">T: Plaza, Portal</h4>
              <p className="text-[9px] text-slate-300 font-bold mt-3 uppercase">Basado en tendencias</p>
            </div>
          </div>
        </section>

        {/* ACCIONES Y FILTROS */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Voz AI'}
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Nuevo Movimiento</Button>
          </div>
        </div>

        {/* TABLA DE PRODUCTOS */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className={`p-2 hover:bg-slate-100 rounded-full transition-all ${isLoading ? 'animate-spin' : ''}`}>
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Venta Tot.</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all group">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 NUEVO PRODUCTO MAESTRO">
         <div className="space-y-4">
           <Input label="Referencia" value={maestroForm.Codigo} onChange={e => setMaestroForm({...maestroForm, Codigo: e.target.value.toUpperCase()})} />
           <Input label="Nombre" value={maestroForm.Descripcion} onChange={e => setMaestroForm({...maestroForm, Descripcion: e.target.value})} />
           <Select label="Categoría" value={maestroForm.Categoria} onChange={e => setMaestroForm({...maestroForm, Categoria: e.target.value})} options={PRODUCT_CATEGORIES.map(c => ({value: c, label: c}))} />
           <div className="grid grid-cols-2 gap-4">
             <Input label="Costo" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} />
             <Input label="Venta" type="number" value={maestroForm.Venta} onChange={e => setMaestroForm({...maestroForm, Venta: Number(e.target.value)})} />
           </div>
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMaestroModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting}>{isSubmitting ? 'Guardando...' : 'Crear Producto'}</Button>
           </div>
         </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}, {value: 'TRASLADO', label: 'Traslado'}]} />
           </div>
           {movForm.type === 'TRASLADO' && (
             <Select label="Sede Destino" value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as SedeId})} options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value: s.id, label: s.name}))} />
           )}
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar Operación'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, ProductStock, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [statsBackend, setStatsBackend] = useState<any>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isMaestroModalOpen, setIsMaestroModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // Forms
  // Added explicit type for movForm to allow empty string in destSede field which is common in forms before a value is selected
  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const [maestroForm, setMaestroForm] = useState<Partial<MaestroProducto>>({ Codigo: '', Descripcion: '', Categoria: 'Vestidos', Costo: 0, Venta: 0, Activo: 'SI' });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;

      if (source && source.productos) {
        setRawProducts(source.productos);
        setStatsBackend(source.estadisticas);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  // --- CÁLCULO DINÁMICO DE LOS 6 INSIGHTS ---
  const executiveInsights = useMemo(() => {
    if (!rawProducts.length) return null;

    // 1. Producto Estrella (Mayor Venta Potencial: Precio * Stock Total)
    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    // 2. Producto con Mayor Stock Físico
    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // 3. Sede Líder en Venta (Suma de Valor de Venta por sede)
    // 4. Sede con Mayor Stock Físico (Suma de unidades por sede)
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const sedeMayorStock = [...sedesData].sort((a, b) => b.totalUnidades - a.totalUnidades)[0];

    // 5. Stock Crítico (Producto con menos stock total)
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: {
        ref: estrella.referencia,
        nombre: estrella.nombre,
        valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString()
      },
      mayorStockProd: {
        ref: mayorStockProd.referencia,
        nombre: mayorStockProd.nombre,
        cantidad: mayorStockProd.stock?.total || 0
      },
      sedeLiderVenta: {
        name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''),
        monto: sedeLiderVenta.totalVenta.toLocaleString()
      },
      sedeMayorStock: {
        name: sedeMayorStock.name.replace(/^[0-9].\s*/, ''),
        cantidad: sedeMayorStock.totalUnidades
      },
      critico: {
        ref: critico.referencia,
        nombre: critico.nombre,
        info: critico.stock?.total || 0
      },
      horarios: "Mañana (Cen, Tal) / Tarde (Plaza)"
    };
  }, [rawProducts]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Activo: 'SI',
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
      SedeId: filterSede === 'ALL' ? 'taller' : filterSede
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert("Tu navegador no soporta reconocimiento de voz.");
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);

    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);

      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Actúa como asistente de inventario experto. Procesa esta instrucción de voz: "${transcript}".
          Extrae: referencia, cantidad y tipo de movimiento (ENTRADA, SALIDA, TRASLADO).
          Responde en JSON: { "reference": string, "quantity": number, "type": "ENTRADA"|"SALIDA"|"TRASLADO", "destSede": string|null, "notes": string }`,
          config: {
            responseMimeType: "application/json",
            responseSchema: {
              type: Type.OBJECT,
              properties: {
                reference: { type: Type.STRING },
                quantity: { type: Type.NUMBER },
                type: { type: Type.STRING },
                destSede: { type: Type.STRING },
                notes: { type: Type.STRING }
              }
            }
          }
        });

        const text = response.text || '{}';
        const data = JSON.parse(text);
        // Fixed: destSede can now safely accept empty string due to updated movForm state type, fixing line 162 error
        setMovForm({
          reference: data.reference || '',
          quantity: data.quantity || 1,
          type: (data.type as MovementType) || 'SALIDA',
          destSede: (data.destSede as SedeId) || '',
          notes: data.notes || 'Vía Voz AI'
        });
        setIsMovModalOpen(true);
      } catch (e) {
        console.error("AI Error:", e);
      }
    };
    recognition.onerror = () => setIsListening(false);
    recognition.start();
  };

  const handleRegisterMaestro = async () => {
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.GESTION_MAESTRO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...maestroForm, usuario: user.username })
      });
      if (response.ok) { setIsMaestroModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore inventariapp</h1>
        </div>
        <div className="flex items-center gap-4">
          <Button variant="secondary" onClick={onLogout} className="text-xs font-bold h-9">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">

        {/* KPI CARDS (RESUMEN) */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden group">
             <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/10 rounded-full -mr-16 -mt-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión ({filterSede === 'ALL' ? 'Global' : filterSede})</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group">
             <div className="absolute bottom-0 left-0 w-32 h-32 bg-white/10 rounded-full -ml-16 -mb-16 blur-2xl group-hover:scale-150 transition-all duration-700"></div>
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {/* INSIGHTS EJECUTIVOS - 6 CASILLAS (3x2 Desktop, Responsive Mobile) */}
        <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
          <div className="flex items-center gap-3 mb-6 px-2">
            <div className="bg-amber-100 p-2 rounded-lg">
              <svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg>
            </div>
            <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Insights Ejecutivos</h3>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {/* 1. Sede Líder Venta */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder (Ventas)</p>
              <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights?.sedeLiderVenta.name || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Monto: ${executiveInsights?.sedeLiderVenta.monto}</p>
            </div>

            {/* 2. Sede Mayor Stock */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-blue-500 uppercase mb-3 tracking-widest">🏢 Sede Mayor Stock</p>
              <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights?.sedeMayorStock.name || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase">Unidades: {executiveInsights?.sedeMayorStock.cantidad}</p>
            </div>

            {/* 3. Producto Estrella */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all group">
              <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
              <h4 className="text-sm font-black text-slate-800 group-hover:text-indigo-600 transition-colors truncate">{executiveInsights?.estrella.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.estrella.nombre}</p>
              <div className="mt-2 text-[9px] font-black text-emerald-600">Venta Est.: ${executiveInsights?.estrella.valor}</div>
            </div>

            {/* 4. Producto Mayor Stock */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-purple-500 uppercase mb-3 tracking-widest">📦 Mayor Stock (Prod)</p>
              <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights?.mayorStockProd.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.mayorStockProd.nombre}</p>
              <div className="mt-2 text-[9px] font-black text-purple-600">{executiveInsights?.mayorStockProd.cantidad} Unidades</div>
            </div>

            {/* 5. Stock Crítico */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
              <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights?.critico.ref || '...'}</h4>
              <p className="text-[10px] text-slate-400 font-bold mt-1 uppercase truncate">{executiveInsights?.critico.nombre}</p>
              <div className="mt-2 text-[9px] font-black bg-rose-50 text-rose-600 px-2 py-1 rounded-md inline-block">Quedan: {executiveInsights?.critico.info}</div>
            </div>

            {/* 6. Horarios Pico */}
            <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-all">
              <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">🕒 Horarios Pico (AI)</p>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight">M: Cen, Tal, Cou</h4>
              <h4 className="text-[10px] font-black text-slate-800 leading-tight mt-1">T: Plaza, Portal</h4>
              <p className="text-[9px] text-slate-300 font-bold mt-3 uppercase">Basado en tendencias</p>
            </div>
          </div>
        </section>

        {/* ACCIONES Y FILTROS */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              {user.role === 'GERENTE' && (
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              )}
            </div>
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2" strokeLinecap="round"/></svg>
              {isListening ? 'Escuchando...' : 'Voz AI'}
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Nuevo Movimiento</Button>
          </div>
        </div>

        {/* TABLA DE PRODUCTOS */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className={`p-2 hover:bg-slate-100 rounded-full transition-all ${isLoading ? 'animate-spin' : ''}`}>
              <svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Venta Tot.</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all group">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMaestroModalOpen} onClose={() => setIsMaestroModalOpen(false)} title="📋 NUEVO PRODUCTO MAESTRO">
         <div className="space-y-4">
           <Input label="Referencia" value={maestroForm.Codigo} onChange={e => setMaestroForm({...maestroForm, Codigo: e.target.value.toUpperCase()})} />
           <Input label="Nombre" value={maestroForm.Descripcion} onChange={e => setMaestroForm({...maestroForm, Descripcion: e.target.value})} />
           <Select label="Categoría" value={maestroForm.Categoria} onChange={e => setMaestroForm({...maestroForm, Categoria: e.target.value})} options={PRODUCT_CATEGORIES.map(c => ({value: c, label: c}))} />
           <div className="grid grid-cols-2 gap-4">
             <Input label="Costo" type="number" value={maestroForm.Costo} onChange={e => setMaestroForm({...maestroForm, Costo: Number(e.target.value)})} />
             <Input label="Venta" type="number" value={maestroForm.Venta} onChange={e => setMaestroForm({...maestroForm, Venta: Number(e.target.value)})} />
           </div>
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMaestroModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMaestro} disabled={isSubmitting}>{isSubmitting ? 'Guardando...' : 'Crear Producto'}</Button>
           </div>
         </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}, {value: 'TRASLADO', label: 'Traslado'}]} />
           </div>
           {movForm.type === 'TRASLADO' && (
             <Select label="Sede Destino" value={movForm.destSede} onChange={e => setMovForm({...movForm, destSede: e.target.value as SedeId})} options={SEDES.filter(s => s.id !== user.sedeId).map(s => ({value: s.id, label: s.name}))} />
           )}
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar Operación'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import { Sede } from './types';

/**
 * CONFIGURACIÓN n8n
 */
export const N8N_WEBHOOKS = {
  CONSULTA_GLOBAL: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/consulta-inventario',
  REGISTRO_MOVIMIENTO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/movimiento',
  GESTION_MAESTRO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/producto-nuevo',
  INFORME_IA: 'https://icad-n8n.ltubgr.easypanel.host/webhook/692386ed-2848-4323-a6d4-1f2f7a5f0349'
};

export const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzYf1o2Q0DNm2hGPksEYP8GQ5nOhVRt48mnDp41n6igS5mdq3uezQA40BRQWvIYjQlVnA/exec';

export const SEDES: Sede[] = [
  { id: 'taller', name: '1. Taller' },
  { id: 'country', name: '2. Country' },
  { id: 'plaza_sol', name: '3. Plaza del Sol' },
  { id: 'portal_prado', name: '4. Portal del Prado' },
  { id: 'centro', name: '5. Centro' }
];

export const PRODUCT_CATEGORIES = [
  'Vestidos',
  'Blusas / Tops',
  'Pantalones / Jeans',
  'Faldas',
  'Chaquetas / Abrigos',
  'Calzado',
  'Accesorios',
  'Lencería / Intima',
  'Vestidos de Baño'
];

export const STORAGE_KEYS = {
  AUTH: 'yeilu_auth_state',
  CACHED_DATA: 'yeilu_cached_data',
  MOVEMENTS: 'yeilu_movements_data'
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts,
          timestamp: new Date().toISOString()
        })
      });
      const data = await response.json();
      setReportData(data);
    } catch (error) {
      console.error("Report Error:", error);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const sedeMayorStock = [...sedesData].sort((a, b) => b.totalUnidades - a.totalUnidades)[0];
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      sedeMayorStock: { name: sedeMayorStock.name.replace(/^[0-9].\s*/, ''), cantidad: sedeMayorStock.totalUnidades },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 },
      horarios: "Pico: 14:00 - 17:00"
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              Análisis Estratégico
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">

        {/* KPI CARDS - VISIBLES PARA TODOS PERO CON DATA SEGÚN ROL */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {/* INSIGHTS EJECUTIVOS - SOLO GERENTE */}
        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info}</p>
              </div>
            </div>
          </section>
        )}

        {/* ACCIONES */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        {/* TABLA */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL INFORME IA ESTRATÉGICO */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>

              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <p className="text-[11px] text-slate-600 leading-relaxed">{sec.contenido}</p>
                  </div>
                ))}
              </div>

              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : (
            <div className="text-center py-10">
              <p className="text-xs text-slate-400">No se pudo generar el informe. Reintente.</p>
            </div>
          )}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar Análisis</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setIsReportModalOpen(true);

    try {
      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        mode: 'cors',
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts,
          timestamp: new Date().toISOString()
        })
      });

      if (!response.ok) {
        throw new Error(`Error del servidor: ${response.status}`);
      }

      const data = await response.json();
      setReportData(data);
    } catch (error: any) {
      console.error("Report Error:", error);
      setReportError(
        error.message === "Failed to fetch" 
          ? "Error de Conexión (CORS): n8n no está permitiendo peticiones desde este dominio. Verifica la configuración de 'Respond with Headers' en el nodo Webhook de n8n."
          : `Error al generar informe: ${error.message}`
      );
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              Análisis Estratégico
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info}</p>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
              <p className="text-[9px] text-slate-400 text-center max-w-[200px]">Esto puede tardar unos segundos dependiendo de la cantidad de productos.</p>
            </div>
          ) : reportError ? (
            <div className="py-10 text-center space-y-6">
              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2">Error de Conexión</h4>
                <p className="text-[11px] font-medium leading-relaxed">{reportError}</p>
              </div>
              <Button onClick={handleGenerateReport} fullWidth>Reintentar Análisis</Button>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>
              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <p className="text-[11px] text-slate-600 leading-relaxed">{sec.contenido}</p>
                  </div>
                ))}
              </div>
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : null}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setIsReportModalOpen(true);

    try {
      // Usamos un controlador de aborto para manejar timeouts si n8n tarda demasiado (> 60s)
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90000); // 90 segundos

      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts,
          timestamp: new Date().toISOString()
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new Error(`Servidor n8n respondió con error: ${response.status}`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
        const data = await response.json();
        // Si n8n devuelve el JSON estructurado que sugerimos:
        setReportData(data);
      } else {
        // Si n8n devuelve texto plano o Markdown:
        const text = await response.text();
        setReportData({
          titulo: "Informe Estratégico Yeilu",
          resumen: "Análisis generado mediante procesamiento de lenguaje natural.",
          secciones: [{
            tag: "IA",
            titulo: "Análisis Detallado",
            contenido: text,
            estado: "info"
          }],
          recomendaciones: ["Revisar tendencias de stock", "Optimizar rotación en sedes"]
        });
      }
    } catch (error: any) {
      console.error("Report Error:", error);
      if (error.name === 'AbortError') {
        setReportError("El análisis está tardando demasiado. Verifica que n8n no esté bloqueado o aumenta el tiempo de respuesta.");
      } else {
        setReportError(
          "No se pudo conectar con el agente. Asegúrate de que en n8n:\n1. 'Respond' esté en 'When Last Node Finishes'\n2. El nodo Webhook tenga activado el método 'OPTIONS'."
        );
      }
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              disabled={isGeneratingReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all disabled:opacity-50"
            >
              <svg className={`w-4 h-4 ${isGeneratingReport ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              {isGeneratingReport ? 'Generando...' : 'Análisis Estratégico'}
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info}</p>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
              <p className="text-[9px] text-slate-400 text-center max-w-[200px]">Este proceso puede tomar hasta 40 segundos mientras n8n procesa la IA.</p>
            </div>
          ) : reportError ? (
            <div className="py-10 text-center space-y-6">
              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block text-left">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2 text-center">Error de Comunicación</h4>
                <p className="text-[11px] font-medium leading-relaxed whitespace-pre-wrap">{reportError}</p>
                <div className="mt-4 p-3 bg-white rounded-xl text-[10px] text-slate-500 border border-rose-100 font-bold">
                  TIP: En n8n, cambia la opción "Respond" de "Immediately" a "When Last Node Finishes".
                </div>
              </div>
              <Button onClick={handleGenerateReport} fullWidth>Reintentar Análisis</Button>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>
              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <div className="text-[11px] text-slate-600 leading-relaxed whitespace-pre-wrap font-medium">{sec.contenido}</div>
                  </div>
                ))}
              </div>
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : null}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setIsReportModalOpen(true);

    // Debug: Ver en consola qué URL se está llamando
    console.log("🚀 Iniciando petición a n8n:", N8N_WEBHOOKS.INFORME_IA);

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 60000); 

      // Enviamos una petición lo más limpia posible para evitar bloqueos de CORS
      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        mode: 'cors', // Forzamos modo CORS
        headers: { 
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts.slice(0, 50), // Enviamos solo los primeros 50 para evitar payloads pesados en pruebas
          timestamp: new Date().toISOString(),
          debug: true
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`Error ${response.status}: ${errorText || 'Sin respuesta del servidor'}`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
        const data = await response.json();
        setReportData(data);
      } else {
        const text = await response.text();
        // Si n8n devuelve texto plano, lo estructuramos
        setReportData({
          titulo: "Análisis Estratégico Yeilu",
          resumen: "Resumen procesado por la IA de n8n.",
          secciones: [{
            tag: "INFO",
            titulo: "Resultado del Análisis",
            contenido: text || "n8n devolvió una respuesta vacía.",
            estado: "info"
          }],
          recomendaciones: ["Verificar logs de n8n", "Asegurar que el modelo LLM esté respondiendo"]
        });
      }
    } catch (error: any) {
      console.error("❌ Error Crítico en Fetch n8n:", error);

      let msg = "Error desconocido.";
      if (error.name === 'AbortError') {
        msg = "Tiempo de espera agotado (60s). n8n tardó demasiado en responder.";
      } else if (error.message.includes("Failed to fetch")) {
        msg = "No se pudo establecer conexión. Posibles causas:\n1. El flujo n8n está APAGADO (usa la URL de Test).\n2. CORS bloqueado (verifica que n8n permita el origen).\n3. La URL es incorrecta.";
      } else {
        msg = error.message;
      }
      setReportError(msg);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              disabled={isGeneratingReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all disabled:opacity-50"
            >
              <svg className={`w-4 h-4 ${isGeneratingReport ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              {isGeneratingReport ? 'Analizando...' : 'Análisis Estratégico'}
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info}</p>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4 text-center">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
              <p className="text-[9px] text-slate-400 max-w-[200px]">Si n8n no registra la entrada, asegúrate de estar usando la URL correcta (Test vs Prod) y que el flujo esté activo.</p>
            </div>
          ) : reportError ? (
            <div className="py-10 text-center space-y-6">
              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block text-left">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2 text-center">Fallo de Comunicación</h4>
                <p className="text-[11px] font-medium leading-relaxed whitespace-pre-wrap">{reportError}</p>
                <div className="mt-4 p-3 bg-white rounded-xl text-[10px] text-slate-500 border border-rose-100 font-bold">
                  IMPORTANTE: Si estás probando en n8n, haz clic en "Listen for test event" ANTES de presionar el botón de análisis.
                </div>
              </div>
              <Button onClick={handleGenerateReport} fullWidth>Reintentar Petición</Button>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>
              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <div className="text-[11px] text-slate-600 leading-relaxed whitespace-pre-wrap font-medium">{sec.contenido}</div>
                  </div>
                ))}
              </div>
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : null}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);
  const [n8nConfigError, setN8nConfigError] = useState(false);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setN8nConfigError(false);
    setIsReportModalOpen(true);

    console.log("🚀 Enviando datos a n8n para análisis...");

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90000); 

      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        mode: 'cors',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts.slice(0, 80), 
          timestamp: new Date().toISOString()
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorJson = await response.json().catch(() => ({}));
        const errorMessage = errorJson.message || "";

        // Detectamos el error específico de n8n
        if (errorMessage.includes("Unused Respond to Webhook node")) {
          setN8nConfigError(true);
          throw new Error("Configuración de n8n incompatible detectada.");
        }

        throw new Error(`n8n devolvió error ${response.status}: ${errorMessage || 'Fallo en el servidor'}`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
        const data = await response.json();
        setReportData(data);
      } else {
        const text = await response.text();
        setReportData({
          titulo: "Informe de Inteligencia",
          resumen: "Análisis generado por n8n.",
          secciones: [{
            tag: "IA",
            titulo: "Resultado",
            contenido: text || "Respuesta vacía.",
            estado: "info"
          }],
          recomendaciones: ["Verificar consistencia de datos", "Analizar tendencias semanales"]
        });
      }
    } catch (error: any) {
      console.error("❌ Detalle del Error:", error);
      setReportError(error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });

    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              disabled={isGeneratingReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all disabled:opacity-50"
            >
              <svg className={`w-4 h-4 ${isGeneratingReport ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              {isGeneratingReport ? 'Analizando...' : 'Análisis Estratégico'}
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info}</p>
              </div>
            </div>
          </section>
        )}

        {/* Controls */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        {/* Table */}
        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4 text-center">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
            </div>
          ) : reportError ? (
            <div className="py-10 text-center space-y-6">
              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block text-left">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2 text-center">Error en n8n (500)</h4>
                <p className="text-[11px] font-medium leading-relaxed mb-4">{reportError}</p>

                {n8nConfigError && (
                  <div className="mt-4 space-y-3">
                    <div className="p-3 bg-white rounded-xl text-[10px] text-slate-600 border border-rose-200 font-bold leading-relaxed">
                      <span className="text-rose-600 block mb-1">CÓMO SOLUCIONARLO:</span>
                      1. En n8n, abre el flujo.<br/>
                      2. Busca un nodo llamado <span className="text-indigo-600">"Respond to Webhook"</span>.<br/>
                      3. <span className="underline">BÓRRALO</span> del workflow o asegúrate de que el flujo pase por él.<br/>
                      4. Si quieres usar "When Last Node Finishes", no debes tener ningún nodo "Respond to Webhook" suelto.
                    </div>
                  </div>
                )}
              </div>
              <Button onClick={handleGenerateReport} fullWidth>Reintentar Análisis</Button>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>
              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <div className="text-[11px] text-slate-600 leading-relaxed whitespace-pre-wrap font-medium">{sec.contenido}</div>
                  </div>
                ))}
              </div>
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : null}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);
  const [n8nConfigError, setN8nConfigError] = useState(false);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && source.productos) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setN8nConfigError(false);
    setIsReportModalOpen(true);

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90000); 

      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        mode: 'cors',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts.slice(0, 80), 
          timestamp: new Date().toISOString()
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorJson = await response.json().catch(() => ({}));
        const errorMessage = errorJson.message || "";
        if (errorMessage.includes("Unused Respond to Webhook node")) {
          setN8nConfigError(true);
          throw new Error("Configuración de n8n incompatible detectada.");
        }
        throw new Error(`n8n devolvió error ${response.status}: ${errorMessage || 'Fallo en el servidor'}`);
      }

      const contentType = response.headers.get("content-type");
      if (contentType && contentType.includes("application/json")) {
        const data = await response.json();
        setReportData(data);
      } else {
        const text = await response.text();
        setReportData({
          titulo: "Informe de Inteligencia",
          resumen: "Análisis generado por n8n.",
          secciones: [{
            tag: "IA",
            titulo: "Resultado",
            contenido: text || "Respuesta vacía.",
            estado: "info"
          }],
          recomendaciones: ["Verificar consistencia de datos", "Analizar tendencias semanales"]
        });
      }
    } catch (error: any) {
      console.error("❌ Detalle del Error:", error);
      setReportError(error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!rawProducts.length || user.role !== 'GERENTE') return null;

    // 1. Producto Estrella (Por valor total de venta en stock)
    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    // 2. Mayor Stock Físico (Por unidades totales)
    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // 3. Sede Líder (Valor de venta acumulado en stock)
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      const totalUnidadesSede = rawProducts.reduce((acc, p) => acc + (p.stock?.[key] || 0), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede, totalUnidades: totalUnidadesSede };
    });
    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];

    // 4. Stock Crítico (Menor cantidad)
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // 5. Categoría Líder (Por cantidad de unidades)
    const catGroups: Record<string, number> = {};
    rawProducts.forEach(p => {
      const cat = p.tipo || 'Otros';
      catGroups[cat] = (catGroups[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catGroups).sort((a, b) => b[1] - a[1])[0];

    // 6. Margen Bruto Estimado (Promedio Global)
    const totalVenta = rawProducts.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = rawProducts.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);
    const margenBruto = totalVenta > 0 ? ((totalVenta - totalCosto) / totalVenta) * 100 : 0;

    return {
      estrella: { ref: estrella.referencia, nombre: estrella.nombre, valor: (estrella.precioVenta * (estrella.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd.referencia, nombre: mayorStockProd.nombre, cantidad: mayorStockProd.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta.name.replace(/^[0-9].\s*/, ''), monto: sedeLiderVenta.totalVenta.toLocaleString() },
      critico: { ref: critico.referencia, nombre: critico.nombre, info: critico.stock?.total || 0 },
      topCategoria: { name: topCat ? topCat[0] : 'Otros', cantidad: topCat ? topCat[1] : 0 },
      margen: { valor: Math.round(margenBruto) }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              disabled={isGeneratingReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all disabled:opacity-50"
            >
              <svg className={`w-4 h-4 ${isGeneratingReport ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" strokeWidth="2"/></svg>
              {isGeneratingReport ? 'Analizando...' : 'Análisis Estratégico'}
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(allStockData.reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="flex items-center gap-3 mb-6 px-2">
              <div className="bg-amber-100 p-2 rounded-lg"><svg className="w-5 h-5 text-amber-600" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"></path></svg></div>
              <h3 className="text-xs font-black text-slate-900 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">🏆 Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.sedeLiderVenta.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">${executiveInsights.sedeLiderVenta.monto}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">⭐ Producto Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1 truncate">{executiveInsights.estrella.nombre}</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">⚠️ Stock Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">Quedan: {executiveInsights.critico.info} UND</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">📊 Mayor Volumen</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.mayorStockProd.ref}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">{executiveInsights.mayorStockProd.cantidad} Unidades en Stock</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-cyan-500 uppercase mb-3 tracking-widest">🏷️ Categoría Top</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.topCategoria.name}</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">{executiveInsights.topCategoria.cantidad} Unidades Totales</p>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-violet-500 uppercase mb-3 tracking-widest">📈 Margen Bruto</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">Eficiencia Global</h4>
                <p className="text-[10px] text-slate-400 font-bold mt-1">{executiveInsights.margen.valor}% Margen Esperado</p>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            {user.role === 'GERENTE' && (
              <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
                <Select 
                  value={filterSede} 
                  onChange={e => setFilterSede(e.target.value as any)}
                  options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                  className="border-none font-black text-xs text-indigo-600 bg-transparent"
                />
              </div>
            )}
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={handleVoiceInput} className={`flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest ${isListening ? 'bg-red-500 text-white animate-pulse' : 'bg-white text-slate-800 border border-slate-200 hover:border-indigo-500'}`}>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-20a3 3 0 013 3v5a3 3 0 01-3 3 3 3 0 01-3-3V5a3 3 0 013-3z" strokeWidth="2"/></svg>
              AI Voz
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Operación Stock</Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="✨ INFORME FINANCIERO IA">
        <div className="max-h-[70vh] overflow-y-auto pr-2 space-y-6">
          {isGeneratingReport ? (
            <div className="flex flex-col items-center justify-center py-20 space-y-4 text-center">
              <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
              <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest animate-pulse">Analizando flujos y proyecciones...</p>
            </div>
          ) : reportError ? (
            <div className="py-10 text-center space-y-6">
              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block text-left">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2 text-center">Configuración n8n Detectada (500)</h4>
                <p className="text-[11px] font-medium leading-relaxed mb-4">{reportError}</p>
                {n8nConfigError && (
                  <div className="mt-4 p-4 bg-white rounded-2xl border border-rose-200 text-[10px] font-bold text-slate-600 leading-relaxed">
                    <span className="text-rose-600 block mb-2 uppercase tracking-widest">Reparación requerida en n8n:</span>
                    Tu flujo tiene un nodo <span className="text-indigo-600">"Respond to Webhook"</span> que no se está usando correctamente. <br/><br/>
                    1. Abre n8n.<br/>
                    2. Elimina cualquier nodo "Respond to Webhook" huérfano.<br/>
                    3. O asegúrate de que el flujo termine pasando por ese nodo antes de responder.<br/>
                    4. Alternativamente, cambia el Webhook principal a <span className="text-indigo-600">"Respond: Immediately"</span>.
                  </div>
                )}
              </div>
              <Button onClick={handleGenerateReport} fullWidth>Reintentar Petición</Button>
            </div>
          ) : reportData ? (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
              <h2 className="text-2xl font-black text-slate-900 leading-tight mb-2">{reportData.titulo}</h2>
              <p className="text-sm text-slate-500 leading-relaxed mb-8">{reportData.resumen}</p>
              <div className="space-y-4">
                {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border ${
                    sec.estado === 'success' ? 'bg-emerald-50 border-emerald-100' :
                    sec.estado === 'warning' ? 'bg-amber-50 border-amber-100' :
                    sec.estado === 'danger' ? 'bg-rose-50 border-rose-100' : 'bg-blue-50 border-blue-100'
                  }`}>
                    <div className="flex items-center gap-2 mb-2">
                      <span className="text-[8px] font-black uppercase px-2 py-0.5 rounded-full bg-white/50 text-slate-600 tracking-tighter">{sec.tag}</span>
                      <h4 className="text-xs font-black text-slate-800 uppercase">{sec.titulo}</h4>
                    </div>
                    <div className="text-[11px] text-slate-600 leading-relaxed whitespace-pre-wrap font-medium">{sec.contenido}</div>
                  </div>
                ))}
              </div>
              <div className="mt-8 pt-8 border-t border-slate-100">
                <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest mb-4">Recomendaciones Clave</h4>
                <div className="space-y-3">
                  {reportData.recomendaciones.map((rec, i) => (
                    <div key={i} className="flex gap-3 items-start">
                      <div className="mt-1 w-1.5 h-1.5 rounded-full bg-indigo-400 flex-shrink-0"></div>
                      <p className="text-[11px] font-bold text-slate-700">{rec}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          ) : null}
          <Button fullWidth onClick={() => setIsReportModalOpen(false)} variant="secondary" className="mt-6 rounded-2xl">Cerrar</Button>
        </div>
      </Modal>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 OPERACIÓN DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <Button variant="secondary" className="mt-8 px-3" onClick={() => setIsQRVisible(true)}>📷</Button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);
  const [n8nConfigError, setN8nConfigError] = useState(false);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      // Aseguramos que productos sea siempre un arreglo
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      } else {
        setRawProducts([]);
      }
    } catch (error) {
      console.error("Error n8n:", error);
      setRawProducts([]);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setN8nConfigError(false);
    setIsReportModalOpen(true);

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90000); 

      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        mode: 'cors',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts.slice(0, 80), 
          timestamp: new Date().toISOString()
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);

      // Leemos el texto primero para evitar el error de JSON vacío
      const responseText = await response.text();

      if (!response.ok) {
        let errorMessage = "Fallo en el servidor n8n.";
        try {
          const errorObj = JSON.parse(responseText);
          errorMessage = errorObj.message || errorMessage;
        } catch(e) { /* No es JSON */ }

        if (errorMessage.includes("Unused Respond to Webhook node")) {
          setN8nConfigError(true);
          throw new Error("n8n tiene un nodo de respuesta mal conectado.");
        }
        throw new Error(`Error ${response.status}: ${errorMessage}`);
      }

      if (!responseText) {
        throw new Error("n8n devolvió una respuesta vacía.");
      }

      try {
        const data = JSON.parse(responseText);
        // Validamos estructura mínima para evitar fallos de .map()
        setReportData({
          titulo: data.titulo || "Informe de Inteligencia",
          resumen: data.resumen || "Análisis de datos procesado.",
          secciones: Array.isArray(data.secciones) ? data.secciones : [],
          recomendaciones: Array.isArray(data.recomendaciones) ? data.recomendaciones : []
        });
      } catch (e) {
        // Si no es JSON, lo tratamos como texto plano/Markdown
        setReportData({
          titulo: "Informe de Inteligencia (Texto)",
          resumen: "Análisis generado por IA.",
          secciones: [{
            tag: "INFO",
            titulo: "Análisis Detallado",
            contenido: responseText,
            estado: "info"
          }],
          recomendaciones: ["Verificar logs en n8n para salida JSON"]
        });
      }
    } catch (error: any) {
      console.error("❌ Detalle del Error:", error);
      setReportError(error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0 || user.role !== 'GERENTE') return null;

    // 1. Producto Estrella
    const estrella = [...rawProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    // 2. Mayor Stock Físico
    const mayorStockProd = [...rawProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // 3. Sede Líder
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = rawProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede };
    });
    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];

    // 4. Stock Crítico
    const critico = [...rawProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // 5. Categoría Líder
    const catGroups: Record<string, number> = {};
    rawProducts.forEach(p => {
      const cat = p.tipo || 'Otros';
      catGroups[cat] = (catGroups[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catGroups).sort((a, b) => b[1] - a[1])[0];

    // 6. Margen Bruto
    const totalVenta = rawProducts.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = rawProducts.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);
    const margenBruto = totalVenta > 0 ? ((totalVenta - totalCosto) / totalVenta) * 100 : 0;

    return {
      estrella: { ref: estrella?.referencia, nombre: estrella?.nombre, valor: ((estrella?.precioVenta || 0) * (estrella?.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd?.referencia, nombre: mayorStockProd?.nombre, cantidad: mayorStockProd?.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta?.name.replace(/^[0-9].\s*/, ''), monto: (sedeLiderVenta?.totalVenta || 0).toLocaleString() },
      critico: { ref: critico?.referencia, nombre: critico?.nombre, info: critico?.stock?.total || 0 },
      topCategoria: { name: topCat ? topCat[0] : 'Otros', cantidad: topCat ? topCat[1] : 0 },
      margen: { valor: Math.round(margenBruto) }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={handleGenerateReport}
              disabled={isGeneratingReport}
              className="hidden md:flex items-center gap-2 bg-gradient-to-r from-indigo-600 to-violet-600 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all disabled:opacity-50"
            >
