import React, { useState, useEffect } from 'react';
import { AuthState, SedeId, User, UserRole } from './types';
import { STORAGE_KEYS, GAS_WEB_APP_URL } from './constants';
import { Input, Button } from './components/UI';
import { Dashboard } from './components/Dashboard';

const App: React.FC = () => {
  const [authState, setAuthState] = useState<AuthState>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.AUTH);
    return saved ? JSON.parse(saved) : { user: null, isAuthenticated: false };
  });

  const [loginForm, setLoginForm] = useState({ email: '', password: '' });
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    localStorage.setItem(STORAGE_KEYS.AUTH, JSON.stringify(authState));
  }, [authState]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!GAS_WEB_APP_URL || GAS_WEB_APP_URL.includes('EJEMPLO')) {
      setError('Configuración incompleta: URL de Google Sheets no válida.');
      setIsLoading(false);
      return;
    }

    try {
      const response = await fetch(`${GAS_WEB_APP_URL}?action=GET_ALL`);
      if (!response.ok) throw new Error("Error de conexión con Google Sheets.");

      const data = await response.json();
      const usersTable = data.usuarios || [];

      if (!Array.isArray(usersTable) || usersTable.length === 0) {
        throw new Error("No se encontraron usuarios en la pestaña 'Usuarios' de tu Excel.");
      }

      // Función ultra-flexible para obtener valores sin importar mayúsculas o espacios en los headers
      const getFlexibleValue = (obj: any, aliases: string[]) => {
        if (!obj) return null;
        const keys = Object.keys(obj);
        for (const alias of aliases) {
          const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
          if (foundKey !== undefined) return obj[foundKey];
        }
        return null;
      };

      const foundUser = usersTable.find((u: any) => {
        if (!u) return false;
        // Limpieza profunda de valores para comparación
        const emailInSheet = String(getFlexibleValue(u, ['Correo', 'Email', 'Usuario', 'ID', 'Login']) || '').trim().toLowerCase();
        const passInSheet = String(getFlexibleValue(u, ['Contraseña', 'Contrasena', 'Password', 'Clave', 'Pass']) || '').trim();

        return emailInSheet === loginForm.email.trim().toLowerCase() && 
               passInSheet === loginForm.password.trim();
      });

      if (!foundUser) {
        console.warn("Intento fallido. Usuarios recibidos:", usersTable);
        throw new Error("Credenciales no encontradas. Revisa que el usuario y la clave coincidan exactamente con tu Excel (Pestaña Usuarios).");
      }

      const userData: User = {
        id: String(getFlexibleValue(foundUser, ['Correo', 'Email', 'ID', 'Usuario']) || Date.now().toString()),
        username: String(getFlexibleValue(foundUser, ['Nombre', 'Name', 'Usuario']) || 'Usuario'),
        sedeId: String(getFlexibleValue(foundUser, ['Sede', 'Tienda', 'Local']) || '').toLowerCase().trim().replace(/^[0-9].\s*/, '') as SedeId,
        role: String(getFlexibleValue(foundUser, ['Perfil', 'Rol', 'Role']) || 'OPERADOR').toUpperCase().trim() as UserRole,
        name: String(getFlexibleValue(foundUser, ['Nombre', 'Name']) || 'Usuario')
      };

      setAuthState({ user: userData, isAuthenticated: true });
    } catch (err: any) {
      console.error("Login Error:", err);
      setError(err.message || 'Error inesperado al intentar entrar.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    setAuthState({ user: null, isAuthenticated: false });
  };

  if (authState.isAuthenticated && authState.user) {
    return <Dashboard user={authState.user} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="w-full max-w-md bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200 border border-slate-100 overflow-hidden">
        <div className="bg-indigo-600 p-10 text-white text-center">
          <div className="bg-white/20 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 backdrop-blur-md">
             <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2-2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z"></path></svg>
          </div>
          <h2 className="text-3xl font-black uppercase tracking-tighter">Yeilu Store</h2>
          <p className="text-indigo-100 mt-2 font-bold tracking-widest text-[10px] uppercase opacity-80">Inventory Intelligence v2.3</p>
        </div>

        <form onSubmit={handleLogin} className="p-10 space-y-6">
          {error && (
            <div className="bg-rose-50 border border-rose-100 text-rose-600 text-[11px] font-black p-4 rounded-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-2">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"></path></svg>
              {error}
            </div>
          )}

          <div className="space-y-4">
            <Input 
              label="Usuario o Correo" 
              type="text"
              placeholder="Ej: admintaller" 
              value={loginForm.email}
              onChange={e => setLoginForm(prev => ({ ...prev, email: e.target.value }))}
              required
              className="rounded-xl py-3"
            />
            <Input 
              label="Contraseña" 
              type="password" 
              placeholder="••••••••" 
              value={loginForm.password}
              onChange={e => setLoginForm(prev => ({ ...prev, password: e.target.value }))}
              required
              className="rounded-xl py-3"
            />
          </div>

          <Button type="submit" fullWidth disabled={isLoading} className="py-4 text-[11px] font-black uppercase tracking-widest shadow-xl shadow-indigo-100 rounded-2xl">
            {isLoading ? (
              <span className="flex items-center gap-3">
                <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Sincronizando...
              </span>
            ) : 'Iniciar Sesión'}
          </Button>

          <div className="pt-8 border-t border-slate-50 text-center">
            <p className="text-[9px] text-slate-400 uppercase tracking-[0.2em] font-black leading-relaxed">
              VINCULADO A GOOGLE SHEETS<br/>
              TABLA: "Usuarios"
            </p>
          </div>
        </form>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { User, MaestroProducto, SedeId, MovementType } from '../types';
import { SEDES, PRODUCT_CATEGORIES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: any[]; // Cambiado a any[] para manejar objetos de n8n
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isListening, setIsListening] = useState(false);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);
  const [n8nConfigError, setN8nConfigError] = useState(false);

  const [movForm, setMovForm] = useState<{
    reference: string;
    quantity: number;
    type: MovementType;
    destSede: SedeId | '';
    notes: string;
  }>({ 
    reference: '', 
    quantity: 1, 
    type: 'SALIDA', 
    destSede: '', 
    notes: '' 
  });

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      } else {
        setRawProducts([]);
      }
    } catch (error) {
      console.error("Error n8n:", error);
      setRawProducts([]);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleGenerateReport = async () => {
    setIsGeneratingReport(true);
    setReportError(null);
    setReportData(null);
    setN8nConfigError(false);
    setIsReportModalOpen(true);

    try {
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 90000); 

      const response = await fetch(N8N_WEBHOOKS.INFORME_IA, {
        method: 'POST',
        mode: 'cors',
        headers: { 
          'Content-Type': 'application/json',
          'Accept': 'application/json'
        },
        body: JSON.stringify({
          usuario: user.username,
          sede: filterSede,
          data: rawProducts.slice(0, 80), 
          timestamp: new Date().toISOString()
        }),
        signal: controller.signal
      });

      clearTimeout(timeoutId);
      const responseText = await response.text();

      if (!response.ok) {
        let errorMessage = "Fallo en el servidor n8n.";
        try {
          const errorObj = JSON.parse(responseText);
          errorMessage = errorObj.message || errorMessage;
        } catch(e) {}

        if (errorMessage.includes("Unused Respond to Webhook node")) {
          setN8nConfigError(true);
          throw new Error("n8n tiene un problema con el nodo de respuesta.");
        }
        throw new Error(`Error ${response.status}: ${errorMessage}`);
      }

      if (!responseText || responseText.trim() === "") {
        throw new Error("El servidor n8n devolvió una respuesta vacía.");
      }

      try {
        const data = JSON.parse(responseText);
        setReportData({
          titulo: data.titulo || "Informe de Inteligencia",
          resumen: data.resumen || "Análisis financiero detallado.",
          secciones: Array.isArray(data.secciones) ? data.secciones : [],
          recomendaciones: Array.isArray(data.recomendaciones) ? data.recomendaciones : []
        });
      } catch (e) {
        setReportData({
          titulo: "Informe de Inteligencia (Texto)",
          resumen: "Análisis generado por IA.",
          secciones: [{
            tag: "IA",
            titulo: "Análisis",
            contenido: responseText,
            estado: "info"
          }],
          recomendaciones: []
        });
      }
    } catch (error: any) {
      console.error("❌ Detalle del Error:", error);
      setReportError(error.message);
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0 || user.role !== 'GERENTE') return null;

    const safeProducts = rawProducts.filter(p => p && p.referencia);
    if (safeProducts.length === 0) return null;

    // 1. Producto Estrella
    const estrella = [...safeProducts].sort((a, b) => 
      ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0))
    )[0];

    // 2. Mayor Stock Físico
    const mayorStockProd = [...safeProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // 3. Sede Líder
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = safeProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede };
    });
    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];

    // 4. Stock Crítico
    const critico = [...safeProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // 5. Categoría Líder
    const catGroups: Record<string, number> = {};
    safeProducts.forEach(p => {
      const cat = p.tipo || 'Otros';
      catGroups[cat] = (catGroups[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catGroups).sort((a, b) => b[1] - a[1])[0];

    // 6. Margen Bruto
    const totalVenta = safeProducts.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safeProducts.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);
    const margenBruto = totalVenta > 0 ? ((totalVenta - totalCosto) / totalVenta) * 100 : 0;

    return {
      estrella: { ref: estrella?.referencia, nombre: estrella?.nombre || 'Producto', valor: ((estrella?.precioVenta || 0) * (estrella?.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd?.referencia, nombre: mayorStockProd?.nombre || 'Producto', cantidad: mayorStockProd?.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta?.name?.replace(/^[0-9].\s*/, '') || 'Sin Datos', monto: (sedeLiderVenta?.totalVenta || 0).toLocaleString() },
      critico: { ref: critico?.referencia, nombre: critico?.nombre || 'Producto', info: critico?.stock?.total || 0 },
      topCategoria: { name: topCat ? topCat[0] : 'Otros', cantidad: topCat ? topCat[1] : 0 },
      margen: { valor: Math.round(margenBruto) }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  const handleVoiceInput = async () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return alert("Navegador no compatible.");
    const recognition = new SpeechRecognition();
    recognition.lang = 'es-ES';
    setIsListening(true);
    recognition.onresult = async (event: any) => {
      const transcript = event.results[0][0].transcript;
      setIsListening(false);
      try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: `Instrucción: "${transcript}". Extrae referencia, cantidad y tipo (ENTRADA, SALIDA). JSON format.`,
          config: { responseMimeType: "application/json" }
        });
        const data = JSON.parse(response.text);
        setMovForm({ reference: data.reference || '', quantity: data.quantity || 1, type: (data.type as MovementType) || 'SALIDA', destSede: '', notes: 'Voz AI' });
        setIsMovModalOpen(true);
      } catch (e) { console.error(e); }
    };
    recognition.start();
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return;
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { setIsMovModalOpen(false); loadData(); }
    } catch (e) { console.error(e); } finally { setIsSubmitting(false); }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {isQRVisible && <QRScanner onScan={(ref) => { setMovForm({...movForm, reference: ref}); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
