              <div className="bg-rose-50 text-rose-600 p-6 rounded-[2rem] border border-rose-100 inline-block text-left">
                <svg className="w-12 h-12 mx-auto mb-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <h4 className="text-sm font-black uppercase mb-2 text-center">Error de Conexión</h4>
