import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: any[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // AI Report State
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [reportError, setReportError] = useState<string | null>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("La referencia es obligatoria", "error");
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { 
        showNotify("Movimiento registrado con éxito");
        setIsMovModalOpen(false); 
        loadData(); 
      } else {
        throw new Error();
      }
    } catch (e) { 
      showNotify("Error al registrar movimiento", "error");
    } finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Faltan datos obligatorios", "error");
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (response.ok) {
        showNotify("Ingreso al inventario exitoso");
        setIsIngresoModalOpen(false);
        setIngresoForm({ referencia: '', cantidad: 1, costo_unitario: 0, precio_venta: 0, stock_minimo: 5, imagen: null });
        loadData();
      } else {
        throw new Error();
      }
    } catch (e) {
      showNotify("Error al ingresar producto", "error");
    } finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Todos los campos son obligatorios", "error");
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (response.ok) {
        showNotify("Usuario creado correctamente");
        setIsUserModalOpen(false);
        setUserForm({ nombre: '', correo: '', password: '', perfil: 'OPERADOR', sede: 'taller' });
      } else {
        throw new Error();
      }
    } catch (e) {
      showNotify("Error al crear el usuario", "error");
    } finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setIngresoForm(prev => ({ ...prev, imagen: reader.result as string }));
        showNotify("Imagen cargada y lista");
      };
      reader.readAsDataURL(file);
    }
  };

  const executiveInsights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0 || user.role !== 'GERENTE') return null;
    const safeProducts = rawProducts.filter(p => p && p.referencia);
    if (safeProducts.length === 0) return null;

    const estrella = [...safeProducts].sort((a, b) => ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0)))[0];
    const mayorStockProd = [...safeProducts].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      const totalVentaSede = safeProducts.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0);
      return { id: s.id, name: s.name, totalVenta: totalVentaSede };
    });
    const sedeLiderVenta = [...sedesData].sort((a, b) => b.totalVenta - a.totalVenta)[0];
    const critico = [...safeProducts].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];
    const totalVenta = safeProducts.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safeProducts.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);
    const margenBruto = totalVenta > 0 ? ((totalVenta - totalCosto) / totalVenta) * 100 : 0;

    return {
      estrella: { ref: estrella?.referencia, nombre: estrella?.nombre || 'Producto', valor: ((estrella?.precioVenta || 0) * (estrella?.stock?.total || 0)).toLocaleString() },
      mayorStockProd: { ref: mayorStockProd?.referencia, nombre: mayorStockProd?.nombre || 'Producto', cantidad: mayorStockProd?.stock?.total || 0 },
      sedeLiderVenta: { name: sedeLiderVenta?.name?.replace(/^[0-9].\s*/, '') || 'Sin Datos', monto: (sedeLiderVenta?.totalVenta || 0).toLocaleString() },
      critico: { ref: critico?.referencia, nombre: critico?.nombre || 'Producto', info: critico?.stock?.total || 0 },
      margen: { valor: Math.round(margenBruto) }
    };
  }, [rawProducts, user.role]);

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {/* Notificaciones de Confirmación */}
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          <div className="bg-white/20 p-1.5 rounded-full">
            {notification.type === 'success' ? (
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
            ) : (
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
            )}
          </div>
          <span className="text-xs font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(decodedText) => { 
            try {
              const data = JSON.parse(decodedText);
              setMovForm(prev => ({ ...prev, reference: (data.ref || data.reference || decodedText).toUpperCase(), notes: data.notes || prev.notes }));
            } catch (e) {
              setMovForm(prev => ({ ...prev, reference: decodedText.toUpperCase() }));
            }
            setIsQRVisible(false); 
            setIsMovModalOpen(true); 
          }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={() => setIsUserModalOpen(true)}
              className="hidden md:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" strokeWidth="2"/></svg>
              Crear Usuario
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round((allStockData || []).reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round((allStockData || []).reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && executiveInsights && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">Sede Líder</p>
                <h4 className="text-sm font-black text-slate-800 uppercase truncate">{executiveInsights.sedeLiderVenta.name}</h4>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-emerald-500 uppercase mb-3 tracking-widest">Estrella</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.estrella.nombre}</h4>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-rose-500 uppercase mb-3 tracking-widest">Crítico</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.critico.nombre}</h4>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">Volumen</p>
                <h4 className="text-sm font-black text-slate-800 truncate">{executiveInsights.mayorStockProd.cantidad} UND</h4>
              </div>
              <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                <p className="text-[9px] font-black text-violet-500 uppercase mb-3 tracking-widest">Margen</p>
                <h4 className="text-sm font-black text-slate-800 uppercase">{executiveInsights.margen.valor}%</h4>
              </div>
            </div>
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              <Select 
                value={filterSede} 
                onChange={e => setFilterSede(e.target.value as any)}
                options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                className="border-none font-black text-xs text-indigo-600 bg-transparent"
              />
            </div>
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg bg-emerald-600 text-white hover:bg-emerald-700 flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              Ingreso al Inventario
            </button>
            <Button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest">Movimiento de Stock</Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {(allStockData || []).sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL: MOVIMIENTO DE STOCK */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-slate-200 transition-all text-slate-600">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL: INGRESO AL INVENTARIO (CON FOTO) */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ INGRESO AL INVENTARIO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Stock Mínimo" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo Unitario ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Precio Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>

          <div className="pt-2">
            <label className="text-sm font-black text-slate-700 uppercase mb-2 block">Imagen del Producto</label>
            <div className="flex items-center gap-4 p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl overflow-hidden min-h-[100px] relative">
              {ingresoForm.imagen ? (
                <div className="relative w-full h-full flex flex-col items-center">
                  <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md border-2 border-white" alt="Vista previa" />
                  <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="mt-2 text-[10px] font-black text-rose-500 uppercase tracking-tighter">Eliminar y cambiar</button>
                </div>
              ) : (
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="flex flex-col items-center justify-center w-full gap-2 text-slate-400 hover:text-indigo-600 transition-all"
                >
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
                  <span className="text-[10px] font-black uppercase tracking-widest">Subir o Tomar Foto</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsIngresoModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>{isSubmitting ? 'Subiendo...' : 'Confirmar'}</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: CREACIÓN DE USUARIOS (SÓLO GERENTE) */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR NUEVO USUARIO">
        <div className="space-y-4">
          <Input label="Nombre Completo" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo Electrónico" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Contraseña" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />

          <div className="grid grid-cols-2 gap-4">
            <Select 
              label="Perfil" 
              value={userForm.perfil} 
              onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})}
              options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]}
            />
            <Select 
              label="Sede Asignada" 
              value={userForm.sede} 
              onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})}
              options={SEDES.map(s => ({value: s.id, label: s.name}))}
            />
          </div>

          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsUserModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>{isSubmitting ? 'Creando...' : 'Crear Usuario'}</Button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import { Sede } from './types';

/**
 * CONFIGURACIÓN n8n
 */
export const N8N_WEBHOOKS = {
  CONSULTA_GLOBAL: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/consulta-inventario',
  REGISTRO_MOVIMIENTO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/movimiento',
  GESTION_MAESTRO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/producto-nuevo',
  PRODUCTO_CON_IMAGEN: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/producto-con-imagen',
  CREAR_USUARIO: 'https://icad-n8n.ltubgr.easypanel.host/webhook/api/crear-usuario',
  INFORME_IA: 'https://icad-n8n.ltubgr.easypanel.host/webhook/692386ed-2848-4323-a6d4-1f2f7a5f0349'
};

export const GAS_WEB_APP_URL = 'https://script.google.com/macros/s/AKfycbzYf1o2Q0DNm2hGPksEYP8GQ5nOhVRt48mnDp41n6igS5mdq3uezQA40BRQWvIYjQlVnA/exec';

export const SEDES: Sede[] = [
  { id: 'taller', name: '1. Taller' },
  { id: 'country', name: '2. Country' },
  { id: 'plaza_sol', name: '3. Plaza del Sol' },
  { id: 'portal_prado', name: '4. Portal del Prado' },
  { id: 'centro', name: '5. Centro' }
];

export const PRODUCT_CATEGORIES = [
  'Vestidos',
  'Blusas / Tops',
  'Pantalones / Jeans',
  'Faldas',
  'Chaquetas / Abrigos',
  'Calzado',
  'Accesorios',
  'Lencería / Intima',
  'Vestidos de Baño'
];

export const STORAGE_KEYS = {
  AUTH: 'yeilu_auth_state',
  CACHED_DATA: 'yeilu_cached_data',
  MOVEMENTS: 'yeilu_movements_data'
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  // Modals
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Forms
  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) {
      showNotify("La referencia es obligatoria", "error");
      return;
    }
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (response.ok) { 
        showNotify("Movimiento registrado con éxito");
        setIsMovModalOpen(false); 
        loadData(); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
      } else {
        throw new Error();
      }
    } catch (e) { 
      showNotify("Error al registrar movimiento", "error");
    } finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) {
      showNotify("La referencia es obligatoria", "error");
      return;
    }
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (response.ok) {
        showNotify("Producto ingresado al inventario con éxito");
        setIsIngresoModalOpen(false);
        setIngresoForm({ referencia: '', cantidad: 1, costo_unitario: 0, precio_venta: 0, stock_minimo: 5, imagen: null });
        loadData();
      } else {
        throw new Error();
      }
    } catch (e) {
      showNotify("Error al ingresar producto", "error");
    } finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre || !userForm.password) {
      showNotify("Todos los campos son obligatorios", "error");
      return;
    }
    setIsSubmitting(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (response.ok) {
        showNotify("Usuario creado correctamente");
        setIsUserModalOpen(false);
        setUserForm({ nombre: '', correo: '', password: '', perfil: 'OPERADOR', sede: 'taller' });
      } else {
        throw new Error();
      }
    } catch (e) {
      showNotify("Error al crear el usuario", "error");
    } finally { setIsSubmitting(true); setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setIngresoForm(prev => ({ ...prev, imagen: reader.result as string }));
        showNotify("Imagen cargada correctamente");
      };
      reader.readAsDataURL(file);
    }
  };

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {/* Sistema de Notificaciones */}
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-rose-600 text-white'}`}>
          <div className="bg-white/20 p-1.5 rounded-full">
            {notification.type === 'success' ? (
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
            ) : (
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
            )}
          </div>
          <span className="text-xs font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(decodedText) => { 
            try {
              const data = JSON.parse(decodedText);
              setMovForm(prev => ({ ...prev, reference: (data.ref || data.reference || decodedText).toUpperCase(), notes: data.notes || prev.notes }));
            } catch (e) {
              setMovForm(prev => ({ ...prev, reference: decodedText.toUpperCase() }));
            }
            setIsQRVisible(false); 
            setIsMovModalOpen(true); 
          }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button 
              onClick={() => setIsUserModalOpen(true)}
              className="hidden md:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z" strokeWidth="2"/></svg>
              Crear Usuario
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round((allStockData || []).reduce((acc, s) => acc + (s.Costo * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round((allStockData || []).reduce((acc, s) => acc + (s.Venta * s.Stock_Actual), 0)).toLocaleString()}</h2>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <div className="bg-white p-2 rounded-2xl border border-slate-100 shadow-sm inline-flex">
              <Select 
                value={filterSede} 
                onChange={e => setFilterSede(e.target.value as any)}
                options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
                className="border-none font-black text-xs text-indigo-600 bg-transparent"
              />
            </div>
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button 
              onClick={() => setIsIngresoModalOpen(true)} 
              className="flex-1 md:flex-none p-4 rounded-2xl transition-all shadow-lg bg-emerald-600 text-white hover:bg-emerald-700 flex items-center justify-center gap-3 font-black text-[10px] uppercase tracking-widest"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              Ingreso al Inventario
            </button>
            <Button 
              onClick={() => setIsMovModalOpen(true)} 
              className="flex-1 md:flex-none py-4 px-6 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg"
            >
              Movimiento de Stock
            </Button>
          </div>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 border border-slate-100 overflow-hidden">
          <div className="p-8 border-b border-slate-50 flex justify-between items-center bg-slate-50/20">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest">Inventario Real-Time</h3>
            <button onClick={loadData} className="p-2 hover:bg-slate-100 rounded-full transition-all">
              <svg className={`w-5 h-5 text-slate-400 ${isLoading ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg>
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] border-b border-slate-50">
                  <th className="px-8 py-6">Referencia</th>
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6 text-center">Stock</th>
                  <th className="px-8 py-6 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {(allStockData || []).sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={`${s.Codigo}-${idx}`} className="hover:bg-slate-50 transition-all">
                    <td className="px-8 py-6 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-6">
                      <div className="text-[11px] font-black uppercase text-slate-800">{s.Descripcion}</div>
                      <div className="text-[9px] font-bold text-slate-400 uppercase mt-1">{s.Categoria}</div>
                    </td>
                    <td className="px-8 py-6 text-center">
                      <span className={`px-4 py-1.5 rounded-full font-black text-[10px] ${s.Stock_Actual <= (s.Stock_Minimo || 5) ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                        {s.Stock_Actual} UND
                      </span>
                    </td>
                    <td className="px-8 py-6 text-right font-black text-slate-700 text-xs">${Math.round(s.Venta * s.Stock_Actual).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL: MOVIMIENTO DE STOCK */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-slate-200 transition-all text-slate-600 flex items-center justify-center">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select 
               label="Tipo" 
               value={movForm.type} 
               onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} 
               options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} 
             />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Acción cancelada"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL: INGRESO AL INVENTARIO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ INGRESO AL INVENTARIO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Stock Mínimo" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo Unitario ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Precio Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>

          <div className="pt-2">
            <label className="text-sm font-black text-slate-700 uppercase mb-2 block">Imagen del Producto</label>
            <div className="flex flex-col items-center gap-4 p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl overflow-hidden min-h-[140px] relative">
              {ingresoForm.imagen ? (
                <div className="relative w-full flex flex-col items-center">
                  <img src={ingresoForm.imagen} className="w-24 h-24 object-cover rounded-xl shadow-md border-2 border-white mb-2" alt="Vista previa" />
                  <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[10px] font-black text-rose-500 uppercase tracking-tighter hover:underline">Eliminar imagen</button>
                </div>
              ) : (
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="flex flex-col items-center justify-center w-full h-full gap-2 text-slate-400 hover:text-indigo-600 transition-all py-4"
                >
                  <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"/></svg>
                  <span className="text-[10px] font-black uppercase tracking-widest">Tomar Foto o Cargar</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => { setIsIngresoModalOpen(false); showNotify("Acción cancelada"); }}>Cancelar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>{isSubmitting ? 'Procesando...' : 'Confirmar'}</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: CREACIÓN DE USUARIOS */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR NUEVO USUARIO">
        <div className="space-y-4">
          <Input label="Nombre Completo" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo Electrónico" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Contraseña" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />

          <div className="grid grid-cols-2 gap-4">
            <Select 
              label="Perfil" 
              value={userForm.perfil} 
              onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})}
              options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]}
            />
            <Select 
              label="Sede Asignada" 
              value={userForm.sede} 
              onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})}
              options={SEDES.map(s => ({value: s.id, label: s.name}))}
            />
          </div>

          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => { setIsUserModalOpen(false); showNotify("Acción cancelada"); }}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>{isSubmitting ? 'Creando...' : 'Crear Usuario'}</Button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  // Modals
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Forms
  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
      showNotify("Error al sincronizar datos", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  // INDICADORES EJECUTIVOS (Restaurados)
  const insights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0) return null;
    const safe = rawProducts.filter(p => p && p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);
    const estrella = [...safe].sort((a, b) => ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0)))[0];
    const critico = [...safe].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { name: s.name, total: safe.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0) };
    });
    const lider = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      estrella: estrella?.nombre || 'N/A',
      critico: critico?.nombre || 'N/A',
      lider: lider?.name.replace(/^[0-9].\s*/, '') || 'N/A'
    };
  }, [rawProducts]);

  const handleGenerateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario de moda y genera un reporte estratégico en JSON. 
      Datos: ${JSON.stringify(rawProducts.slice(0, 20))}
      Responde SOLO el JSON con esta estructura:
      { "titulo": "string", "resumen": "string", "secciones": [{ "tag": "string", "titulo": "string", "contenido": "string", "estado": "success|warning|danger" }], "recomendaciones": ["string"] }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt
      });

      const text = response.text || "{}";
      const cleanJson = text.replace(/```json|```/g, "").trim();
      setReportData(JSON.parse(cleanJson));
      showNotify("Informe IA generado con éxito");
    } catch (e) {
      console.error(e);
      showNotify("Error al generar reporte con IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Referencia obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) {
        showNotify("Movimiento guardado");
        setIsMovModalOpen(false);
        loadData();
      } else throw new Error();
    } catch { showNotify("Error al guardar movimiento", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Referencia obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) {
        showNotify("Producto ingresado correctamente");
        setIsIngresoModalOpen(false);
        setIngresoForm({ referencia: '', cantidad: 1, costo_unitario: 0, precio_venta: 0, stock_minimo: 5, imagen: null });
        loadData();
      } else throw new Error();
    } catch { showNotify("Error al ingresar producto", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Datos incompletos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) {
        showNotify("Usuario creado");
        setIsUserModalOpen(false);
      } else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setIngresoForm(prev => ({ ...prev, imagen: reader.result as string }));
        showNotify("Imagen cargada y confirmada", "info");
      };
      reader.readAsDataURL(file);
    }
  };

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-slate-50 font-sans pb-10">
      {/* Sistema de Notificaciones */}
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(decodedText) => { 
            setMovForm(prev => ({ ...prev, reference: decodedText.toUpperCase() }));
            setIsQRVisible(false); 
            setIsMovModalOpen(true); 
            showNotify("Código QR detectado");
          }} 
          onClose={() => { setIsQRVisible(false); showNotify("Escáner cerrado", "info"); }} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="hidden md:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all">
              Crear Usuario
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-4 lg:p-8 space-y-8">
        {/* Indicadores Financieros */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2.5rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {/* Panel de Insights (Restaurado para Gerentes) */}
        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 md:grid-cols-5 gap-4">
             <div className="p-5 bg-white rounded-3xl border border-slate-100 shadow-sm">
                <p className="text-[8px] font-black text-indigo-500 uppercase mb-2">Sede Líder</p>
                <p className="text-xs font-black text-slate-800 truncate">{insights.lider}</p>
             </div>
             <div className="p-5 bg-white rounded-3xl border border-slate-100 shadow-sm">
                <p className="text-[8px] font-black text-emerald-500 uppercase mb-2">Estrella</p>
                <p className="text-xs font-black text-slate-800 truncate">{insights.estrella}</p>
             </div>
             <div className="p-5 bg-white rounded-3xl border border-slate-100 shadow-sm">
                <p className="text-[8px] font-black text-rose-500 uppercase mb-2">Crítico</p>
                <p className="text-xs font-black text-slate-800 truncate">{insights.critico}</p>
             </div>
             <div className="p-5 bg-white rounded-3xl border border-slate-100 shadow-sm">
                <p className="text-[8px] font-black text-violet-500 uppercase mb-2">Margen</p>
                <p className="text-xs font-black text-slate-800 uppercase">{insights.margen}%</p>
             </div>
             <div className="col-span-2 md:col-span-1">
                <button onClick={handleGenerateAIReport} className="w-full h-full p-4 bg-gradient-to-br from-indigo-500 to-purple-600 text-white rounded-3xl font-black text-[9px] uppercase tracking-widest shadow-lg hover:scale-[1.02] transition-all flex flex-col items-center justify-center gap-1">
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                   Informe IA
                </button>
             </div>
          </section>
        )}

        {/* Acciones Principales */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="flex-1 w-full">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 VISTA GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.toUpperCase()}`}))]}
              className="font-black text-xs text-indigo-600 bg-white shadow-sm p-4 rounded-2xl"
            />
          </div>
          <div className="flex gap-2 w-full md:w-auto">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 md:flex-none p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              Ingreso Inventario
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 md:flex-none p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg">
              Movimiento de Stock
            </button>
          </div>
        </div>

        {/* Tabla de Inventario */}
        <div className="bg-white rounded-[2.5rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-8 border-b flex justify-between items-center">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock en Tiempo Real</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Producto</th>
                  <th className="px-8 py-5 text-center">Stock</th>
                  <th className="px-8 py-5 text-right">Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50">
                    <td className="px-8 py-5 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-8 py-5 font-bold text-[11px] text-slate-700">{s.Descripcion}</td>
                    <td className="px-8 py-5 text-center">
                       <span className={`px-3 py-1 rounded-full text-[9px] font-black ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{s.Stock_Actual} UND</span>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-slate-700 text-[11px]">${Math.round(s.Venta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL: MOVIMIENTO (QR ICON) */}
      <Modal isOpen={isMovModalOpen} onClose={() => { setIsMovModalOpen(false); showNotify("Acción cancelada", "info"); }} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-slate-200 transition-all text-slate-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Movimiento cancelado", "info"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL: INGRESO (FOTO) */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => { setIsIngresoModalOpen(false); showNotify("Acción cancelada", "info"); }} title="✨ INGRESO DE PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Stock Mínimo" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo Unitario ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Precio Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <label className="text-xs font-black text-slate-700 uppercase mb-2 block">Imagen</label>
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative">
                   <img src={ingresoForm.imagen} className="w-20 h-20 mx-auto object-cover rounded-xl" />
                   <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[9px] font-black text-rose-500 mt-2">Eliminar</button>
                </div>
              ) : (
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 text-slate-400 py-4 w-full">
                  <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"/></svg>
                  <span className="text-[9px] font-black uppercase">Tomar Foto / Subir</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => { setIsIngresoModalOpen(false); showNotify("Ingreso cancelado", "info"); }}>Cancelar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Confirmar</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: USUARIO */}
      <Modal isOpen={isUserModalOpen} onClose={() => { setIsUserModalOpen(false); showNotify("Acción cancelada", "info"); }} title="👤 CREAR USUARIO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Contraseña" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Perfil" value={userForm.perfil} onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})} options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]} />
            <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => { setIsUserModalOpen(false); showNotify("Cancelado", "info"); }}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: REPORTE IA */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🤖 INTELIGENCIA ESTRATÉGICA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Analizando Inventario...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6">
             <div className="bg-indigo-50 p-6 rounded-3xl">
                <h4 className="text-sm font-black text-indigo-900 uppercase mb-2">{reportData.titulo}</h4>
                <p className="text-xs text-indigo-700 leading-relaxed">{reportData.resumen}</p>
             </div>
             {reportData.secciones.map((sec, i) => (
                <div key={i} className={`p-5 rounded-3xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'}`}>
                   <h5 className="text-[10px] font-black uppercase mb-1">{sec.titulo}</h5>
                   <p className="text-xs opacity-80">{sec.contenido}</p>
                </div>
             ))}
             <div className="bg-slate-900 p-6 rounded-3xl text-white">
                <p className="text-[9px] font-black uppercase text-slate-500 mb-3">Recomendaciones</p>
                <ul className="space-y-2">
                   {reportData.recomendaciones.map((r, i) => <li key={i} className="text-xs flex gap-2"><span className="text-indigo-400">•</span> {r}</li>)}
                </ul>
             </div>
             <Button fullWidth onClick={() => setIsReportModalOpen(false)}>Cerrar Reporte</Button>
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  // Modals
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Forms
  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
      showNotify("Error al sincronizar datos", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0) return null;
    const safe = rawProducts.filter(p => p && p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);

    // Sede Líder
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { name: s.name.replace(/^[0-9].\s*/, ''), total: safe.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0) };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    // Producto Estrella (Mayor valor venta total)
    const estrella = [...safe].sort((a, b) => ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0)))[0];

    // Stock Crítico
    const critico = [...safe].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // Mayor Volumen (Cantidad de unidades)
    const volumen = [...safe].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // Categoría Top
    const catMap: Record<string, number> = {};
    safe.forEach(p => {
      const cat = p.tipo || 'Otros';
      catMap[cat] = (catMap[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catMap).sort((a,b) => b[1] - a[1])[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: { nombre: estrella?.nombre || 'N/A', ref: estrella?.referencia || '', valor: (estrella?.precioVenta || 0) * (estrella?.stock?.total || 0) },
      critico: { nombre: critico?.referencia || 'N/A', stock: critico?.stock?.total || 0 },
      volumen: { nombre: volumen?.nombre || 'N/A', stock: volumen?.stock?.total || 0 },
      categoria: { nombre: topCat?.[0] || 'N/A', stock: topCat?.[1] || 0 }
    };
  }, [rawProducts]);

  const handleGenerateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario y genera un reporte estratégico en JSON. 
      Datos: ${JSON.stringify(rawProducts.slice(0, 15))}
      Estructura JSON: { "titulo": "string", "resumen": "string", "secciones": [{ "tag": "string", "titulo": "string", "contenido": "string", "estado": "success|warning|danger" }], "recomendaciones": ["string"] }`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      const cleanJson = (response.text || "{}").replace(/```json|```/g, "").trim();
      setReportData(JSON.parse(cleanJson));
    } catch (e) {
      showNotify("Error en IA", "error");
      setIsReportModalOpen(false);
    } finally { setIsGeneratingReport(false); }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { showNotify("¡Movimiento registrado!"); setIsMovModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de conexión", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { showNotify("¡Producto ingresado!"); setIsIngresoModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de carga", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Faltan datos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) { showNotify("Usuario creado"); setIsUserModalOpen(false); }
      else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { setIngresoForm(p => ({ ...p, imagen: reader.result as string })); showNotify("Imagen lista", "info"); };
      reader.readAsDataURL(file);
    }
  };

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); showNotify("QR Sincronizado"); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="hidden md:flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all">Crear Usuario</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* Resumen General */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl relative overflow-hidden group">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl relative overflow-hidden group">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {/* PANEL DE CONTROL GERENCIAL (Diseño idéntico a la imagen) */}
        {user.role === 'GERENTE' && insights && (
          <section className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
              </div>
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              {/* Sede Líder */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏆</span>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">Sede Líder</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.lider.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1">${Math.round(insights.lider.valor).toLocaleString()}</p>
              </div>

              {/* Producto Estrella */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⭐</span>
                  <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Producto Estrella</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.estrella.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.estrella.ref} - ${Math.round(insights.estrella.valor).toLocaleString()}</p>
              </div>

              {/* Stock Crítico */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⚠️</span>
                  <p className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Stock Crítico</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.critico.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">Quedan: {insights.critico.stock} UND</p>
              </div>

              {/* Mayor Volumen */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📊</span>
                  <p className="text-[9px] font-black text-amber-500 uppercase tracking-widest">Mayor Volumen</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.volumen.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.volumen.stock} Unidades</p>
              </div>

              {/* Categoría Top */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏷️</span>
                  <p className="text-[9px] font-black text-sky-500 uppercase tracking-widest">Categoría Top</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.categoria.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.categoria.stock} UND Totales</p>
              </div>

              {/* Margen Bruto */}
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📈</span>
                  <p className="text-[9px] font-black text-violet-500 uppercase tracking-widest">Margen Bruto</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">Eficiencia</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.margen}% Estimado</p>
              </div>
            </div>
          </section>
        )}

        {/* Acciones e Informe IA */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white shadow-sm h-[52px] rounded-2xl px-4"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              Ingreso Inventario
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              Movimiento Stock
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={handleGenerateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                Informe IA
              </button>
            )}
          </div>
        </div>

        {/* Tabla Detallada */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventario en Tiempo Real</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 transition-all ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Stock Actual</th>
                  <th className="px-8 py-5 text-right">Valor Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-8 py-5 font-black text-[11px] text-indigo-600 group-hover:scale-105 transition-transform">{s.Codigo}</td>
                    <td className="px-8 py-5">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.Descripcion}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black tracking-tighter mt-1">{s.Categoria}</p>
                    </td>
                    <td className="px-8 py-5 text-center">
                       <span className={`px-4 py-1.5 rounded-full text-[9px] font-black ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>{s.Stock_Actual} UND</span>
                    </td>
                    <td className="px-8 py-5 text-right font-black text-slate-700 text-[11px]">${Math.round(s.Venta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL: MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => { setIsMovModalOpen(false); showNotify("Movimiento cancelado", "info"); }} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="ESCRIBE O ESCANEA..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 hover:text-indigo-600 transition-all text-slate-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Observaciones" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="OPCIONAL..." />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Cancelado", "info"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Cargando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL: INGRESO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => { setIsIngresoModalOpen(false); showNotify("Ingreso cancelado", "info"); }} title="✨ INGRESO DE PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <label className="text-[10px] font-black text-slate-700 uppercase mb-2 block">Evidencia Visual</label>
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative">
                   <img src={ingresoForm.imagen} className="w-24 h-24 mx-auto object-cover rounded-xl shadow-lg border-2 border-white" />
                   <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[9px] font-black text-rose-500 mt-2 uppercase">Cambiar Foto</button>
                </div>
              ) : (
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 text-slate-400 py-4 w-full group hover:text-indigo-600 transition-all">
                  <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  <span className="text-[9px] font-black uppercase tracking-widest">Tomar Foto o Subir</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsIngresoModalOpen(false)}>Cerrar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Ingresar Stock</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: USUARIO (SOLO GERENTE) */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Email" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Perfil" value={userForm.perfil} onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})} options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]} />
            <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name.replace(/^[0-9].\s*/, '')}))} />
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsUserModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear Usuario</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: REPORTE IA */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🤖 ESTRATEGIA CON IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Modelando Datos Estratégicos...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6">
             <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                <h4 className="text-sm font-black text-indigo-900 uppercase mb-2">{reportData.titulo}</h4>
                <p className="text-xs text-indigo-700 leading-relaxed font-medium">{reportData.resumen}</p>
             </div>
             <div className="grid gap-3">
               {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border-l-4 shadow-sm ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500 text-rose-900' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-emerald-50 border-emerald-500 text-emerald-900'}`}>
                     <h5 className="text-[10px] font-black uppercase mb-1 tracking-tight">{sec.titulo}</h5>
                     <p className="text-[11px] opacity-80 leading-snug">{sec.contenido}</p>
                  </div>
               ))}
             </div>
             <div className="bg-slate-900 p-6 rounded-[1.5rem] text-white shadow-xl">
                <p className="text-[9px] font-black uppercase text-slate-500 mb-3 tracking-[0.2em]">Hoja de Ruta / Recomendaciones</p>
                <ul className="space-y-3">
                   {reportData.recomendaciones.map((r, i) => (
                     <li key={i} className="text-[11px] flex gap-3 items-start">
                       <span className="text-indigo-400 font-black mt-1">→</span> 
                       <span className="font-medium opacity-90">{r}</span>
                     </li>
                   ))}
                </ul>
             </div>
             <Button fullWidth onClick={() => setIsReportModalOpen(false)}>Finalizar Análisis</Button>
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  // Modals
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Forms
  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }
    } catch (error) {
      console.error("Error n8n:", error);
      showNotify("Error al sincronizar datos", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0) return null;
    const safe = rawProducts.filter(p => p && p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);

    // Sede Líder
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { name: s.name.replace(/^[0-9].\s*/, ''), total: safe.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0) };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    // Producto Estrella (Mayor valor venta total)
    const estrella = [...safe].sort((a, b) => ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0)))[0];

    // Stock Crítico
    const critico = [...safe].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];

    // Mayor Volumen (Cantidad de unidades)
    const volumen = [...safe].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    // Categoría Top
    const catMap: Record<string, number> = {};
    safe.forEach(p => {
      const cat = p.tipo || 'Otros';
      catMap[cat] = (catMap[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catMap).sort((a,b) => b[1] - a[1])[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: { nombre: estrella?.nombre || 'N/A', ref: estrella?.referencia || '', valor: (estrella?.precioVenta || 0) * (estrella?.stock?.total || 0) },
      critico: { nombre: critico?.referencia || 'N/A', stock: critico?.stock?.total || 0 },
      volumen: { nombre: volumen?.nombre || 'N/A', stock: volumen?.stock?.total || 0 },
      categoria: { nombre: topCat?.[0] || 'N/A', stock: topCat?.[1] || 0 }
    };
  }, [rawProducts]);

  const handleGenerateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario y genera un reporte estratégico en JSON. 
      Datos: ${JSON.stringify(rawProducts.slice(0, 15))}
      Estructura JSON: { "titulo": "string", "resumen": "string", "secciones": [{ "tag": "string", "titulo": "string", "contenido": "string", "estado": "success|warning|danger" }], "recomendaciones": ["string"] }`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      const cleanJson = (response.text || "{}").replace(/```json|```/g, "").trim();
      setReportData(JSON.parse(cleanJson));
    } catch (e) {
      showNotify("Error en IA", "error");
      setIsReportModalOpen(false);
    } finally { setIsGeneratingReport(false); }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { showNotify("¡Movimiento registrado!"); setIsMovModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de conexión", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { showNotify("¡Producto ingresado!"); setIsIngresoModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de carga", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Faltan datos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) { showNotify("Usuario creado"); setIsUserModalOpen(false); }
      else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { setIngresoForm(p => ({ ...p, imagen: reader.result as string })); showNotify("Imagen lista", "info"); };
      reader.readAsDataURL(file);
    }
  };

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); showNotify("QR Sincronizado"); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="flex items-center gap-2 bg-slate-900 text-white px-3 md:px-4 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md">
              <span className="md:inline">Crear Usuario</span>
              <svg className="w-4 h-4 md:hidden" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* Resumen General */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl relative overflow-hidden group">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl relative overflow-hidden group">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {/* PANEL DE CONTROL GERENCIAL */}
        {user.role === 'GERENTE' && insights && (
          <section className="space-y-6">
            <div className="flex items-center gap-3">
              <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
              </div>
              <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Panel de Control Gerencial</h3>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏆</span>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">Sede Líder</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.lider.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1">${Math.round(insights.lider.valor).toLocaleString()}</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⭐</span>
                  <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Producto Estrella</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.estrella.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.estrella.ref} - ${Math.round(insights.estrella.valor).toLocaleString()}</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⚠️</span>
                  <p className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Stock Crítico</p>
