              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏷️</span>
                  <p className="text-[9px] font-black text-sky-500 uppercase tracking-widest">Categoría Top</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.categoria.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.categoria.stock} UND Totales</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📈</span>
                  <p className="text-[9px] font-black text-violet-500 uppercase tracking-widest">Margen Bruto</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">Eficiencia</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.margen}% Estimado</p>
              </div>
            </div>
          </section>
        )}

        {/* Acciones e Informe IA */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white shadow-sm h-[52px] rounded-2xl px-4"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={handleGenerateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-1 md:gap-2">
                <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        {/* Tabla Detallada */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock en Tiempo Real</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 transition-all ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5">REF</th>
                  <th className="px-4 md:px-8 py-5">Descripción</th>
                  <th className="px-4 md:px-8 py-5 text-center">Stock</th>
                  <th className="px-4 md:px-8 py-5 text-right">Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-4 md:px-8 py-4 md:py-5 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-4 md:px-8 py-4 md:py-5">
                      <p className="font-bold text-[10px] md:text-[11px] text-slate-700 uppercase">{s.Descripcion}</p>
                      <p className="text-[8px] md:text-[9px] text-slate-400 uppercase font-black tracking-tighter mt-0.5">{s.Categoria}</p>
                    </td>
                    <td className="px-2 md:px-8 py-4 md:py-5 text-center">
                       <span className={`inline-block px-3 py-1.5 rounded-full text-[9px] font-black whitespace-nowrap shadow-sm ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.Stock_Actual} UND
                       </span>
                    </td>
                    <td className="px-4 md:px-8 py-4 md:py-5 text-right font-black text-slate-700 text-[10px] md:text-[11px]">${Math.round(s.Venta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL: MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => { setIsMovModalOpen(false); showNotify("Movimiento cancelado", "info"); }} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="ESCRIBE O ESCANEA..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 hover:text-indigo-600 transition-all text-slate-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}]} />
           </div>
           <Input label="Observaciones" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="OPCIONAL..." />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Cancelado", "info"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Cargando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL: INGRESO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => { setIsIngresoModalOpen(false); showNotify("Ingreso cancelado", "info"); }} title="✨ INGRESO DE PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <label className="text-[10px] font-black text-slate-700 uppercase mb-2 block">Evidencia Visual</label>
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative">
                   <img src={ingresoForm.imagen} className="w-24 h-24 mx-auto object-cover rounded-xl shadow-lg border-2 border-white" />
                   <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[9px] font-black text-rose-500 mt-2 uppercase">Cambiar Foto</button>
                </div>
              ) : (
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 text-slate-400 py-4 w-full group hover:text-indigo-600 transition-all">
                  <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  <span className="text-[9px] font-black uppercase tracking-widest">Tomar Foto o Subir</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsIngresoModalOpen(false)}>Cerrar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Ingresar Stock</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: USUARIO */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Email" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Perfil" value={userForm.perfil} onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})} options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]} />
            <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name.replace(/^[0-9].\s*/, '')}))} />
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsUserModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear Usuario</Button>
          </div>
        </div>
      </Modal>

      {/* MODAL: REPORTE IA */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🤖 ESTRATEGIA CON IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Modelando Datos Estratégicos...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6">
             <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                <h4 className="text-sm font-black text-indigo-900 uppercase mb-2">{reportData.titulo}</h4>
                <p className="text-xs text-indigo-700 leading-relaxed font-medium">{reportData.resumen}</p>
             </div>
             <div className="grid gap-3">
               {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border-l-4 shadow-sm ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500 text-rose-900' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-emerald-50 border-emerald-500 text-emerald-900'}`}>
                     <h5 className="text-[10px] font-black uppercase mb-1 tracking-tight">{sec.titulo}</h5>
                     <p className="text-[11px] opacity-80 leading-snug">{sec.contenido}</p>
                  </div>
               ))}
             </div>
             <div className="bg-slate-900 p-6 rounded-[1.5rem] text-white shadow-xl">
                <p className="text-[9px] font-black uppercase text-slate-500 mb-3 tracking-[0.2em]">Hoja de Ruta / Recomendaciones</p>
                <ul className="space-y-3">
                   {reportData.recomendaciones.map((r, i) => (
                     <li key={i} className="text-[11px] flex gap-3 items-start">
                       <span className="text-indigo-400 font-black mt-1">→</span> 
                       <span className="font-medium opacity-90">{r}</span>
                     </li>
                   ))}
                </ul>
             </div>
             <Button fullWidth onClick={() => setIsReportModalOpen(false)}>Finalizar Análisis</Button>
          </div>
        )}
