                  <p className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Stock Crítico</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.critico.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">Quedan: {insights.critico.stock} UND</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📊</span>
                  <p className="text-[9px] font-black text-amber-500 uppercase tracking-widest">Mayor Volumen</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.volumen.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.volumen.stock} Unidades</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏷️</span>
                  <p className="text-[9px] font-black text-sky-500 uppercase tracking-widest">Categoría Top</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.categoria.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.categoria.stock} UND Totales</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📈</span>
                  <p className="text-[9px] font-black text-violet-500 uppercase tracking-widest">Margen Bruto</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">Eficiencia</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.margen}% Estimado</p>
              </div>
            </div>
          </section>
        )}

        {/* Registro de Verificación de Movimientos (Nueva sección) */}
        {recentMovements.length > 0 && (
          <div className="bg-white/40 p-6 rounded-3xl border border-dashed border-slate-200">
             <div className="flex items-center gap-2 mb-4">
                <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Sincronización de Movimientos Recientes</p>
             </div>
             <div className="flex gap-4 overflow-x-auto pb-2">
                {recentMovements.map((m, i) => (
                  <div key={i} className="bg-white p-3 rounded-2xl border border-slate-100 shadow-sm flex-shrink-0 min-w-[160px]">
                    <p className="text-[8px] font-black text-indigo-600 uppercase mb-1">{m.referencia}</p>
                    <div className="flex justify-between items-center">
                      <span className={`text-[8px] font-black px-2 py-0.5 rounded-full ${m.tipo === 'SALIDA' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>{m.tipo}</span>
                      <span className="text-[10px] font-black text-slate-700">{m.cantidad} UND</span>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        )}

        {/* Acciones */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white shadow-sm h-[52px] rounded-2xl px-4"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={handleGenerateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-1 md:gap-2">
                <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        {/* Tabla Detallada */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock en Tiempo Real</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 transition-all ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5">REF</th>
                  <th className="px-4 md:px-8 py-5">Descripción</th>
                  <th className="px-4 md:px-8 py-5 text-center">Stock</th>
                  <th className="px-4 md:px-8 py-5 text-right">Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-4 md:px-8 py-4 md:py-5 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-4 md:px-8 py-4 md:py-5">
                      <p className="font-bold text-[10px] md:text-[11px] text-slate-700 uppercase">{s.Descripcion}</p>
                      <p className="text-[8px] md:text-[9px] text-slate-400 uppercase font-black tracking-tighter mt-0.5">{s.Categoria}</p>
                    </td>
                    <td className="px-2 md:px-8 py-4 md:py-5 text-center">
                       <span className={`inline-block px-3 py-1.5 rounded-full text-[9px] font-black whitespace-nowrap shadow-sm ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.Stock_Actual} UND
                       </span>
                    </td>
                    <td className="px-4 md:px-8 py-4 md:py-5 text-right font-black text-slate-700 text-[10px] md:text-[11px]">${Math.round(s.Venta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODALES */}
      <Modal isOpen={isMovModalOpen} onClose={() => { setIsMovModalOpen(false); showNotify("Movimiento cancelado", "info"); }} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="ESCRIBE O ESCANEA..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 hover:text-indigo-600 transition-all text-slate-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}, {value: 'TRASLADO', label: 'Traslado'}]} />
           </div>
           <Input label="Observaciones" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="OPCIONAL..." />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Cancelado", "info"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Cargando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => { setIsIngresoModalOpen(false); showNotify("Ingreso cancelado", "info"); }} title="✨ INGRESO DE PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <label className="text-[10px] font-black text-slate-700 uppercase mb-2 block">Evidencia Visual</label>
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative">
                   <img src={ingresoForm.imagen} className="w-24 h-24 mx-auto object-cover rounded-xl shadow-lg border-2 border-white" />
                   <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[9px] font-black text-rose-500 mt-2 uppercase">Cambiar Foto</button>
                </div>
              ) : (
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 text-slate-400 py-4 w-full group hover:text-indigo-600 transition-all">
                  <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  <span className="text-[9px] font-black uppercase tracking-widest">Tomar Foto o Subir</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsIngresoModalOpen(false)}>Cerrar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Ingresar Stock</Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Email" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Perfil" value={userForm.perfil} onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})} options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]} />
            <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede} as any)} options={SEDES.map(s => ({value: s.id, label: s.name.replace(/^[0-9].\s*/, '')}))} />
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsUserModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear Usuario</Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🤖 ESTRATEGIA CON IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Modelando Datos Estratégicos...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6">
             <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                <h4 className="text-sm font-black text-indigo-900 uppercase mb-2">{reportData.titulo}</h4>
                <p className="text-xs text-indigo-700 leading-relaxed font-medium">{reportData.resumen}</p>
             </div>
             <div className="grid gap-3">
               {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border-l-4 shadow-sm ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500 text-rose-900' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-emerald-50 border-emerald-500 text-emerald-900'}`}>
                     <h5 className="text-[10px] font-black uppercase mb-1 tracking-tight">{sec.titulo}</h5>
                     <p className="text-[11px] opacity-80 leading-snug">{sec.contenido}</p>
                  </div>
               ))}
             </div>
             <div className="bg-slate-900 p-6 rounded-[1.5rem] text-white shadow-xl">
                <p className="text-[9px] font-black uppercase text-slate-500 mb-3 tracking-[0.2em]">Hoja de Ruta / Recomendaciones</p>
                <ul className="space-y-3">
                   {reportData.recomendaciones.map((r, i) => (
                     <li key={i} className="text-[11px] flex gap-3 items-start">
                       <span className="text-indigo-400 font-black mt-1">→</span> 
                       <span className="font-medium opacity-90">{r}</span>
                     </li>
                   ))}
                </ul>
             </div>
             <Button fullWidth onClick={() => setIsReportModalOpen(false)}>Finalizar Análisis</Button>
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [recentMovements, setRecentMovements] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  // Modals
  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Forms
  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      const source = Array.isArray(data) ? data[0] : data;

      // Cargamos productos (maestro + stock calculado)
      if (source && Array.isArray(source.productos)) {
        setRawProducts(source.productos);
      }

      // Cargamos el registro de movimientos recientes para verificación
      if (source && Array.isArray(source.movimientos)) {
        setRecentMovements(source.movimientos.slice(0, 5));
      }
    } catch (error) {
      console.error("Error n8n:", error);
      showNotify("Error al sincronizar datos", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!Array.isArray(rawProducts) || rawProducts.length === 0) return null;
    const safe = rawProducts.filter(p => p && p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + ((p.precioVenta || 0) * (p.stock?.total || 0)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + ((p.precioCosto || 0) * (p.stock?.total || 0)), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { name: s.name.replace(/^[0-9].\s*/, ''), total: safe.reduce((acc, p) => acc + ((p.stock?.[key] || 0) * (p.precioVenta || 0)), 0) };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    const estrella = [...safe].sort((a, b) => ((b.precioVenta || 0) * (b.stock?.total || 0)) - ((a.precioVenta || 0) * (a.stock?.total || 0)))[0];
    const critico = [...safe].sort((a, b) => (a.stock?.total || 0) - (b.stock?.total || 0))[0];
    const volumen = [...safe].sort((a, b) => (b.stock?.total || 0) - (a.stock?.total || 0))[0];

    const catMap: Record<string, number> = {};
    safe.forEach(p => {
      const cat = p.tipo || 'Otros';
      catMap[cat] = (catMap[cat] || 0) + (p.stock?.total || 0);
    });
    const topCat = Object.entries(catMap).sort((a,b) => b[1] - a[1])[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: { nombre: estrella?.nombre || 'N/A', ref: estrella?.referencia || '', valor: (estrella?.precioVenta || 0) * (estrella?.stock?.total || 0) },
      critico: { nombre: critico?.referencia || 'N/A', stock: critico?.stock?.total || 0 },
      volumen: { nombre: volumen?.nombre || 'N/A', stock: volumen?.stock?.total || 0 },
      categoria: { nombre: topCat?.[0] || 'N/A', stock: topCat?.[1] || 0 }
    };
  }, [rawProducts]);

  const handleGenerateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario y movimientos recientes: ${JSON.stringify(rawProducts.slice(0, 10))}. Genera un reporte estratégico JSON: { "titulo": "string", "resumen": "string", "secciones": [{ "tag": "string", "titulo": "string", "contenido": "string", "estado": "success|warning|danger" }], "recomendaciones": ["string"] }`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      const cleanJson = (response.text || "{}").replace(/```json|```/g, "").trim();
      setReportData(JSON.parse(cleanJson));
    } catch (e) {
      showNotify("Error en IA", "error");
      setIsReportModalOpen(false);
    } finally { setIsGeneratingReport(false); }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      // Enviamos el movimiento al webhook de n8n
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        // Forzamos recarga para que los indicadores carguen la info actualizada del webhook
        setTimeout(loadData, 1000); 
      }
      else throw new Error();
    } catch { showNotify("Error de conexión", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { showNotify("¡Producto ingresado!"); setIsIngresoModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de carga", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Faltan datos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) { showNotify("Usuario creado"); setIsUserModalOpen(false); }
      else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { setIngresoForm(p => ({ ...p, imagen: reader.result as string })); showNotify("Imagen lista", "info"); };
      reader.readAsDataURL(file);
    }
  };

  const allStockData = useMemo(() => {
    if (!Array.isArray(rawProducts)) return [];
    return rawProducts.map(p => ({
      Codigo: p.referencia || 'SIN-REF',
      Descripcion: p.nombre || 'Sin nombre',
      Categoria: p.tipo || 'Otros',
      Costo: Number(p.precioCosto) || 0,
      Venta: Number(p.precioVenta) || 0,
      Stock_Minimo: Number(p.stockMinimo) || 5,
      Stock_Actual: filterSede === 'ALL' ? (p.stock?.total || 0) : (p.stock?.[mapAppSedeToJsonProperty(filterSede)] || 0),
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); showNotify("QR Sincronizado"); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="flex items-center gap-2 bg-slate-900 text-white px-3 md:px-4 py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-md">
              <span className="md:inline">Crear Usuario</span>
              <svg className="w-4 h-4 md:hidden" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* Resumen General */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl relative overflow-hidden group">
             <div className="flex justify-between items-start">
               <div>
                 <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
                 <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
               </div>
               {isLoading && <div className="w-2 h-2 rounded-full bg-slate-700 animate-ping"></div>}
             </div>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl relative overflow-hidden group">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {/* PANEL DE CONTROL GERENCIAL */}
        {user.role === 'GERENTE' && insights && (
          <section className="space-y-6">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 p-2 rounded-lg text-amber-600">
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z"/></svg>
                </div>
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">Panel de Control Gerencial</h3>
              </div>
              <p className="text-[8px] font-bold text-slate-400 uppercase tracking-widest">Vía: n8n Webhook /api/movimiento</p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏆</span>
                  <p className="text-[9px] font-black text-indigo-500 uppercase tracking-widest">Sede Líder</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.lider.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1">${Math.round(insights.lider.valor).toLocaleString()}</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⭐</span>
                  <p className="text-[9px] font-black text-emerald-500 uppercase tracking-widest">Producto Estrella</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.estrella.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.estrella.ref} - ${Math.round(insights.estrella.valor).toLocaleString()}</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">⚠️</span>
                  <p className="text-[9px] font-black text-rose-500 uppercase tracking-widest">Stock Crítico</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.critico.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">Quedan: {insights.critico.stock} UND</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📊</span>
                  <p className="text-[9px] font-black text-amber-500 uppercase tracking-widest">Mayor Volumen</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 truncate">{insights.volumen.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.volumen.stock} Unidades</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">🏷️</span>
                  <p className="text-[9px] font-black text-sky-500 uppercase tracking-widest">Categoría Top</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">{insights.categoria.nombre}</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.categoria.stock} UND Totales</p>
              </div>

              <div className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                <div className="flex items-center gap-2 mb-3">
                  <span className="text-lg">📈</span>
                  <p className="text-[9px] font-black text-violet-500 uppercase tracking-widest">Margen Bruto</p>
                </div>
                <h4 className="text-lg font-black text-slate-800 uppercase">Eficiencia</h4>
                <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{insights.margen}% Estimado</p>
              </div>
            </div>
          </section>
        )}

        {/* Registro de Verificación de Movimientos (Nueva sección) */}
        {recentMovements.length > 0 && (
          <div className="bg-white/40 p-6 rounded-3xl border border-dashed border-slate-200">
             <div className="flex items-center gap-2 mb-4">
                <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">Sincronización de Movimientos Recientes</p>
             </div>
             <div className="flex gap-4 overflow-x-auto pb-2">
                {recentMovements.map((m, i) => (
                  <div key={i} className="bg-white p-3 rounded-2xl border border-slate-100 shadow-sm flex-shrink-0 min-w-[160px]">
                    <p className="text-[8px] font-black text-indigo-600 uppercase mb-1">{m.referencia}</p>
                    <div className="flex justify-between items-center">
                      <span className={`text-[8px] font-black px-2 py-0.5 rounded-full ${m.tipo === 'SALIDA' ? 'bg-rose-50 text-rose-500' : 'bg-emerald-50 text-emerald-500'}`}>{m.tipo}</span>
                      <span className="text-[10px] font-black text-slate-700">{m.cantidad} UND</span>
                    </div>
                  </div>
                ))}
             </div>
          </div>
        )}

        {/* Acciones */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white shadow-sm h-[52px] rounded-2xl px-4"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-emerald-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-indigo-700 transition-all flex items-center justify-center gap-1 md:gap-2">
              <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4-4" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={handleGenerateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[9px] md:text-[10px] uppercase tracking-widest shadow-lg hover:bg-slate-800 transition-all flex items-center justify-center gap-1 md:gap-2">
                <svg className="w-4 h-4 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        {/* Tabla Detallada */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Stock en Tiempo Real</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 transition-all ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-4 md:px-8 py-5">REF</th>
                  <th className="px-4 md:px-8 py-5">Descripción</th>
                  <th className="px-4 md:px-8 py-5 text-center">Stock</th>
                  <th className="px-4 md:px-8 py-5 text-right">Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {allStockData.sort((a,b) => b.Stock_Actual - a.Stock_Actual).map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all group">
                    <td className="px-4 md:px-8 py-4 md:py-5 font-black text-[11px] text-indigo-600">{s.Codigo}</td>
                    <td className="px-4 md:px-8 py-4 md:py-5">
                      <p className="font-bold text-[10px] md:text-[11px] text-slate-700 uppercase">{s.Descripcion}</p>
                      <p className="text-[8px] md:text-[9px] text-slate-400 uppercase font-black tracking-tighter mt-0.5">{s.Categoria}</p>
                    </td>
                    <td className="px-2 md:px-8 py-4 md:py-5 text-center">
                       <span className={`inline-block px-3 py-1.5 rounded-full text-[9px] font-black whitespace-nowrap shadow-sm ${s.Stock_Actual <= s.Stock_Minimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.Stock_Actual} UND
                       </span>
                    </td>
                    <td className="px-4 md:px-8 py-4 md:py-5 text-right font-black text-slate-700 text-[10px] md:text-[11px]">${Math.round(s.Venta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODALES */}
      <Modal isOpen={isMovModalOpen} onClose={() => { setIsMovModalOpen(false); showNotify("Movimiento cancelado", "info"); }} title="📦 MOVIMIENTO DE STOCK">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="ESCRIBE O ESCANEA..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl hover:bg-indigo-100 hover:text-indigo-600 transition-all text-slate-600">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2m5 2h-2m-2-4h-2m8 4v10a2 2 0 01-2 2H5a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2h-1m-10 0H5a2 2 0 01-2-2V5a2 2 0 012-2h10l5 5" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
             </button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as MovementType})} options={[{value: 'ENTRADA', label: 'Entrada'}, {value: 'SALIDA', label: 'Salida'}, {value: 'TRASLADO', label: 'Traslado'}]} />
           </div>
           <Input label="Observaciones" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} placeholder="OPCIONAL..." />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => { setIsMovModalOpen(false); showNotify("Cancelado", "info"); }}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>{isSubmitting ? 'Cargando...' : 'Confirmar'}</Button>
           </div>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => { setIsIngresoModalOpen(false); showNotify("Ingreso cancelado", "info"); }} title="✨ INGRESO DE PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo ($)" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta ($)" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <label className="text-[10px] font-black text-slate-700 uppercase mb-2 block">Evidencia Visual</label>
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative">
                   <img src={ingresoForm.imagen} className="w-24 h-24 mx-auto object-cover rounded-xl shadow-lg border-2 border-white" />
                   <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="text-[9px] font-black text-rose-500 mt-2 uppercase">Cambiar Foto</button>
                </div>
              ) : (
                <button onClick={() => fileInputRef.current?.click()} className="flex flex-col items-center gap-2 text-slate-400 py-4 w-full group hover:text-indigo-600 transition-all">
                  <svg className="w-8 h-8 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
                  <span className="text-[9px] font-black uppercase tracking-widest">Tomar Foto o Subir</span>
                </button>
              )}
              <input type="file" accept="image/*" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsIngresoModalOpen(false)}>Cerrar</Button>
            <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Ingresar Stock</Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 CREAR ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Email" type="email" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <div className="grid grid-cols-2 gap-4">
            <Select label="Perfil" value={userForm.perfil} onChange={e => setUserForm({...userForm, perfil: e.target.value as UserRole})} options={[{value:'GERENTE', label:'Gerente'}, {value:'OPERADOR', label:'Operador'}]} />
            {/* Fix: use e.target.value and cast to SedeId for the sede property */}
            <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name.replace(/^[0-9].\s*/, '')}))} />
          </div>
          <div className="flex gap-3 pt-4">
            <Button variant="secondary" fullWidth onClick={() => setIsUserModalOpen(false)}>Cancelar</Button>
            <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear Usuario</Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🤖 ESTRATEGIA CON IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center gap-4">
             <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
             <p className="text-[10px] font-black uppercase tracking-widest text-indigo-600">Modelando Datos Estratégicos...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6">
             <div className="bg-indigo-50 p-6 rounded-3xl border border-indigo-100">
                <h4 className="text-sm font-black text-indigo-900 uppercase mb-2">{reportData.titulo}</h4>
                <p className="text-xs text-indigo-700 leading-relaxed font-medium">{reportData.resumen}</p>
             </div>
             <div className="grid gap-3">
               {reportData.secciones.map((sec, i) => (
                  <div key={i} className={`p-5 rounded-[1.5rem] border-l-4 shadow-sm ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500 text-rose-900' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500 text-amber-900' : 'bg-emerald-50 border-emerald-500 text-emerald-900'}`}>
                     <h5 className="text-[10px] font-black uppercase mb-1 tracking-tight">{sec.titulo}</h5>
                     <p className="text-[11px] opacity-80 leading-snug">{sec.contenido}</p>
                  </div>
               ))}
             </div>
             <div className="bg-slate-900 p-6 rounded-[1.5rem] text-white shadow-xl">
                <p className="text-[9px] font-black uppercase text-slate-500 mb-3 tracking-[0.2em]">Hoja de Ruta / Recomendaciones</p>
                <ul className="space-y-3">
                   {reportData.recomendaciones.map((r, i) => (
                     <li key={i} className="text-[11px] flex gap-3 items-start">
                       <span className="text-indigo-400 font-black mt-1">→</span> 
                       <span className="font-medium opacity-90">{r}</span>
                     </li>
                   ))}
                </ul>
             </div>
             <Button fullWidth onClick={() => setIsReportModalOpen(false)}>Finalizar Análisis</Button>
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState({
    referencia: '',
    cantidad: 1,
    costo_unitario: 0,
    precio_venta: 0,
    stock_minimo: 5,
    imagen: '' as string | null
  });

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      // Intentamos extraer el stock de forma flexible
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias']) || {};
      const totalStock = typeof stockObj === 'number' ? stockObj : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma']) || 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia']) || 'Otros'),
        precioCosto: Number(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra']) || 0),
        precioVenta: Number(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta']) || 0),
        stockMinimo: Number(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta']) || 5),
        stock: {
          total: Number(totalStock),
          taller: Number(getFlexibleValue(stockObj, ['taller', 'bodega1']) || 0),
          country: Number(getFlexibleValue(stockObj, ['country', 'bodega2']) || 0),
          plazaDelSol: Number(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3']) || 0),
          portalDelPrado: Number(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4']) || 0),
          centro: Number(getFlexibleValue(stockObj, ['centro', 'bodega5']) || 0)
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      // Manejo de estructura: si es un array de un solo elemento con la data, o un objeto con key productos
      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      }

      if (sourceArray.length > 0) {
        const normalized = normalizeData(sourceArray);
        setRawProducts(normalized);
      } else {
        console.warn("Webhook retornó array vacío o estructura no reconocida");
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error al sincronizar inventario", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];
    const estrella = [...safe].sort((a, b) => (b.precioVenta * b.stock.total) - (a.precioVenta * a.stock.total))[0];
    const critico = [...safe].sort((a, b) => a.stock.total - b.stock.total)[0];
    const volumen = [...safe].sort((a, b) => b.stock.total - a.stock.total)[0];

    const catMap: Record<string, number> = {};
    safe.forEach(p => {
      catMap[p.tipo] = (catMap[p.tipo] || 0) + p.stock.total;
    });
    const topCat = Object.entries(catMap).sort((a,b) => b[1] - a[1])[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: { nombre: estrella?.nombre || 'N/A', ref: estrella?.referencia || '', valor: (estrella?.precioVenta || 0) * (estrella?.stock.total || 0) },
      critico: { nombre: critico?.referencia || 'N/A', stock: critico?.stock.total || 0 },
      volumen: { nombre: volumen?.nombre || 'N/A', stock: volumen?.stock.total || 0 },
      categoria: { nombre: topCat?.[0] || 'N/A', stock: topCat?.[1] || 0 }
    };
  }, [rawProducts]);

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        loadData(); 
      } else throw new Error();
    } catch { showNotify("Error al registrar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { showNotify("¡Producto ingresado!"); setIsIngresoModalOpen(false); loadData(); }
      else throw new Error();
    } catch { showNotify("Error de carga", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Faltan datos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) { showNotify("Usuario creado"); setIsUserModalOpen(false); }
      else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { 
        setIngresoForm(p => ({ ...p, imagen: reader.result as string })); 
        showNotify("Imagen cargada"); 
      };
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => ({
      ...p,
      stockVisual: filterSede === 'ALL' ? p.stock.total : p.stock[mapAppSedeToJsonProperty(filterSede)]
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Crear Usuario</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <div className="flex justify-between items-start">
               <div>
                 <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
                 <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
               </div>
               {isLoading && <div className="w-2 h-2 rounded-full bg-indigo-500 animate-ping"></div>}
             </div>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella.nombre, sub: insights.estrella.ref },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico.nombre, sub: `${insights.critico.stock} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen.nombre, sub: `${insights.volumen.stock} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria.nombre, sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm group hover:border-indigo-200 transition-all">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg">{kpi.icon}</span>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p>
                  </div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        {/* Controles */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
          </div>
        </div>

        {/* Tabla */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventario Detallado</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Stock</th>
                  <th className="px-8 py-5 text-right">Precio</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-3 py-1 rounded-full text-[10px] font-black ${s.stockVisual <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockVisual} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="SKU..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL INGRESO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO PRODUCTO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? <img src={ingresoForm.imagen} className="w-20 h-20 mx-auto object-cover rounded-xl" /> : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Añadir Imagen</button>}
              <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} />
            </div>
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Ingresar</Button>
        </div>
      </Modal>

      {/* MODAL USUARIO */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 NUEVO ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      // Priorizamos encontrar el contenedor de stock por sede o el valor total
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};

      // Intentamos extraer el total real del stock (no el mínimo)
      // Buscamos específicamente en el objeto stock o en la raíz del producto
      const totalStock = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) || 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias']) || 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: Number(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo']) || 0),
        precioVenta: Number(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta']) || 0),
        stockMinimo: Number(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) || 5),
        stock: {
          total: Number(totalStock),
          taller: Number(getFlexibleValue(stockObj, ['taller', 'bodega1']) || 0),
          country: Number(getFlexibleValue(stockObj, ['country', 'bodega2']) || 0),
          plazaDelSol: Number(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3']) || 0),
          portalDelPrado: Number(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4']) || 0),
          centro: Number(getFlexibleValue(stockObj, ['centro', 'bodega5']) || 0)
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      } else if (typeof data === 'object') {
         // Si el webhook devuelve un objeto directo con campos de producto
         sourceArray = [data];
      }

      if (sourceArray.length > 0) {
        const normalized = normalizeData(sourceArray);
        setRawProducts(normalized);
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error al sincronizar inventario", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);

    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];
    const estrella = [...safe].sort((a, b) => (b.precioVenta * b.stock.total) - (a.precioVenta * a.stock.total))[0];
    const critico = [...safe].sort((a, b) => a.stock.total - b.stock.total)[0];
    const volumen = [...safe].sort((a, b) => b.stock.total - a.stock.total)[0];

    const catMap: Record<string, number> = {};
    safe.forEach(p => {
      catMap[p.tipo] = (catMap[p.tipo] || 0) + p.stock.total;
    });
    const topCat = Object.entries(catMap).sort((a,b) => b[1] - a[1])[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: { nombre: estrella?.nombre || 'N/A', ref: estrella?.referencia || '', valor: (estrella?.precioVenta || 0) * (estrella?.stock.total || 0) },
      critico: { nombre: critico?.referencia || 'N/A', stock: critico?.stock.total || 0 },
      volumen: { nombre: volumen?.nombre || 'N/A', stock: volumen?.stock.total || 0 },
      categoria: { nombre: topCat?.[0] || 'N/A', stock: topCat?.[1] || 0 }
    };
  }, [rawProducts]);

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      } else throw new Error();
    } catch { showNotify("Error al registrar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado con éxito!"); 
        setIsIngresoModalOpen(false); 
        // RESETEAMOS EL FORMULARIO
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
      else throw new Error();
    } catch { showNotify("Error de carga", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleCreateUser = async () => {
    if (!userForm.correo || !userForm.nombre) return showNotify("Faltan datos", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.CREAR_USUARIO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userForm)
      });
      if (res.ok) { showNotify("Usuario creado"); setIsUserModalOpen(false); }
      else throw new Error();
    } catch { showNotify("Error al crear usuario", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => { 
        setIngresoForm(p => ({ ...p, imagen: reader.result as string })); 
        showNotify("Imagen cargada"); 
      };
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => ({
      ...p,
      stockVisual: filterSede === 'ALL' ? p.stock.total : p.stock[mapAppSedeToJsonProperty(filterSede)]
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Crear Usuario</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <div className="flex justify-between items-start">
               <div>
                 <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
                 <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
               </div>
               {isLoading && <div className="w-2 h-2 rounded-full bg-indigo-500 animate-ping"></div>}
             </div>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella.nombre, sub: insights.estrella.ref },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico.nombre, sub: `${insights.critico.stock} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen.nombre, sub: `${insights.volumen.stock} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria.nombre, sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm group hover:border-indigo-200 transition-all">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg">{kpi.icon}</span>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p>
                  </div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        {/* Controles */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
          </div>
        </div>

        {/* Tabla */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Inventario Detallado</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">Precio</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       {/* Mostramos stockVisual que representa el stock real calculado */}
                       <span className={`inline-block px-3 py-1 rounded-full text-[10px] font-black ${s.stockVisual <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockVisual} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} placeholder="SKU..." />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1m-3 3h2" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input label="Notas" value={movForm.notes} onChange={e => setMovForm({...movForm, notes: e.target.value})} />
           <div className="flex gap-3 pt-4">
             <Button variant="secondary" fullWidth onClick={() => setIsMovModalOpen(false)}>Cancelar</Button>
             <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
           </div>
         </div>
      </Modal>

      {/* MODAL INGRESO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO PRODUCTO / INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo Unitario" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta Unitario" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="pt-2">
            <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
              {ingresoForm.imagen ? (
                <div className="relative inline-block">
                  <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                  <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3"/></svg></button>
                </div>
              ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Añadir Imagen</button>}
              <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
            </div>
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>
             {isSubmitting ? 'Procesando...' : 'Registrar Ingreso'}
          </Button>
        </div>
      </Modal>

      {/* MODAL USUARIO */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 NUEVO ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          <Button fullWidth onClick={handleCreateUser} disabled={isSubmitting}>Crear</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

// Estado inicial limpio para el formulario de ingreso
const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      // 1. Buscamos el objeto contenedor de stock
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};

      // 2. Extraemos el total real (Existencias reales, NO el mínimo)
      const totalStock = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) || 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) || 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: Number(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo']) || 0),
        precioVenta: Number(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta']) || 0),
        stockMinimo: Number(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) || 5),
        stock: {
          total: Number(totalStock),
          taller: Number(getFlexibleValue(stockObj, ['taller', 'bodega1']) || 0),
          country: Number(getFlexibleValue(stockObj, ['country', 'bodega2']) || 0),
          plazaDelSol: Number(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3']) || 0),
          portalDelPrado: Number(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4']) || 0),
          centro: Number(getFlexibleValue(stockObj, ['centro', 'bodega5']) || 0)
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      } else if (typeof data === 'object') {
         sourceArray = [data];
      }

      if (sourceArray.length > 0) {
        setRawProducts(normalizeData(sourceArray));
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0]
    };
  }, [rawProducts]);

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado con éxito!"); 
        setIsIngresoModalOpen(false); 
        // RESETEAMOS EL FORMULARIO A VALORES VACÍOS
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      } else {
        throw new Error();
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => ({
      ...p,
      // Usamos el stock real según la sede o global
      stockReal: filterSede === 'ALL' ? p.stock.total : p.stock[mapAppSedeToJsonProperty(filterSede)]
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Usuarios</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       {/* Aquí se muestran las EXISTENCIAS REALES mapeadas del webhook */}
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Foto/Imagen</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      // 1. Buscamos el contenedor de stock (Prioridad: stock -> Inventario -> Existencias)
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};

      // 2. Extraemos el total real (Existencias actuales, no el mínimo)
      const totalStock = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) || 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) || 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: Number(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo']) || 0),
        precioVenta: Number(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta']) || 0),
        stockMinimo: Number(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) || 5),
        stock: {
          total: Number(totalStock),
          taller: Number(getFlexibleValue(stockObj, ['taller', 'bodega1']) || 0),
          country: Number(getFlexibleValue(stockObj, ['country', 'bodega2']) || 0),
          plazaDelSol: Number(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3']) || 0),
          portalDelPrado: Number(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4']) || 0),
          centro: Number(getFlexibleValue(stockObj, ['centro', 'bodega5']) || 0)
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      } else if (typeof data === 'object') {
         sourceArray = [data];
      }

      if (sourceArray.length > 0) {
        setRawProducts(normalizeData(sourceArray));
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario de Yeilu Store y genera un informe ejecutivo en JSON.
      Datos: ${JSON.stringify(rawProducts.slice(0, 15))}
      Formato JSON: { "titulo": string, "resumen": string, "secciones": [{ "tag": string, "titulo": string, "contenido": string, "estado": "success"|"warning"|"danger"|"info" }], "recomendaciones": [string] }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      setReportData(JSON.parse(response.text || '{}'));
    } catch (error) {
      console.error("AI Error:", error);
      showNotify("Error al generar informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado con éxito!"); 
        setIsIngresoModalOpen(false); 
        // RESETEAMOS EL FORMULARIO A VALORES VACÍOS
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      } else {
        throw new Error();
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => ({
      ...p,
      stockReal: filterSede === 'ALL' ? p.stock.total : p.stock[mapAppSedeToJsonProperty(filterSede)]
    }));
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Usuarios</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        {/* KPIs */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm group hover:border-indigo-200 transition-all">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg">{kpi.icon}</span>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p>
                  </div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        {/* Controles */}
        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2 hover:bg-black transition-all">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        {/* Tabla */}
        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       {/* Aquí se muestran las EXISTENCIAS REALES mapeadas del webhook */}
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* MODAL MOVIMIENTO */}
      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      {/* MODAL INGRESO */}
      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Foto/Imagen</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      {/* MODAL REPORTE IA */}
      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME ESTRATÉGICO IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Gemini está analizando tu inventario...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium leading-relaxed">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-black uppercase text-slate-400">{sec.tag}</span>
                   <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 </div>
                 <p className="text-xs text-slate-600 leading-relaxed">{sec.contenido}</p>
              </div>
            ))}
            <div className="bg-slate-900 p-6 rounded-2xl text-white">
               <h5 className="font-black text-[10px] uppercase tracking-widest mb-4 text-indigo-400">Recomendaciones</h5>
               <ul className="space-y-3">
                 {reportData.recomendaciones.map((rec, i) => (
                   <li key={i} className="flex gap-3 text-xs font-medium opacity-90">
                     <span className="text-indigo-500">◆</span> {rec}
                   </li>
                 ))}
               </ul>
            </div>
          </div>
        )}
      </Modal>

      {/* MODAL USUARIO */}
      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 NUEVO ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          <Button fullWidth onClick={() => { showNotify("Usuario creado localmente"); setIsUserModalOpen(false); }} disabled={isSubmitting}>Crear</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función auxiliar para evitar NaN: Limpia símbolos y convierte a número real
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  // Elimina todo lo que no sea número, punto o signo menos (ej: elimina $, comas, espacios)
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};

      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'bodega1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'bodega2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'bodega5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      } else if (typeof data === 'object') {
         sourceArray = [data];
      }

      if (sourceArray.length > 0) {
        setRawProducts(normalizeData(sourceArray));
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario de Yeilu Store y genera un informe ejecutivo profesional en JSON.
      Datos principales: ${JSON.stringify(rawProducts.slice(0, 20))}
      Estructura de salida requerida: { "titulo": string, "resumen": string, "secciones": [{ "tag": string, "titulo": string, "contenido": string, "estado": "success"|"warning"|"danger"|"info" }], "recomendaciones": [string] }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const parsed = JSON.parse(response.text || '{}');
      setReportData(parsed);
    } catch (error) {
      console.error("AI Error:", error);
      showNotify("Error al generar informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado con éxito!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      } else {
        throw new Error();
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      const key = mapAppSedeToJsonProperty(filterSede);
      return {
        ...p,
        stockReal: filterSede === 'ALL' ? p.stock.total : (p.stock[key] ?? 0)
      };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Usuarios</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm group hover:border-indigo-200 transition-all">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg">{kpi.icon}</span>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p>
                  </div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2 hover:bg-black transition-all">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Foto/Imagen</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME ESTRATÉGICO IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Gemini está analizando tu inventario...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium leading-relaxed">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-black uppercase text-slate-400">{sec.tag}</span>
                   <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 </div>
                 <p className="text-xs text-slate-600 leading-relaxed">{sec.contenido}</p>
              </div>
            ))}
            <div className="bg-slate-900 p-6 rounded-2xl text-white">
               <h5 className="font-black text-[10px] uppercase tracking-widest mb-4 text-indigo-400">Recomendaciones</h5>
               <ul className="space-y-3">
                 {reportData.recomendaciones.map((rec, i) => (
                   <li key={i} className="flex gap-3 text-xs font-medium opacity-90">
                     <span className="text-indigo-500">◆</span> {rec}
                   </li>
                 ))}
               </ul>
            </div>
          </div>
        )}
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 NUEVO ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          <Button fullWidth onClick={() => { showNotify("Usuario creado localmente"); setIsUserModalOpen(false); }} disabled={isSubmitting}>Crear</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función auxiliar para evitar NaN: Limpia símbolos y convierte a número real
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  // Elimina todo lo que no sea número, punto o signo menos (ej: elimina $, comas, espacios)
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};

      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'bodega1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'bodega2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'bodega5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();

      let sourceArray = [];
      if (Array.isArray(data)) {
        if (data[0]?.productos) sourceArray = data[0].productos;
        else sourceArray = data;
      } else if (data.productos) {
        sourceArray = data.productos;
      } else if (typeof data === 'object') {
         sourceArray = [data];
      }

      if (sourceArray.length > 0) {
        setRawProducts(normalizeData(sourceArray));
      }
    } catch (error) {
      console.error("Error n8n Load:", error);
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);

    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Analiza este inventario de Yeilu Store y genera un informe ejecutivo profesional en JSON.
      Datos principales: ${JSON.stringify(rawProducts.slice(0, 20))}
      Estructura de salida requerida: { "titulo": string, "resumen": string, "secciones": [{ "tag": string, "titulo": string, "contenido": string, "estado": "success"|"warning"|"danger"|"info" }], "recomendaciones": [string] }`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });

      const parsed = JSON.parse(response.text || '{}');
      setReportData(parsed);
    } catch (error) {
      console.error("AI Error:", error);
      showNotify("Error al generar informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: user.sedeId, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: user.sedeId })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado con éxito!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      } else {
        throw new Error();
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  // Fixed: Argument of type 'SedeId | "ALL"' is not assignable to parameter of type 'SedeId'.
  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') {
        return {
          ...p,
          stockReal: p.stock.total
        };
      }
      const key = mapAppSedeToJsonProperty(filterSede);
      return {
        ...p,
        stockReal: p.stock[key] ?? 0
      };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : notification.type === 'error' ? 'bg-rose-600' : 'bg-indigo-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && (
        <QRScanner 
          onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} 
          onClose={() => setIsQRVisible(false)} 
        />
      )}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex items-center gap-3">
          {user.role === 'GERENTE' && (
            <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-md">Usuarios</button>
          )}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm group hover:border-indigo-200 transition-all">
                  <div className="flex items-center gap-2 mb-2">
                    <span className="text-lg">{kpi.icon}</span>
                    <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p>
                  </div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2 hover:bg-black transition-all">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full hover:bg-slate-100 ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 REGISTRAR MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase">Foto/Imagen</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME ESTRATÉGICO IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Gemini está analizando tu inventario...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium leading-relaxed">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <div className="flex items-center gap-2 mb-2">
                   <span className="text-[10px] font-black uppercase text-slate-400">{sec.tag}</span>
                   <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 </div>
                 <p className="text-xs text-slate-600 leading-relaxed">{sec.contenido}</p>
              </div>
            ))}
            <div className="bg-slate-900 p-6 rounded-2xl text-white">
               <h5 className="font-black text-[10px] uppercase tracking-widest mb-4 text-indigo-400">Recomendaciones</h5>
               <ul className="space-y-3">
                 {reportData.recomendaciones.map((rec, i) => (
                   <li key={i} className="flex gap-3 text-xs font-medium opacity-90">
                     <span className="text-indigo-500">◆</span> {rec}
                   </li>
                 ))}
               </ul>
            </div>
          </div>
        )}
      </Modal>

      <Modal isOpen={isUserModalOpen} onClose={() => setIsUserModalOpen(false)} title="👤 NUEVO ACCESO">
        <div className="space-y-4">
          <Input label="Nombre" value={userForm.nombre} onChange={e => setUserForm({...userForm, nombre: e.target.value})} />
          <Input label="Correo" value={userForm.correo} onChange={e => setUserForm({...userForm, correo: e.target.value})} />
          <Input label="Clave" type="password" value={userForm.password} onChange={e => setUserForm({...userForm, password: e.target.value})} />
          <Select label="Sede" value={userForm.sede} onChange={e => setUserForm({...userForm, sede: e.target.value as SedeId})} options={SEDES.map(s => ({value: s.id, label: s.name}))} />
          <Button fullWidth onClick={() => { showNotify("Usuario creado localmente"); setIsUserModalOpen(false); }} disabled={isSubmitting}>Crear</Button>
        </div>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función para limpiar símbolos y evitar NaN
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};
      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'bodega1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'bodega2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'bodega5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      let sourceArray = Array.isArray(data) ? (data[0]?.productos || data) : (data.productos || [data]);
      if (sourceArray.length > 0) setRawProducts(normalizeData(sourceArray));
    } catch (error) {
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Genera un informe estratégico JSON: ${JSON.stringify(rawProducts.slice(0, 15))}`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });
      setReportData(JSON.parse(response.text || '{}'));
    } catch (error) {
      showNotify("Error informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    // IMPORTANTE: Si el filtro de sede está en ALL, se usa la sede del usuario. Si hay una sede seleccionada, se usa esa.
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: sedeTarget, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    // IMPORTANTE: Enviamos la sede seleccionada en el filtro global al webhook
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: sedeTarget })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') return { ...p, stockReal: p.stock.total };
      const key = mapAppSedeToJsonProperty(filterSede);
      return { ...p, stockReal: p.stock[key] ?? 0 };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : 'bg-rose-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && <QRScanner onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2"/></svg></div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex gap-3">
          {user.role === 'GERENTE' && <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Usuarios</button>}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                  <div className="flex items-center gap-2 mb-2"><span className="text-lg">{kpi.icon}</span><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p></div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Añadir Foto</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Analizando...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 <p className="text-xs text-slate-600 mt-1">{sec.contenido}</p>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función para limpiar símbolos y evitar NaN
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes']) || {};
      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'bodega1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'bodega2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'bodega3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'bodega4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'bodega5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      let sourceArray = Array.isArray(data) ? (data[0]?.productos || data) : (data.productos || [data]);
      if (sourceArray.length > 0) setRawProducts(normalizeData(sourceArray));
    } catch (error) {
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Genera un informe estratégico JSON: ${JSON.stringify(rawProducts.slice(0, 15))}`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });
      setReportData(JSON.parse(response.text || '{}'));
    } catch (error) {
      showNotify("Error informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    // IMPORTANTE: Se envía la sede que está seleccionada actualmente en el filtro global.
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: sedeTarget, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    // IMPORTANTE: Se envía la sede que está seleccionada actualmente en el filtro global.
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: sedeTarget })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') return { ...p, stockReal: p.stock.total };
      const key = mapAppSedeToJsonProperty(filterSede);
      return { ...p, stockReal: p.stock[key] ?? 0 };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : 'bg-rose-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && <QRScanner onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2"/></svg></div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex gap-3">
          {user.role === 'GERENTE' && <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Usuarios</button>}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                  <div className="flex items-center gap-2 mb-2"><span className="text-lg">{kpi.icon}</span><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p></div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input 
             label="Observaciones / Motivo (Opcional)" 
             value={movForm.notes} 
             onChange={e => setMovForm({...movForm, notes: e.target.value})} 
             placeholder="Ej: Venta, Traslado a Centro, Ajuste de inventario..."
             className="text-xs"
           />
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Añadir Foto</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Analizando...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 <p className="text-xs text-slate-600 mt-1">{sec.contenido}</p>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función para limpiar símbolos y evitar NaN
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  // Sanitiza quitando todo excepto números, puntos y guiones
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase().trim());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      // Intentamos obtener el objeto de stock o usamos el producto raíz como fallback
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes', 'stocks']) || p;

      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock', 'total']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          // Alias expandidos para cubrir variaciones en los nombres de las columnas del Sheets
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'Taller', 'bodega1', 'BODEGA 1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'Country', 'bodega2', 'BODEGA 2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'plaza_del_sol', 'Plaza del Sol', 'bodega3', 'BODEGA 3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'portal_del_prado', 'Portal del Prado', 'bodega4', 'BODEGA 4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'Centro', 'bodega5', 'BODEGA 5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      let sourceArray = Array.isArray(data) ? (data[0]?.productos || data) : (data.productos || [data]);
      if (sourceArray.length > 0) setRawProducts(normalizeData(sourceArray));
    } catch (error) {
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);
    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * p.stock.total), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * p.stock.total), 0);
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta*b.stock.total) - (a.precioVenta*a.stock.total))[0],
      critico: safe.sort((a,b) => a.stock.total - b.stock.total)[0],
      volumen: safe.sort((a,b) => b.stock.total - a.stock.total)[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { acc[p.tipo] = (acc[p.tipo]||0)+p.stock.total; return acc; }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Genera un informe estratégico JSON: ${JSON.stringify(rawProducts.slice(0, 15))}`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });
      setReportData(JSON.parse(response.text || '{}'));
    } catch (error) {
      showNotify("Error informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: sedeTarget, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: sedeTarget })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') return { ...p, stockReal: p.stock.total };
      const key = mapAppSedeToJsonProperty(filterSede);
      return { ...p, stockReal: (p.stock as any)[key] ?? 0 };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : 'bg-rose-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && <QRScanner onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2"/></svg></div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex gap-3">
          {user.role === 'GERENTE' && <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Usuarios</button>}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stock.total || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stock.total || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                  <div className="flex items-center gap-2 mb-2"><span className="text-lg">{kpi.icon}</span><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p></div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input 
             label="Observaciones / Motivo (Opcional)" 
             value={movForm.notes} 
             onChange={e => setMovForm({...movForm, notes: e.target.value})} 
             placeholder="Ej: Venta, Traslado a Centro, Ajuste de inventario..."
             className="text-xs"
           />
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Añadir Foto</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Analizando...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 <p className="text-xs text-slate-600 mt-1">{sec.contenido}</p>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función para limpiar símbolos y evitar NaN
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase().trim());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes', 'stocks']) || p;
      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock', 'total']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'Taller', 'bodega1', 'BODEGA 1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'Country', 'bodega2', 'BODEGA 2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'plaza_del_sol', 'Plaza del Sol', 'bodega3', 'BODEGA 3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'portal_del_prado', 'Portal del Prado', 'bodega4', 'BODEGA 4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'Centro', 'bodega5', 'BODEGA 5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      let sourceArray = Array.isArray(data) ? (data[0]?.productos || data) : (data.productos || [data]);
      if (sourceArray.length > 0) setRawProducts(normalizeData(sourceArray));
    } catch (error) {
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);

    // Determinar qué stock usar para los indicadores basándose en el filtro global
    const getStockForIndicators = (p: any) => {
      if (filterSede === 'ALL') return p.stock.total;
      const key = mapAppSedeToJsonProperty(filterSede);
      return (p.stock as any)[key] ?? 0;
    };

    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * getStockForIndicators(p)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * getStockForIndicators(p)), 0);

    // Sede líder siempre se calcula sobre el global para saber cuál es la mejor
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta * getStockForIndicators(b)) - (a.precioVenta * getStockForIndicators(a)))[0],
      critico: safe.sort((a,b) => getStockForIndicators(a) - getStockForIndicators(b))[0],
      volumen: safe.sort((a,b) => getStockForIndicators(b) - getStockForIndicators(a))[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { 
        const stock = getStockForIndicators(p);
        acc[p.tipo] = (acc[p.tipo]||0) + stock; 
        return acc; 
      }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts, filterSede]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Genera un informe estratégico JSON: ${JSON.stringify(rawProducts.slice(0, 15))}`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { responseMimeType: "application/json" }
      });
      setReportData(JSON.parse(response.text || '{}'));
    } catch (error) {
      showNotify("Error informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: sedeTarget, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: sedeTarget })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') return { ...p, stockReal: p.stock.total };
      const key = mapAppSedeToJsonProperty(filterSede);
      return { ...p, stockReal: (p.stock as any)[key] ?? 0 };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : 'bg-rose-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && <QRScanner onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2"/></svg></div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex gap-3">
          {user.role === 'GERENTE' && <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Usuarios</button>}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual ({filterSede === 'ALL' ? 'Global' : filterSede.toUpperCase()})</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada ({filterSede === 'ALL' ? 'Global' : filterSede.toUpperCase()})</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stockReal || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stockReal || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                  <div className="flex items-center gap-2 mb-2"><span className="text-lg">{kpi.icon}</span><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p></div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input 
             label="Observaciones / Motivo (Opcional)" 
             value={movForm.notes} 
             onChange={e => setMovForm({...movForm, notes: e.target.value})} 
             placeholder="Ej: Venta, Traslado a Centro, Ajuste de inventario..."
             className="text-xs"
           />
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Añadir Foto</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Analizando...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 <p className="text-xs text-slate-600 mt-1">{sec.contenido}</p>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, MaestroProducto, SedeId, MovementType, UserRole } from '../types';
import { SEDES, N8N_WEBHOOKS } from '../constants';
import { Button, Input, Select, Modal } from './UI';
import { QRScanner } from './QRScanner';
import { GoogleGenAI, Type } from "@google/genai";

interface IASection {
  tag: string;
  titulo: string;
  contenido: string;
  estado: 'success' | 'warning' | 'danger' | 'info';
}

interface IAReport {
  titulo: string;
  resumen: string;
  secciones: IASection[];
  recomendaciones: string[];
}

interface Notification {
  show: boolean;
  message: string;
  type: 'success' | 'error' | 'info';
}

const INITIAL_INGRESO_STATE = {
  referencia: '',
  cantidad: 1,
  costo_unitario: 0,
  precio_venta: 0,
  stock_minimo: 5,
  imagen: null as string | null
};

// Función para limpiar símbolos y evitar NaN
const parseSafeNumber = (val: any): number => {
  if (val === null || val === undefined || val === '') return 0;
  if (typeof val === 'number') return isNaN(val) ? 0 : val;
  const sanitized = String(val).replace(/[^0-9.-]+/g, "");
  const parsed = parseFloat(sanitized);
  return isNaN(parsed) ? 0 : parsed;
};

export const Dashboard: React.FC<{ user: User; onLogout: () => void }> = ({ user, onLogout }) => {
  const [rawProducts, setRawProducts] = useState<any[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isQRVisible, setIsQRVisible] = useState(false);
  const [filterSede, setFilterSede] = useState<SedeId | 'ALL'>(user.role === 'GERENTE' ? 'ALL' : user.sedeId);

  const [isMovModalOpen, setIsMovModalOpen] = useState(false);
  const [isIngresoModalOpen, setIsIngresoModalOpen] = useState(false);
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const [reportData, setReportData] = useState<IAReport | null>(null);
  const [notification, setNotification] = useState<Notification>({ show: false, message: '', type: 'success' });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [movForm, setMovForm] = useState({
    reference: '', 
    quantity: 1, 
    type: 'SALIDA' as MovementType, 
    destSede: '' as SedeId | '', 
    notes: '' 
  });

  const [ingresoForm, setIngresoForm] = useState(INITIAL_INGRESO_STATE);

  const [userForm, setUserForm] = useState({
    nombre: '',
    correo: '',
    password: '',
    perfil: 'OPERADOR' as UserRole,
    sede: 'taller' as SedeId
  });

  const showNotify = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setNotification({ show: true, message, type });
    setTimeout(() => setNotification({ show: false, message: '', type: 'success' }), 4000);
  };

  const getFlexibleValue = (obj: any, aliases: string[]) => {
    if (!obj || typeof obj !== 'object') return null;
    const keys = Object.keys(obj);
    for (const alias of aliases) {
      const foundKey = keys.find(k => k.trim().toLowerCase() === alias.toLowerCase().trim());
      if (foundKey !== undefined) return obj[foundKey];
    }
    return null;
  };

  const mapAppSedeToJsonProperty = (sedeId: SedeId): string => {
    const map: Record<string, string> = {
      'taller': 'taller', 'country': 'country', 'plaza_sol': 'plazaDelSol', 'portal_prado': 'portalDelPrado', 'centro': 'centro'
    };
    return map[sedeId] || sedeId;
  };

  const normalizeData = (data: any[]): any[] => {
    return data.map(p => {
      const stockObj = getFlexibleValue(p, ['stock', 'Inventario', 'Existencias', 'Sedes', 'stocks']) || p;
      const totalStockVal = typeof stockObj === 'number' 
        ? stockObj 
        : (getFlexibleValue(stockObj, ['total', 'Cantidad', 'Suma', 'Total_Existencias']) ?? 
           getFlexibleValue(p, ['Stock_Actual', 'Cantidad_Total', 'Existencias', 'Stock', 'total']) ?? 0);

      return {
        referencia: String(getFlexibleValue(p, ['referencia', 'codigo', 'sku', 'id', 'Codigo']) || '').toUpperCase(),
        nombre: String(getFlexibleValue(p, ['nombre', 'descripcion', 'producto', 'Descripcion']) || 'Sin Nombre'),
        tipo: String(getFlexibleValue(p, ['tipo', 'categoria', 'familia', 'Categoria']) || 'Otros'),
        precioCosto: parseSafeNumber(getFlexibleValue(p, ['precioCosto', 'costo', 'valor_compra', 'Costo'])),
        precioVenta: parseSafeNumber(getFlexibleValue(p, ['precioVenta', 'venta', 'valor_venta', 'Venta'])),
        stockMinimo: parseSafeNumber(getFlexibleValue(p, ['stockMinimo', 'minimo', 'alerta', 'Stock_Minimo']) ?? 5),
        stock: {
          total: parseSafeNumber(totalStockVal),
          taller: parseSafeNumber(getFlexibleValue(stockObj, ['taller', 'Taller', 'bodega1', 'BODEGA 1'])),
          country: parseSafeNumber(getFlexibleValue(stockObj, ['country', 'Country', 'bodega2', 'BODEGA 2'])),
          plazaDelSol: parseSafeNumber(getFlexibleValue(stockObj, ['plaza_sol', 'plazaDelSol', 'plaza_del_sol', 'Plaza del Sol', 'bodega3', 'BODEGA 3'])),
          portalDelPrado: parseSafeNumber(getFlexibleValue(stockObj, ['portal_prado', 'portalDelPrado', 'portal_del_prado', 'Portal del Prado', 'bodega4', 'BODEGA 4'])),
          centro: parseSafeNumber(getFlexibleValue(stockObj, ['centro', 'Centro', 'bodega5', 'BODEGA 5']))
        }
      };
    });
  };

  const loadData = async () => {
    setIsLoading(true);
    try {
      const response = await fetch(N8N_WEBHOOKS.CONSULTA_GLOBAL);
      const data = await response.json();
      let sourceArray = Array.isArray(data) ? (data[0]?.productos || data) : (data.productos || [data]);
      if (sourceArray.length > 0) setRawProducts(normalizeData(sourceArray));
    } catch (error) {
      showNotify("Error de sincronización", "error");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => { loadData(); }, []);

  const insights = useMemo(() => {
    if (!rawProducts.length) return null;
    const safe = rawProducts.filter(p => p.referencia);

    // Determinar qué stock usar para los indicadores basándose en el filtro global
    const getStockForIndicators = (p: any) => {
      if (filterSede === 'ALL') return p.stock.total;
      const key = mapAppSedeToJsonProperty(filterSede);
      return (p.stock as any)[key] ?? 0;
    };

    const totalVenta = safe.reduce((acc, p) => acc + (p.precioVenta * getStockForIndicators(p)), 0);
    const totalCosto = safe.reduce((acc, p) => acc + (p.precioCosto * getStockForIndicators(p)), 0);

    // Sede líder siempre se calcula sobre el global para saber cuál es la mejor
    const sedesData = SEDES.map(s => {
      const key = mapAppSedeToJsonProperty(s.id);
      return { 
        name: s.name.replace(/^[0-9].\s*/, ''), 
        total: safe.reduce((acc, p) => acc + ((p.stock[key] || 0) * p.precioVenta), 0) 
      };
    });
    const liderSede = [...sedesData].sort((a,b) => b.total - a.total)[0];

    return {
      totalVenta,
      totalCosto,
      margen: totalVenta > 0 ? Math.round(((totalVenta - totalCosto) / totalVenta) * 100) : 0,
      lider: { nombre: liderSede?.name || 'N/A', valor: liderSede?.total || 0 },
      estrella: safe.sort((a,b) => (b.precioVenta * getStockForIndicators(b)) - (a.precioVenta * getStockForIndicators(a)))[0],
      critico: safe.sort((a,b) => getStockForIndicators(a) - getStockForIndicators(b))[0],
      volumen: safe.sort((a,b) => getStockForIndicators(b) - getStockForIndicators(a))[0],
      categoria: Object.entries(safe.reduce((acc:any, p) => { 
        const stock = getStockForIndicators(p);
        acc[p.tipo] = (acc[p.tipo]||0) + stock; 
        return acc; 
      }, {})).sort((a:any, b:any) => b[1]-a[1])[0]
    };
  }, [rawProducts, filterSede]);

  const generateAIReport = async () => {
    setIsGeneratingReport(true);
    setIsReportModalOpen(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Actúa como un experto en analítica de inventarios para Yeilustore. Analiza estos datos: ${JSON.stringify(rawProducts.slice(0, 20))}. Genera un informe estratégico que incluya: un título profesional, un resumen ejecutivo de la situación y secciones con recomendaciones específicas. Usa estados 'success', 'warning', 'danger' o 'info' según corresponda.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: { 
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              titulo: { type: Type.STRING },
              resumen: { type: Type.STRING },
              secciones: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    titulo: { type: Type.STRING },
                    contenido: { type: Type.STRING },
                    estado: { type: Type.STRING, description: "Debe ser: success, warning, danger o info" }
                  },
                  required: ['titulo', 'contenido', 'estado']
                }
              }
            },
            required: ['titulo', 'resumen', 'secciones']
          }
        }
      });

      const resultText = response.text;
      if (resultText) {
        setReportData(JSON.parse(resultText));
      }
    } catch (error) {
      console.error(error);
      showNotify("Error al generar informe IA", "error");
    } finally {
      setIsGeneratingReport(false);
    }
  };

  const handleRegisterMovement = async () => {
    if (!movForm.reference) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.REGISTRO_MOVIMIENTO, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...movForm, sedeId: sedeTarget, usuario: user.username })
      });
      if (res.ok) { 
        showNotify("¡Movimiento registrado!"); 
        setIsMovModalOpen(false); 
        setMovForm({ reference: '', quantity: 1, type: 'SALIDA', destSede: '', notes: '' });
        loadData(); 
      }
    } catch { showNotify("Error de red", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleIngresoInventario = async () => {
    if (!ingresoForm.referencia) return showNotify("Ref obligatoria", "error");
    setIsSubmitting(true);
    const sedeTarget = filterSede === 'ALL' ? user.sedeId : filterSede;
    try {
      const res = await fetch(N8N_WEBHOOKS.PRODUCTO_CON_IMAGEN, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...ingresoForm, usuario: user.username, sede: sedeTarget })
      });
      if (res.ok) { 
        showNotify("¡Producto ingresado!"); 
        setIsIngresoModalOpen(false); 
        setIngresoForm(INITIAL_INGRESO_STATE);
        loadData(); 
      }
    } catch { showNotify("Error al guardar", "error"); }
    finally { setIsSubmitting(false); }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setIngresoForm(p => ({ ...p, imagen: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  const filteredData = useMemo(() => {
    return rawProducts.map(p => {
      if (filterSede === 'ALL') return { ...p, stockReal: p.stock.total };
      const key = mapAppSedeToJsonProperty(filterSede);
      return { ...p, stockReal: (p.stock as any)[key] ?? 0 };
    });
  }, [rawProducts, filterSede]);

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans pb-10">
      {notification.show && (
        <div className={`fixed top-24 left-1/2 -translate-x-1/2 z-[100] px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-top-4 duration-300 ${notification.type === 'success' ? 'bg-emerald-600' : 'bg-rose-600'} text-white`}>
           <span className="text-[10px] font-black uppercase tracking-widest">{notification.message}</span>
        </div>
      )}

      {isQRVisible && <QRScanner onScan={(txt) => { setMovForm(p => ({ ...p, reference: txt.toUpperCase() })); setIsQRVisible(false); setIsMovModalOpen(true); }} onClose={() => setIsQRVisible(false)} />}

      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl text-white shadow-lg"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" strokeWidth="2"/></svg></div>
          <h1 className="text-lg font-black uppercase tracking-tighter text-slate-800">Yeilustore</h1>
        </div>
        <div className="flex gap-3">
          {user.role === 'GERENTE' && <button onClick={() => setIsUserModalOpen(true)} className="bg-slate-900 text-white px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest">Usuarios</button>}
          <Button variant="secondary" onClick={onLogout} className="text-[10px] font-black h-9 uppercase">Salir</Button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto p-4 lg:p-8 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="bg-slate-900 p-8 rounded-[2rem] text-white shadow-2xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 mb-2">Inversión Actual ({filterSede === 'ALL' ? 'Global' : filterSede.toUpperCase()})</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalCosto || 0).toLocaleString()}</h2>
          </div>
          <div className="bg-indigo-600 p-8 rounded-[2rem] text-white shadow-xl">
             <p className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-200 mb-2">Venta Proyectada ({filterSede === 'ALL' ? 'Global' : filterSede.toUpperCase()})</p>
             <h2 className="text-4xl font-black">${Math.round(insights?.totalVenta || 0).toLocaleString()}</h2>
          </div>
        </div>

        {user.role === 'GERENTE' && insights && (
          <section className="grid grid-cols-2 lg:grid-cols-3 gap-6">
             {[
               { icon: '🏆', lab: 'Sede Líder', val: insights.lider.nombre, sub: `$${Math.round(insights.lider.valor).toLocaleString()}` },
               { icon: '⭐', lab: 'Estrella', val: insights.estrella?.nombre || 'N/A', sub: insights.estrella?.referencia || '' },
               { icon: '⚠️', lab: 'Alerta Stock', val: insights.critico?.referencia || 'N/A', sub: `${insights.critico?.stockReal || 0} UND` },
               { icon: '📊', lab: 'Mayor Volumen', val: insights.volumen?.nombre || 'N/A', sub: `${insights.volumen?.stockReal || 0} UND` },
               { icon: '🏷️', lab: 'Top Categoría', val: insights.categoria?.[0] || 'N/A', sub: 'Líder en ventas' },
               { icon: '📈', lab: 'Margen Global', val: `${insights.margen}%`, sub: 'Rendimiento' }
             ].map((kpi, i) => (
               <div key={i} className="bg-white p-6 rounded-[1.5rem] border border-slate-100 shadow-sm">
                  <div className="flex items-center gap-2 mb-2"><span className="text-lg">{kpi.icon}</span><p className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{kpi.lab}</p></div>
                  <h4 className="text-sm font-black text-slate-800 truncate uppercase">{kpi.val}</h4>
                  <p className="text-[10px] font-bold text-slate-400 mt-1 uppercase">{kpi.sub}</p>
               </div>
             ))}
          </section>
        )}

        <div className="flex flex-col md:flex-row gap-4 items-center">
          <div className="w-full md:w-56">
            <Select 
              value={filterSede} 
              onChange={e => setFilterSede(e.target.value as any)}
              options={[{value:'ALL', label:'🌍 GLOBAL'}, ...SEDES.map(s => ({value:s.id, label: `📍 ${s.name.replace(/^[0-9].\s*/, '').toUpperCase()}`}))]}
              className="font-black text-[10px] text-indigo-600 bg-white h-[52px] rounded-2xl shadow-sm"
            />
          </div>
          <div className="flex flex-1 gap-2 w-full">
            <button onClick={() => setIsIngresoModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-emerald-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3"/></svg>
              <span>Ingreso</span>
            </button>
            <button onClick={() => setIsMovModalOpen(true)} className="flex-1 p-4 rounded-2xl bg-indigo-600 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4" strokeWidth="3"/></svg>
              <span>Movimiento</span>
            </button>
            {user.role === 'GERENTE' && (
              <button onClick={generateAIReport} className="flex-1 p-4 rounded-2xl bg-slate-900 text-white font-black text-[10px] uppercase tracking-widest shadow-lg flex items-center justify-center gap-2">
                <svg className="w-4 h-4 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
                <span>Informe IA</span>
              </button>
            )}
          </div>
        </div>

        <div className="bg-white rounded-[2rem] shadow-xl border border-slate-100 overflow-hidden">
          <div className="p-6 md:p-8 border-b flex justify-between items-center bg-slate-50/30">
            <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Existencias Detalladas</h3>
            <button onClick={loadData} className={`p-2 rounded-full ${isLoading ? 'animate-spin' : ''}`}><svg className="w-5 h-5 text-slate-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9" strokeWidth="2"/></svg></button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-slate-400 uppercase tracking-widest border-b bg-slate-50/50">
                  <th className="px-8 py-5">REF</th>
                  <th className="px-8 py-5">Descripción</th>
                  <th className="px-8 py-5 text-center">Existencias</th>
                  <th className="px-8 py-5 text-right">P. Venta</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredData.map((s, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/80 transition-all">
                    <td className="px-8 py-4 font-black text-[11px] text-indigo-600">{s.referencia}</td>
                    <td className="px-8 py-4">
                      <p className="font-bold text-[11px] text-slate-700 uppercase">{s.nombre}</p>
                      <p className="text-[9px] text-slate-400 uppercase font-black">{s.tipo}</p>
                    </td>
                    <td className="px-8 py-4 text-center">
                       <span className={`inline-block px-4 py-1 rounded-full text-[10px] font-black ${s.stockReal <= s.stockMinimo ? 'bg-rose-100 text-rose-600' : 'bg-emerald-100 text-emerald-600'}`}>
                         {s.stockReal} UND
                       </span>
                    </td>
                    <td className="px-8 py-4 text-right font-black text-slate-700 text-[11px]">${Math.round(s.precioVenta).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      <Modal isOpen={isMovModalOpen} onClose={() => setIsMovModalOpen(false)} title="📦 MOVIMIENTO">
         <div className="space-y-4">
           <div className="flex gap-2">
             <Input label="Referencia" value={movForm.reference} onChange={e => setMovForm({...movForm, reference: e.target.value.toUpperCase()})} />
             <button onClick={() => setIsQRVisible(true)} className="mt-8 bg-slate-100 p-3 rounded-xl"><svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v1" strokeWidth="2"/></svg></button>
           </div>
           <div className="grid grid-cols-2 gap-4">
             <Input label="Cantidad" type="number" value={movForm.quantity} onChange={e => setMovForm({...movForm, quantity: Number(e.target.value)})} />
             <Select label="Tipo" value={movForm.type} onChange={e => setMovForm({...movForm, type: e.target.value as any})} options={[{value:'ENTRADA', label:'Entrada'}, {value:'SALIDA', label:'Salida'}, {value:'TRASLADO', label:'Traslado'}]} />
           </div>
           <Input 
             label="Observaciones / Motivo (Opcional)" 
             value={movForm.notes} 
             onChange={e => setMovForm({...movForm, notes: e.target.value})} 
             placeholder="Ej: Venta, Traslado a Centro, Ajuste de inventario..."
             className="text-xs"
           />
           <Button fullWidth onClick={handleRegisterMovement} disabled={isSubmitting}>Confirmar</Button>
         </div>
      </Modal>

      <Modal isOpen={isIngresoModalOpen} onClose={() => setIsIngresoModalOpen(false)} title="✨ NUEVO INGRESO">
        <div className="space-y-4">
          <Input label="Referencia" value={ingresoForm.referencia} onChange={e => setIngresoForm({...ingresoForm, referencia: e.target.value.toUpperCase()})} />
          <div className="grid grid-cols-2 gap-4">
            <Input label="Cantidad" type="number" value={ingresoForm.cantidad} onChange={e => setIngresoForm({...ingresoForm, cantidad: Number(e.target.value)})} />
            <Input label="Mínimo Alerta" type="number" value={ingresoForm.stock_minimo} onChange={e => setIngresoForm({...ingresoForm, stock_minimo: Number(e.target.value)})} />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <Input label="Costo" type="number" value={ingresoForm.costo_unitario} onChange={e => setIngresoForm({...ingresoForm, costo_unitario: Number(e.target.value)})} />
            <Input label="Venta" type="number" value={ingresoForm.precio_venta} onChange={e => setIngresoForm({...ingresoForm, precio_venta: Number(e.target.value)})} />
          </div>
          <div className="p-4 bg-slate-50 border-2 border-dashed border-slate-200 rounded-2xl text-center">
            {ingresoForm.imagen ? (
              <div className="relative inline-block">
                <img src={ingresoForm.imagen} className="w-20 h-20 object-cover rounded-xl shadow-md" />
                <button onClick={() => setIngresoForm(p => ({...p, imagen: null}))} className="absolute -top-2 -right-2 bg-rose-500 text-white rounded-full p-1 text-[8px]">X</button>
              </div>
            ) : <button onClick={() => fileInputRef.current?.click()} className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Añadir Foto</button>}
            <input type="file" className="hidden" ref={fileInputRef} onChange={handleFileChange} accept="image/*" />
          </div>
          <Button fullWidth onClick={handleIngresoInventario} disabled={isSubmitting}>Guardar Producto</Button>
        </div>
      </Modal>

      <Modal isOpen={isReportModalOpen} onClose={() => setIsReportModalOpen(false)} title="🚀 INFORME IA">
        {isGeneratingReport ? (
          <div className="py-12 flex flex-col items-center justify-center text-center">
             <div className="w-12 h-12 border-4 border-indigo-500/30 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
             <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Analizando...</p>
          </div>
        ) : reportData && (
          <div className="space-y-6 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            <div className="bg-indigo-50 p-5 rounded-2xl border border-indigo-100">
               <h4 className="text-indigo-600 font-black text-[10px] uppercase mb-1 tracking-widest">{reportData.titulo}</h4>
               <p className="text-sm text-slate-600 font-medium">{reportData.resumen}</p>
            </div>
            {reportData.secciones.map((sec, i) => (
              <div key={i} className={`p-5 rounded-2xl border-l-4 ${sec.estado === 'danger' ? 'bg-rose-50 border-rose-500' : sec.estado === 'warning' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'}`}>
                 <h5 className="font-black text-sm uppercase text-slate-800">{sec.titulo}</h5>
                 <p className="text-xs text-slate-600 mt-1">{sec.contenido}</p>
              </div>
            ))}
          </div>
        )}
      </Modal>
    </div>
  );
};
